import { z } from "zod";
import { TRPCError } from "@trpc/server";
import { createRouter, authedQuery, accountantQuery } from "./middleware";
import { getDb } from "./queries/connection";
import { chartOfAccounts, journalEntries, journalEntryLines, ledgerEntries, expenses, tickets, accountingPeriods } from "@db/schema";
import { eq, desc, sql, and, inArray } from "drizzle-orm";

export const accountingRouter = createRouter({
  // ΓöÇΓöÇΓöÇ CHART OF ACCOUNTS ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
  accounts: authedQuery
    .input(z.object({ type: z.string().optional() }).optional())
    .query(async ({ input, ctx }) => {
      const db = getDb();
      const where = input?.type ? and(eq(chartOfAccounts.type, input.type as "asset" | "liability" | "equity" | "revenue" | "expense"), eq(chartOfAccounts.tenantId, ctx.user!.tenantId as number)) : eq(chartOfAccounts.tenantId, ctx.user!.tenantId as number);
      return db.query.chartOfAccounts.findMany({
        where,
        orderBy: [chartOfAccounts.code],
      });
    }),

  account: authedQuery
    .input(z.object({ id: z.number() }))
    .query(async ({ input, ctx }) => {
      const db = getDb();
      const account = await db.query.chartOfAccounts.findFirst({
        where: and(eq(chartOfAccounts.id, input.id), eq(chartOfAccounts.tenantId, ctx.user!.tenantId as number)),
      });
      const ledger = await db.query.ledgerEntries.findMany({
        where: and(eq(ledgerEntries.accountId, input.id), eq(ledgerEntries.tenantId, ctx.user!.tenantId as number)),
        orderBy: [ledgerEntries.date],
      });
      return { account, ledger };
    }),

  createAccount: accountantQuery
    .input(z.object({
      code: z.string().min(1),
      name: z.string().min(1),
      type: z.enum(["asset", "liability", "equity", "revenue", "expense"]),
      subtype: z.string().optional(),
      description: z.string().optional(),
      isBankAccount: z.boolean().default(false),
      currency: z.string().default("USD"),
    }))
    .mutation(async ({ input, ctx }) => {
      const db = getDb();
      const result = await db.insert(chartOfAccounts).values({
        ...input,
        tenantId: ctx.user!.tenantId as number,
        currentBalance: "0.00",
        status: "active",
      });
      return { id: Number(result[0].insertId) };
    }),

  // ΓöÇΓöÇΓöÇ JOURNAL ENTRIES ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
  journalEntries: authedQuery
    .input(z.object({
      status: z.string().optional(),
      search: z.string().optional(),
      page: z.number().default(1),
      limit: z.number().default(20),
    }).optional())
    .query(async ({ input, ctx }) => {
      const db = getDb();
      const conditions = [eq(journalEntries.tenantId, ctx.user!.tenantId as number)];
      if (input?.status) conditions.push(eq(journalEntries.status, input.status as "draft" | "posted" | "reversed"));
      if (input?.search) conditions.push(sql`${journalEntries.entryNumber} LIKE ${`%${input.search}%`}`);
      const where = and(...conditions);

      const items = await db.select().from(journalEntries).where(where).limit(input?.limit ?? 20).offset(((input?.page ?? 1) - 1) * (input?.limit ?? 20)).orderBy(desc(journalEntries.date));
      const entryIds = items.map(e => e.id) as number[];
      const lines = entryIds.length > 0
        ? await db.select().from(journalEntryLines).where(inArray(journalEntryLines.journalEntryId, entryIds))
        : [];
      const linesByEntry = new Map<number, typeof lines>();
      for (const line of lines) {
        if (!linesByEntry.has(line.journalEntryId)) linesByEntry.set(line.journalEntryId, []);
        linesByEntry.get(line.journalEntryId)!.push(line);
      }
      const itemsWithLines = items.map(e => ({ ...e, lines: linesByEntry.get(e.id) || [] }));
      const countResult = await db.select({ count: sql<string>`count(*)` }).from(journalEntries).where(where);
      return { items: itemsWithLines, total: Number(countResult[0]?.count ?? 0) };
    }),

  journalEntry: authedQuery
    .input(z.object({ id: z.number() }))
    .query(async ({ input, ctx }) => {
      const db = getDb();
      return db.query.journalEntries.findFirst({
        where: and(eq(journalEntries.id, input.id), eq(journalEntries.tenantId, ctx.user!.tenantId as number)),
        with: { lines: { with: { account: true } } },
      });
    }),

  createJournalEntry: accountantQuery
    .input(z.object({
      entryNumber: z.string().min(1),
      date: z.string(),
      description: z.string().min(1),
      referenceType: z.string().optional(),
      referenceId: z.number().optional(),
      notes: z.string().optional(),
      lines: z.array(z.object({
        accountId: z.number(),
        description: z.string().optional(),
        debit: z.string().refine((value) => !isNaN(Number(value)), { message: "Debit must be a valid number" }).default("0"),
        credit: z.string().refine((value) => !isNaN(Number(value)), { message: "Credit must be a valid number" }).default("0"),
      })).min(2),
    }))
    .mutation(async ({ input, ctx }) => {
      const db = getDb();
      if (!input.date || isNaN(new Date(input.date).getTime())) {
        throw new TRPCError({ code: "BAD_REQUEST", message: "Valid date is required" });
      }

      const totalDebit = input.lines.reduce((sum, l) => sum + Number(l.debit), 0);
      const totalCredit = input.lines.reduce((sum, l) => sum + Number(l.credit), 0);

      if (Math.abs(totalDebit - totalCredit) > 0.001) {
        throw new TRPCError({ code: "BAD_REQUEST", message: "Debits must equal credits" });
      }

      if (input.lines.some(l => l.accountId <= 0)) {
        throw new TRPCError({ code: "BAD_REQUEST", message: "All lines must have a valid account" });
      }

      const result = await db.insert(journalEntries).values({
        tenantId: ctx.user!.tenantId as number,
        entryNumber: input.entryNumber,
        date: new Date(input.date),
        description: input.description,
        referenceType: input.referenceType,
        referenceId: input.referenceId,
        totalDebit: totalDebit.toFixed(2),
        totalCredit: totalCredit.toFixed(2),
        status: "draft",
        notes: input.notes,
      });

      const journalEntryId = Number(result[0].insertId);
      await db.insert(journalEntryLines).values(
        input.lines.map((l) => ({ ...l, journalEntryId }))
      );

      return { id: journalEntryId };
    }),

  postJournalEntry: accountantQuery
    .input(z.object({ id: z.number() }))
    .mutation(async ({ input, ctx }) => {
      const db = getDb();
      const tenantId = ctx.user!.tenantId as number;
      const entry = await db.query.journalEntries.findFirst({
        where: and(eq(journalEntries.id, input.id), eq(journalEntries.tenantId, tenantId)),
        with: { lines: true },
      });

      if (!entry) {
        throw new TRPCError({ code: "NOT_FOUND", message: "Journal entry not found" });
      }

      if (entry.status !== "draft") {
        throw new TRPCError({ code: "BAD_REQUEST", message: "Journal entry is not in draft status" });
      }

      await db.transaction(async (tx) => {
        await tx.update(journalEntries).set({ status: "posted", postedBy: ctx.user!.id, postedAt: new Date() }).where(eq(journalEntries.id, input.id));

        // Create ledger entries
        for (const line of entry.lines) {
          const account = await tx.query.chartOfAccounts.findFirst({
            where: and(eq(chartOfAccounts.id, line.accountId), eq(chartOfAccounts.tenantId, tenantId)),
          });
          const currentBalance = Number(account?.currentBalance ?? 0);
          const newBalance = currentBalance + Number(line.debit) - Number(line.credit);

          await tx.insert(ledgerEntries).values({
            tenantId,
            journalEntryId: input.id,
            accountId: line.accountId,
            date: entry.date ? new Date(entry.date) : new Date(),
            description: line.description || entry.description,
            debit: line.debit,
            credit: line.credit,
            balance: newBalance.toFixed(2),
          });

          await tx.update(chartOfAccounts)
            .set({ currentBalance: newBalance.toFixed(2) })
            .where(and(eq(chartOfAccounts.id, line.accountId), eq(chartOfAccounts.tenantId, tenantId)));
        }
      });

      return { success: true };
    }),

  // ΓöÇΓöÇΓöÇ LEDGER ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
  ledger: authedQuery
    .input(z.object({
      accountId: z.number().optional(),
      page: z.number().default(1),
      limit: z.number().default(50),
    }).optional())
    .query(async ({ input, ctx }) => {
      const db = getDb();
      const where = input?.accountId ? and(eq(ledgerEntries.accountId, input.accountId), eq(ledgerEntries.tenantId, ctx.user!.tenantId as number)) : eq(ledgerEntries.tenantId, ctx.user!.tenantId as number);

      const items = await db.select().from(ledgerEntries).where(where).limit(input?.limit ?? 50).offset(((input?.page ?? 1) - 1) * (input?.limit ?? 50)).orderBy(ledgerEntries.date);
      const accountIds = [...new Set(items.map(i => i.accountId).filter(Boolean))] as number[];
      const journalEntryIds = [...new Set(items.map(i => i.journalEntryId).filter(Boolean))] as number[];
      const accountList = accountIds.length > 0
        ? await db.select().from(chartOfAccounts).where(inArray(chartOfAccounts.id, accountIds))
        : [];
      const journalList = journalEntryIds.length > 0
        ? await db.select().from(journalEntries).where(inArray(journalEntries.id, journalEntryIds))
        : [];
      const accountMap = new Map(accountList.map(a => [a.id, a]));
      const journalMap = new Map(journalList.map(j => [j.id, j]));
      return items.map(i => ({
        ...i,
        account: accountMap.get(i.accountId) || null,
        journalEntry: i.journalEntryId ? journalMap.get(i.journalEntryId) || null : null,
      }));
    }),

  // ΓöÇΓöÇΓöÇ FINANCIAL STATEMENTS ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
  trialBalance: authedQuery.query(async ({ ctx }) => {
    const db = getDb();
    const accounts = await db.query.chartOfAccounts.findMany({
      where: eq(chartOfAccounts.tenantId, ctx.user!.tenantId as number),
      orderBy: [chartOfAccounts.code],
    });

    const ledgerData = await db
      .select({
        accountId: ledgerEntries.accountId,
        totalDebit: sql<number>`COALESCE(SUM(debit), 0)`,
        totalCredit: sql<number>`COALESCE(SUM(credit), 0)`,
      })
      .from(ledgerEntries)
      .where(eq(ledgerEntries.tenantId, ctx.user!.tenantId as number))
      .groupBy(ledgerEntries.accountId);

    return { accounts, ledgerData };
  }),

  financialSummary: authedQuery.query(async ({ ctx }) => {
    const db = getDb();
    const revenue = await db
      .select({ total: sql<number>`COALESCE(SUM(total_amount), 0)` })
      .from(tickets)
      .where(eq(tickets.tenantId, ctx.user!.tenantId as number));
    const expenseTotal = await db
      .select({ total: sql<number>`COALESCE(SUM(amount), 0)` })
      .from(expenses)
      .where(and(eq(expenses.tenantId, ctx.user!.tenantId as number), eq(expenses.status, "approved")));
    const assets = await db
      .select({ total: sql<number>`COALESCE(SUM(current_balance), 0)` })
      .from(chartOfAccounts)
      .where(and(eq(chartOfAccounts.tenantId, ctx.user!.tenantId as number), eq(chartOfAccounts.type, "asset")));
    const liabilities = await db
      .select({ total: sql<number>`COALESCE(SUM(current_balance), 0)` })
      .from(chartOfAccounts)
      .where(and(eq(chartOfAccounts.tenantId, ctx.user!.tenantId as number), eq(chartOfAccounts.type, "liability")));

    return {
      revenue: Number(revenue[0]?.total ?? 0),
      expenses: Number(expenseTotal[0]?.total ?? 0),
      assets: Number(assets[0]?.total ?? 0),
      liabilities: Number(liabilities[0]?.total ?? 0),
      equity: Number(assets[0]?.total ?? 0) - Number(liabilities[0]?.total ?? 0),
    };
  }),

  profitAndLoss: authedQuery
    .input(z.object({ fromDate: z.string().optional(), toDate: z.string().optional() }).optional())
    .query(async ({ input, ctx }) => {
      const db = getDb();
      const tenantId = ctx.user!.tenantId as number;

      // Get all revenue and expense accounts with their ledger balances
      const accounts = await db.select().from(chartOfAccounts)
        .where(and(eq(chartOfAccounts.tenantId, tenantId), sql`${chartOfAccounts.type} IN ('revenue', 'expense')`))
        .orderBy(chartOfAccounts.code);

      const accountIds = accounts.map(a => a.id);
      const ledgerData = accountIds.length > 0
        ? await db
            .select({
              accountId: ledgerEntries.accountId,
              totalDebit: sql<number>`COALESCE(SUM(debit), 0)`,
              totalCredit: sql<number>`COALESCE(SUM(credit), 0)`,
            })
            .from(ledgerEntries)
            .where(and(
              eq(ledgerEntries.tenantId, tenantId),
              inArray(ledgerEntries.accountId, accountIds),
              input?.fromDate ? sql`${ledgerEntries.date} >= ${input.fromDate}` : undefined,
              input?.toDate ? sql`${ledgerEntries.date} <= ${input.toDate}` : undefined,
            ))
            .groupBy(ledgerEntries.accountId)
        : [];

      const ledgerMap = new Map(ledgerData.map(l => [l.accountId, l]));

      let totalRevenue = 0;
      let totalExpenses = 0;
      const revenueAccounts: any[] = [];
      const expenseAccounts: any[] = [];

      for (const account of accounts) {
        const ledger = ledgerMap.get(account.id);
        const debit = Number(ledger?.totalDebit ?? 0);
        const credit = Number(ledger?.totalCredit ?? 0);
        const netBalance = credit - debit; // Revenue: Cr increases, Expense: Dr increases

        if (account.type === "revenue") {
          totalRevenue += netBalance;
          revenueAccounts.push({ ...account, debit, credit, netBalance });
        } else {
          totalExpenses += debit - credit;
          expenseAccounts.push({ ...account, debit, credit, netBalance: debit - credit });
        }
      }

      return {
        revenueAccounts,
        expenseAccounts,
        totalRevenue,
        totalExpenses,
        netIncome: totalRevenue - totalExpenses,
      };
    }),

  balanceSheet: authedQuery
    .input(z.object({ asOfDate: z.string().optional() }).optional())
    .query(async ({ input, ctx }) => {
      const db = getDb();
      const tenantId = ctx.user!.tenantId as number;

      const accounts = await db.select().from(chartOfAccounts)
        .where(and(eq(chartOfAccounts.tenantId, tenantId), sql`${chartOfAccounts.type} IN ('asset', 'liability', 'equity')`))
        .orderBy(chartOfAccounts.code);

      const accountIds = accounts.map(a => a.id);
      const ledgerData = accountIds.length > 0
        ? await db
            .select({
              accountId: ledgerEntries.accountId,
              totalDebit: sql<number>`COALESCE(SUM(debit), 0)`,
              totalCredit: sql<number>`COALESCE(SUM(credit), 0)`,
            })
            .from(ledgerEntries)
            .where(and(
              eq(ledgerEntries.tenantId, tenantId),
              inArray(ledgerEntries.accountId, accountIds),
              input?.asOfDate ? sql`${ledgerEntries.date} <= ${input.asOfDate}` : undefined,
            ))
            .groupBy(ledgerEntries.accountId)
        : [];

      const ledgerMap = new Map(ledgerData.map(l => [l.accountId, l]));

      let totalAssets = 0;
      let totalLiabilities = 0;
      let totalEquity = 0;
      const assets: any[] = [];
      const liabilities: any[] = [];
      const equity: any[] = [];

      for (const account of accounts) {
        const ledger = ledgerMap.get(account.id);
        const debit = Number(ledger?.totalDebit ?? 0);
        const credit = Number(ledger?.totalCredit ?? 0);
        let balance = 0;

        if (account.type === "asset") {
          balance = debit - credit;
          totalAssets += balance;
          assets.push({ ...account, debit, credit, balance });
        } else if (account.type === "liability") {
          balance = credit - debit;
          totalLiabilities += balance;
          liabilities.push({ ...account, debit, credit, balance });
        } else {
          balance = credit - debit;
          totalEquity += balance;
          equity.push({ ...account, debit, credit, balance });
        }
      }

      return {
        assets,
        liabilities,
        equity,
        totalAssets,
        totalLiabilities,
        totalEquity,
        balanced: Math.abs(totalAssets - (totalLiabilities + totalEquity)) < 0.01,
      };
    }),

  retainedEarnings: authedQuery.query(async ({ ctx }) => {
    const db = getDb();
    const tenantId = ctx.user!.tenantId as number;

    // Get retained earnings account balance
    const reAccount = await db.query.chartOfAccounts.findFirst({
      where: and(eq(chartOfAccounts.code, "3100"), eq(chartOfAccounts.tenantId, tenantId)),
    });
    const beginningRE = Number(reAccount?.currentBalance ?? 0);

    // Calculate net income from ledger
    const revenueAccounts = await db.select({ id: chartOfAccounts.id }).from(chartOfAccounts)
      .where(and(eq(chartOfAccounts.tenantId, tenantId), eq(chartOfAccounts.type, "revenue")));
    const expenseAccounts = await db.select({ id: chartOfAccounts.id }).from(chartOfAccounts)
      .where(and(eq(chartOfAccounts.tenantId, tenantId), eq(chartOfAccounts.type, "expense")));

    const revIds = revenueAccounts.map(a => a.id);
    const expIds = expenseAccounts.map(a => a.id);

    const revenueTotal = revIds.length > 0
      ? await db.select({ total: sql<number>`COALESCE(SUM(credit - debit), 0)` }).from(ledgerEntries)
        .where(and(eq(ledgerEntries.tenantId, tenantId), inArray(ledgerEntries.accountId, revIds)))
      : [{ total: 0 }];
    const expenseTotal = expIds.length > 0
      ? await db.select({ total: sql<number>`COALESCE(SUM(debit - credit), 0)` }).from(ledgerEntries)
        .where(and(eq(ledgerEntries.tenantId, tenantId), inArray(ledgerEntries.accountId, expIds)))
      : [{ total: 0 }];

    const netIncome = Number(revenueTotal[0]?.total ?? 0) - Number(expenseTotal[0]?.total ?? 0);

    return {
      beginningRE,
      netIncome,
      endingRE: beginningRE + netIncome,
    };
  }),

  closingPeriod: accountantQuery
    .input(z.object({ year: z.number(), month: z.number().optional() }))
    .mutation(async ({ input, ctx }) => {
      const db = getDb();
      const tenantId = ctx.user!.tenantId as number;

      // Check if already closed
      const existing = await db.query.accountingPeriods.findFirst({
        where: and(
          eq(accountingPeriods.tenantId, tenantId),
          eq(accountingPeriods.year, input.year),
          input.month ? eq(accountingPeriods.month, input.month) : undefined,
        ),
      });

      if (existing?.status === "closed") {
        throw new TRPCError({ code: "BAD_REQUEST", message: "Period is already closed" });
      }

      if (existing) {
        await db.update(accountingPeriods).set({
          status: "closed",
          closedBy: ctx.user!.id,
          closedAt: new Date(),
        }).where(eq(accountingPeriods.id, existing.id));
      } else {
        await db.insert(accountingPeriods).values({
          tenantId,
          year: input.year,
          month: input.month ?? null,
          status: "closed",
          closedBy: ctx.user!.id,
          closedAt: new Date(),
        });
      }

      return { success: true };
    }),

  deleteJournalEntry: accountantQuery
    .input(z.object({ id: z.number() }))
    .mutation(async ({ input, ctx }) => {
      const db = getDb();
      const tenantId = ctx.user!.tenantId as number;
      const entry = await db.query.journalEntries.findFirst({
        where: and(eq(journalEntries.id, input.id), eq(journalEntries.tenantId, tenantId)),
      });
      if (!entry) {
        throw new TRPCError({ code: "NOT_FOUND", message: "Journal entry not found" });
      }
      if (entry.status === "posted") {
        throw new TRPCError({
          code: "FORBIDDEN",
          message: "Posted journal entries cannot be deleted. Create a reversing entry instead.",
        });
      }
      await db.delete(journalEntryLines).where(eq(journalEntryLines.journalEntryId, input.id));
      await db.delete(journalEntries).where(and(eq(journalEntries.id, input.id), eq(journalEntries.tenantId, tenantId)));
      return { success: true };
    }),
});

import { z } from "zod";
import { TRPCError } from "@trpc/server";
import { createRouter, superAdminQuery } from "./middleware";
import { getDb } from "./queries/connection";
import { tenants, subscriptions } from "@db/schema";
import { eq, desc, sql, and } from "drizzle-orm";
import { auditLog } from "./lib/audit";

export const adminRouter = createRouter({
  // ΓöÇΓöÇΓöÇ PENDING REGISTRATIONS ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
  pendingRegistrations: superAdminQuery.query(async () => {
    const db = getDb();
    const items = await db
      .select({
        id: tenants.id,
        name: tenants.name,
        slug: tenants.slug,
        status: tenants.status,
        plan: tenants.plan,
        ownerName: tenants.ownerName,
        ownerEmail: tenants.ownerEmail,
        ownerPhone: tenants.ownerPhone,
        address: tenants.address,
        city: tenants.city,
        registrationToken: tenants.registrationToken,
        createdAt: tenants.createdAt,
      })
      .from(tenants)
      .where(eq(tenants.status, "pending"))
      .orderBy(desc(tenants.createdAt));

    return { items };
  }),

  // ΓöÇΓöÇΓöÇ ALL REGISTRATIONS (with filters) ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
  registrations: superAdminQuery
    .input(
      z.object({
        status: z.enum(["pending", "active", "rejected", "suspended", "all"]).default("all"),
        search: z.string().optional(),
        page: z.number().default(1),
        limit: z.number().default(20),
      }).optional()
    )
    .query(async ({ input }) => {
      const db = getDb();
      const conditions: any[] = [];
      if (input?.status && input.status !== "all") {
        conditions.push(eq(tenants.status, input.status));
      }
      if (input?.search) {
        conditions.push(
          sql`(${tenants.name} LIKE ${`%${input.search}%`} OR ${tenants.ownerEmail} LIKE ${`%${input.search}%`} OR ${tenants.registrationToken} LIKE ${`%${input.search}%`})`
        );
      }

      const where = conditions.length > 0 ? and(...conditions) : undefined;

      const items = await db
        .select()
        .from(tenants)
        .where(where)
        .orderBy(desc(tenants.createdAt))
        .limit(input?.limit ?? 20)
        .offset(((input?.page ?? 1) - 1) * (input?.limit ?? 20));

      console.log("[admin registrations]", items);

      const countResult = await db
        .select({ count: sql<number>`count(*)` })
        .from(tenants)
        .where(where);

      return { items, total: countResult[0]?.count ?? 0 };
    }),

  // ΓöÇΓöÇΓöÇ APPROVE REGISTRATION ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
  approveRegistration: superAdminQuery
    .input(z.object({ tenantId: z.number(), notes: z.string().optional() }))
    .mutation(async ({ input, ctx }) => {
      const db = getDb();

      const tenant = await db
        .select({ id: tenants.id, status: tenants.status, registrationToken: tenants.registrationToken })
        .from(tenants)
        .where(eq(tenants.id, input.tenantId))
        .limit(1);

      if (!tenant[0]) {
        throw new TRPCError({ code: "NOT_FOUND", message: "Tenant not found" });
      }
      if (tenant[0].status !== "pending") {
        throw new TRPCError({ code: "BAD_REQUEST", message: `Tenant is already ${tenant[0].status}` });
      }

      const now = new Date();
      const sub = await db
        .select({ durationMonths: subscriptions.durationMonths })
        .from(subscriptions)
        .where(eq(subscriptions.tenantId, input.tenantId))
        .limit(1);

      const durationMonths = sub[0]?.durationMonths ?? 1;
      const expiresAt = new Date(now);
      expiresAt.setMonth(expiresAt.getMonth() + durationMonths);

      await db.transaction(async (tx) => {
        await tx.update(tenants).set({ status: "active" }).where(eq(tenants.id, input.tenantId));
        await tx
          .update(subscriptions)
          .set({
            status: "active",
            startsAt: now,
            expiresAt,
            approvedBy: ctx.user!.id,
            approvedAt: now,
          })
          .where(eq(subscriptions.tenantId, input.tenantId));
      });

      await auditLog({
        ctx,
        action: "approve_registration",
        entityType: "tenant",
        entityId: input.tenantId,
        newValues: { status: "active", expiresAt: expiresAt.toISOString() },
      });

      return { success: true, expiresAt: expiresAt.toISOString() };
    }),

  // ΓöÇΓöÇΓöÇ REJECT REGISTRATION ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
  rejectRegistration: superAdminQuery
    .input(z.object({ tenantId: z.number(), reason: z.string().optional() }))
    .mutation(async ({ input, ctx }) => {
      const db = getDb();

      const tenant = await db
        .select({ id: tenants.id, status: tenants.status })
        .from(tenants)
        .where(eq(tenants.id, input.tenantId))
        .limit(1);

      if (!tenant[0]) {
        throw new TRPCError({ code: "NOT_FOUND", message: "Tenant not found" });
      }

      await db.transaction(async (tx) => {
        await tx.update(tenants).set({ status: "rejected" }).where(eq(tenants.id, input.tenantId));
        await tx
          .update(subscriptions)
          .set({ status: "rejected" })
          .where(eq(subscriptions.tenantId, input.tenantId));
      });

      await auditLog({
        ctx,
        action: "reject_registration",
        entityType: "tenant",
        entityId: input.tenantId,
        newValues: { status: "rejected", reason: input.reason },
      });

      return { success: true };
    }),

  // ΓöÇΓöÇΓöÇ ACTIVATE SUBSCRIPTION (manual payment approval) ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
  activateSubscription: superAdminQuery
    .input(z.object({ tenantId: z.number() }))
    .mutation(async ({ input, ctx }) => {
      const db = getDb();

      const sub = await db
        .select({ id: subscriptions.id, durationMonths: subscriptions.durationMonths, status: subscriptions.status })
        .from(subscriptions)
        .where(eq(subscriptions.tenantId, input.tenantId))
        .limit(1);

      if (!sub[0]) {
        throw new TRPCError({ code: "NOT_FOUND", message: "Subscription not found" });
      }

      const now = new Date();
      const durationMonths = sub[0].durationMonths ?? 1;
      const expiresAt = new Date(now);
      expiresAt.setMonth(expiresAt.getMonth() + durationMonths);

      await db.transaction(async (tx) => {
        await tx.update(tenants).set({ status: "active" }).where(eq(tenants.id, input.tenantId));
        await tx
          .update(subscriptions)
          .set({
            status: "active",
            startsAt: now,
            expiresAt,
            approvedBy: ctx.user!.id,
            approvedAt: now,
          })
          .where(eq(subscriptions.tenantId, input.tenantId));
      });

      await auditLog({
        ctx,
        action: "activate_subscription",
        entityType: "subscription",
        entityId: sub[0].id,
        newValues: { status: "active", expiresAt: expiresAt.toISOString() },
      });

      return { success: true, expiresAt: expiresAt.toISOString() };
    }),

  // ΓöÇΓöÇΓöÇ DASHBOARD STATS ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
  stats: superAdminQuery.query(async () => {
    const db = getDb();
    const pendingCount = await db
      .select({ count: sql<number>`count(*)` })
      .from(tenants)
      .where(eq(tenants.status, "pending"));

    const activeCount = await db
      .select({ count: sql<number>`count(*)` })
      .from(tenants)
      .where(eq(tenants.status, "active"));

    const totalCount = await db
      .select({ count: sql<number>`count(*)` })
      .from(tenants);

    const stats = {
      pending: pendingCount[0]?.count ?? 0,
      active: activeCount[0]?.count ?? 0,
      total: totalCount[0]?.count ?? 0,
    };

    console.log("[admin stats]", stats);
    return stats;
  }),
});

import { z } from "zod";
import { TRPCError } from "@trpc/server";
import { createRouter, authedQuery } from "./middleware";
import { getDb } from "./queries/connection";
import {
  bankStatements, bankStatementLines, chartOfAccounts, ledgerEntries, journalEntries,
} from "@db/schema";
import { eq, desc, sql, and, gte, lte, inArray } from "drizzle-orm";
import { auditLog } from "./lib/audit";

export const bankReconciliationRouter = createRouter({
  // ΓöÇΓöÇΓöÇ LIST BANK ACCOUNTS ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
  bankAccounts: authedQuery.query(async ({ ctx }) => {
    const db = getDb();
    const tenantId = ctx.user!.tenantId as number;
    return db.select().from(chartOfAccounts)
      .where(and(eq(chartOfAccounts.tenantId, tenantId), eq(chartOfAccounts.isBankAccount, true)))
      .orderBy(chartOfAccounts.name);
  }),

  // ΓöÇΓöÇΓöÇ LIST STATEMENTS ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
  statements: authedQuery
    .input(z.object({
      accountId: z.number().optional(),
      status: z.string().optional(),
      page: z.number().default(1),
      limit: z.number().default(20),
    }).optional())
    .query(async ({ input, ctx }) => {
      const db = getDb();
      const tenantId = ctx.user!.tenantId as number;
      const conditions = [eq(bankStatements.tenantId, tenantId)];

      if (input?.accountId) conditions.push(eq(bankStatements.accountId, input.accountId));
      if (input?.status) conditions.push(eq(bankStatements.status, input.status as any));

      const where = and(...conditions);

      const items = await db.select().from(bankStatements)
        .where(where)
        .limit(input?.limit ?? 20)
        .offset(((input?.page ?? 1) - 1) * (input?.limit ?? 20))
        .orderBy(desc(bankStatements.createdAt));

      const accountIds = [...new Set(items.map(s => s.accountId).filter(Boolean))];
      const accounts = accountIds.length > 0
        ? await db.select().from(chartOfAccounts).where(and(eq(chartOfAccounts.tenantId, tenantId), inArray(chartOfAccounts.id, accountIds)))
        : [];
      const accountMap = new Map(accounts.map(a => [a.id, a]));

      const totalResult = await db.select({ count: sql<number>`count(*)` }).from(bankStatements).where(where);

      return {
        items: items.map(s => ({ ...s, account: accountMap.get(s.accountId) || null })),
        total: totalResult[0]?.count ?? 0,
      };
    }),

  // ΓöÇΓöÇΓöÇ GET STATEMENT DETAIL ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
  statementDetail: authedQuery
    .input(z.object({ id: z.number() }))
    .query(async ({ input, ctx }) => {
      const db = getDb();
      const tenantId = ctx.user!.tenantId as number;

      const statement = await db.select().from(bankStatements)
        .where(and(eq(bankStatements.id, input.id), eq(bankStatements.tenantId, tenantId)))
        .limit(1);
      if (!statement[0]) throw new TRPCError({ code: "NOT_FOUND", message: "Statement not found" });

      const account = await db.select().from(chartOfAccounts)
        .where(and(eq(chartOfAccounts.id, statement[0].accountId), eq(chartOfAccounts.tenantId, tenantId)))
        .limit(1);

      const lines = await db.select().from(bankStatementLines)
        .where(and(eq(bankStatementLines.statementId, input.id), eq(bankStatementLines.tenantId, tenantId)))
        .orderBy(bankStatementLines.transactionDate);

      const matchedJournalIds = [...new Set(lines.map(l => l.matchedJournalEntryId).filter((x): x is number => x !== null))];
      const matchedLedgerIds = [...new Set(lines.map(l => l.matchedLedgerEntryId).filter((x): x is number => x !== null))];

      const journalEntriesData = matchedJournalIds.length > 0
        ? await db.select().from(journalEntries).where(and(eq(journalEntries.tenantId, tenantId), inArray(journalEntries.id, matchedJournalIds)))
        : [];
      const journalMap = new Map(journalEntriesData.map(j => [j.id, j]));

      const ledgerData = matchedLedgerIds.length > 0
        ? await db.select().from(ledgerEntries).where(and(eq(ledgerEntries.tenantId, tenantId), inArray(ledgerEntries.id, matchedLedgerIds)))
        : [];
      const ledgerMap = new Map(ledgerData.map(l => [l.id, l]));

      return {
        statement: statement[0],
        account: account[0] || null,
        lines: lines.map(l => ({
          ...l,
          matchedJournalEntry: l.matchedJournalEntryId ? journalMap.get(l.matchedJournalEntryId) || null : null,
          matchedLedgerEntry: l.matchedLedgerEntryId ? ledgerMap.get(l.matchedLedgerEntryId) || null : null,
        })),
      };
    }),

  // ΓöÇΓöÇΓöÇ CREATE STATEMENT ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
  createStatement: authedQuery
    .input(z.object({
      accountId: z.number(),
      statementDate: z.string(),
      startDate: z.string(),
      endDate: z.string(),
      openingBalance: z.number().default(0),
      closingBalance: z.number().default(0),
      notes: z.string().optional(),
      lines: z.array(z.object({
        transactionDate: z.string(),
        description: z.string(),
        reference: z.string().optional(),
        debit: z.number().default(0),
        credit: z.number().default(0),
        balance: z.number().default(0),
      })).optional(),
    }))
    .mutation(async ({ input, ctx }) => {
      const db = getDb();
      const tenantId = ctx.user!.tenantId as number;

      const account = await db.select().from(chartOfAccounts)
        .where(and(eq(chartOfAccounts.id, input.accountId), eq(chartOfAccounts.tenantId, tenantId)))
        .limit(1);
      if (!account[0]) throw new TRPCError({ code: "NOT_FOUND", message: "Bank account not found" });

      const lineDebits = (input.lines || []).reduce((s, l) => s + l.debit, 0);
      const lineCredits = (input.lines || []).reduce((s, l) => s + l.credit, 0);

      const result = await db.insert(bankStatements).values({
        tenantId,
        accountId: input.accountId,
        statementDate: new Date(input.statementDate),
        startDate: new Date(input.startDate),
        endDate: new Date(input.endDate),
        openingBalance: input.openingBalance.toFixed(2),
        closingBalance: input.closingBalance.toFixed(2),
        totalDebits: lineDebits.toFixed(2),
        totalCredits: lineCredits.toFixed(2),
        notes: input.notes || null,
        status: "pending",
      });

      const statementId = Number(result[0].insertId);

      if (input.lines && input.lines.length > 0) {
        for (const line of input.lines) {
          await db.insert(bankStatementLines).values({
            tenantId,
            statementId,
            transactionDate: new Date(line.transactionDate),
            description: line.description,
            reference: line.reference || null,
            debit: line.debit.toFixed(2),
            credit: line.credit.toFixed(2),
            balance: line.balance.toFixed(2),
            status: "unmatched",
          });
        }
      }

      await auditLog({ ctx, action: "bank_statement_created", entityType: "bank_statement", entityId: statementId });

      return { id: statementId };
    }),

  // ΓöÇΓöÇΓöÇ AUTO-MATCH LINES ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
  autoMatch: authedQuery
    .input(z.object({ statementId: z.number() }))
    .mutation(async ({ input, ctx }) => {
      const db = getDb();
      const tenantId = ctx.user!.tenantId as number;

      const lines = await db.select().from(bankStatementLines)
        .where(and(
          eq(bankStatementLines.statementId, input.statementId),
          eq(bankStatementLines.tenantId, tenantId),
          eq(bankStatementLines.status, "unmatched"),
        ));

      const statement = await db.select().from(bankStatements)
        .where(and(eq(bankStatements.id, input.statementId), eq(bankStatements.tenantId, tenantId)))
        .limit(1);
      if (!statement[0]) throw new TRPCError({ code: "NOT_FOUND", message: "Statement not found" });

      // Get ledger entries for this account in the statement period
      const ledger = await db.select().from(ledgerEntries)
        .where(and(
          eq(ledgerEntries.tenantId, tenantId),
          eq(ledgerEntries.accountId, statement[0].accountId),
          gte(ledgerEntries.date, statement[0].startDate),
          lte(ledgerEntries.date, statement[0].endDate),
        ));

      let matchedCount = 0;

      for (const line of lines) {
        const lineAmount = Number(line.debit) > 0 ? Number(line.debit) : Number(line.credit);
        const isDebit = Number(line.debit) > 0;

        // Try to find matching ledger entry by amount and approximate date
        const candidates = ledger.filter(l => {
          const ledgerAmount = Number(l.debit) > 0 ? Number(l.debit) : Number(l.credit);
          const ledgerIsDebit = Number(l.debit) > 0;
          const amountMatch = Math.abs(ledgerAmount - lineAmount) < 0.01;
          const directionMatch = isDebit === ledgerIsDebit;
          const alreadyMatched = lines.some(existing =>
            existing.matchedLedgerEntryId === l.id && existing.id !== line.id
          );
          return amountMatch && directionMatch && !alreadyMatched;
        });

        if (candidates.length > 0) {
          // Pick the closest by date
          const bestMatch = candidates.sort((a, b) => {
            const da = Math.abs(new Date(a.date).getTime() - new Date(line.transactionDate).getTime());
            const db_ = Math.abs(new Date(b.date).getTime() - new Date(line.transactionDate).getTime());
            return da - db_;
          })[0];

          await db.update(bankStatementLines).set({
            matchedLedgerEntryId: bestMatch.id,
            status: "matched",
            matchConfidence: "85.00",
          }).where(eq(bankStatementLines.id, line.id));

          matchedCount++;
        }
      }

      // Update statement status
      const remainingUnmatched = await db.select({ count: sql<number>`count(*)` }).from(bankStatementLines)
        .where(and(eq(bankStatementLines.statementId, input.statementId), eq(bankStatementLines.status, "unmatched")));
      const totalLines = await db.select({ count: sql<number>`count(*)` }).from(bankStatementLines)
        .where(eq(bankStatementLines.statementId, input.statementId));

      const newStatus = remainingUnmatched[0]?.count === 0 ? "reconciled" : remainingUnmatched[0]?.count < (totalLines[0]?.count ?? 0) ? "partial" : "pending";
      await db.update(bankStatements).set({ status: newStatus }).where(eq(bankStatements.id, input.statementId));

      return { matchedCount, status: newStatus };
    }),

  // ΓöÇΓöÇΓöÇ MANUAL MATCH ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
  manualMatch: authedQuery
    .input(z.object({
      lineId: z.number(),
      ledgerEntryId: z.number().optional(),
      journalEntryId: z.number().optional(),
    }))
    .mutation(async ({ input, ctx }) => {
      const db = getDb();
      const tenantId = ctx.user!.tenantId as number;

      const line = await db.select().from(bankStatementLines)
        .where(and(eq(bankStatementLines.id, input.lineId), eq(bankStatementLines.tenantId, tenantId)))
        .limit(1);
      if (!line[0]) throw new TRPCError({ code: "NOT_FOUND", message: "Statement line not found" });

      await db.update(bankStatementLines).set({
        matchedLedgerEntryId: input.ledgerEntryId || null,
        matchedJournalEntryId: input.journalEntryId || null,
        status: (input.ledgerEntryId || input.journalEntryId) ? "matched" : "unmatched",
        matchConfidence: (input.ledgerEntryId || input.journalEntryId) ? "100.00" : "0.00",
      }).where(eq(bankStatementLines.id, input.lineId));

      // Update statement status
      const statementId = line[0].statementId;
      const remainingUnmatched = await db.select({ count: sql<number>`count(*)` }).from(bankStatementLines)
        .where(and(eq(bankStatementLines.statementId, statementId), eq(bankStatementLines.status, "unmatched")));
      const totalLines = await db.select({ count: sql<number>`count(*)` }).from(bankStatementLines)
        .where(eq(bankStatementLines.statementId, statementId));

      const newStatus = remainingUnmatched[0]?.count === 0 ? "reconciled" : remainingUnmatched[0]?.count < (totalLines[0]?.count ?? 0) ? "partial" : "pending";
      await db.update(bankStatements).set({ status: newStatus }).where(eq(bankStatements.id, statementId));

      return { success: true };
    }),

  // ΓöÇΓöÇΓöÇ IGNORE LINE ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
  ignoreLine: authedQuery
    .input(z.object({ lineId: z.number() }))
    .mutation(async ({ input, ctx }) => {
      const db = getDb();
      const tenantId = ctx.user!.tenantId as number;

      await db.update(bankStatementLines).set({ status: "ignored" })
        .where(and(eq(bankStatementLines.id, input.lineId), eq(bankStatementLines.tenantId, tenantId)));

      return { success: true };
    }),

  // ΓöÇΓöÇΓöÇ STATS ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
  stats: authedQuery.query(async ({ ctx }) => {
    const db = getDb();
    const tenantId = ctx.user!.tenantId as number;

    const totalStatements = await db.select({ count: sql<number>`count(*)` }).from(bankStatements)
      .where(eq(bankStatements.tenantId, tenantId));
    const reconciled = await db.select({ count: sql<number>`count(*)` }).from(bankStatements)
      .where(and(eq(bankStatements.tenantId, tenantId), eq(bankStatements.status, "reconciled")));
    const partial = await db.select({ count: sql<number>`count(*)` }).from(bankStatements)
      .where(and(eq(bankStatements.tenantId, tenantId), eq(bankStatements.status, "partial")));
    const pending = await db.select({ count: sql<number>`count(*)` }).from(bankStatements)
      .where(and(eq(bankStatements.tenantId, tenantId), eq(bankStatements.status, "pending")));
    const unmatchedLines = await db.select({ count: sql<number>`count(*)` }).from(bankStatementLines)
      .where(and(eq(bankStatementLines.tenantId, tenantId), eq(bankStatementLines.status, "unmatched")));

    return {
      totalStatements: totalStatements[0]?.count ?? 0,
      reconciled: reconciled[0]?.count ?? 0,
      partial: partial[0]?.count ?? 0,
      pending: pending[0]?.count ?? 0,
      unmatchedLines: unmatchedLines[0]?.count ?? 0,
    };
  }),
});

import { z } from "zod";
import { TRPCError } from "@trpc/server";
import { createRouter, authedQuery } from "./middleware";
import { getDb } from "./queries/connection";
import {
  deposits,
  wallets,
  walletTransactions,
  chartOfAccounts,
  journalEntries,
  journalEntryLines,
  ledgerEntries,
  customers,
  customerTransactions,
  notifications,
  paymentLocations,
  users,
} from "@db/schema";
import { eq, desc, sql, and, inArray } from "drizzle-orm";
import { auditLog } from "./lib/audit";
import { nextNumber } from "./lib/numbering";

async function postDepositAccounting(
  db: import("./queries/connection").DbOrTx,
  deposit: typeof deposits.$inferSelect,
  tenantId: number,
  _userId: number,
) {
  const amount = Number(deposit.amount);

  // Get accounts
  const cashAccount = await db.query.chartOfAccounts.findFirst({
    where: and(eq(chartOfAccounts.code, "1000"), eq(chartOfAccounts.tenantId, tenantId)),
  });
  const depositAccount = await db.query.chartOfAccounts.findFirst({
    where: and(eq(chartOfAccounts.code, "2100"), eq(chartOfAccounts.tenantId, tenantId)),
  });
  if (!cashAccount || !depositAccount) {
    throw new TRPCError({ code: "INTERNAL_SERVER_ERROR", message: "Required COA accounts missing for deposit posting" });
  }

  // Create journal entry
  const journalResult = await db.insert(journalEntries).values({
    tenantId,
    entryNumber: `JE-${Date.now()}`,
    date: new Date(),
    description: `Deposit received: ${deposit.depositCode}`,
    referenceType: "deposit",
    referenceId: deposit.id,
    status: "posted",
    totalDebit: amount.toFixed(2),
    totalCredit: amount.toFixed(2),
  });
  const journalId = Number(journalResult[0].insertId ?? 0);

  if (journalId > 0) {
    await db.insert(journalEntryLines).values([
      { journalEntryId: journalId, accountId: cashAccount.id, description: "Cash/Bank received", debit: amount.toFixed(2), credit: "0.00" },
      { journalEntryId: journalId, accountId: depositAccount.id, description: "Customer deposit liability", debit: "0.00", credit: amount.toFixed(2) },
    ]);

    for (const line of [
      { accountId: cashAccount.id, debit: amount.toFixed(2), credit: "0.00", description: "Cash/Bank received" },
      { accountId: depositAccount.id, debit: "0.00", credit: amount.toFixed(2), description: "Customer deposit liability" },
    ]) {
      const account = await db.query.chartOfAccounts.findFirst({
        where: and(eq(chartOfAccounts.id, line.accountId), eq(chartOfAccounts.tenantId, tenantId)),
      });
      const currentBal = Number(account?.currentBalance ?? 0);
      const newBal = currentBal + Number(line.debit) - Number(line.credit);
      await db.insert(ledgerEntries).values({
        tenantId,
        journalEntryId: journalId,
        accountId: line.accountId,
        date: new Date(),
        description: line.description,
        debit: line.debit,
        credit: line.credit,
        balance: newBal.toFixed(2),
      });
      await db.update(chartOfAccounts).set({ currentBalance: newBal.toFixed(2) }).where(
        and(eq(chartOfAccounts.id, line.accountId), eq(chartOfAccounts.tenantId, tenantId)),
      );
    }
  }

  return { success: true, journalId };
}

export const depositRouter = createRouter({
  list: authedQuery
    .input(z.object({
      status: z.string().optional(),
      customerId: z.number().optional(),
      page: z.number().default(1),
      limit: z.number().default(20),
    }).optional())
    .query(async ({ input, ctx }) => {
      const db = getDb();
      const tenantId = ctx.user!.tenantId as number;
      const conditions = [eq(deposits.tenantId, tenantId)];
      // TODO: re-enable soft-delete filter after adding deleted_at column to DB
      // isNull(deposits.deletedAt)
      if (input?.status) conditions.push(eq(deposits.status, input.status as "pending" | "under_review" | "approved" | "rejected" | "expired"));
      if (input?.customerId) conditions.push(eq(deposits.customerId, input.customerId));
      const where = and(...conditions);

      const items = await db.select().from(deposits).where(where).orderBy(desc(deposits.createdAt)).limit(input?.limit ?? 20).offset(((input?.page ?? 1) - 1) * (input?.limit ?? 20));

      const customerIds = [...new Set(items.map(i => i.customerId).filter(Boolean))] as number[];
      const walletIds = [...new Set(items.map(i => i.walletId).filter(Boolean))] as number[];
      const locationIds = [...new Set(items.map(i => i.locationId).filter(Boolean))] as number[];

      const customerList = customerIds.length > 0
        ? await db.select().from(customers).where(and(eq(customers.tenantId, tenantId), inArray(customers.id, customerIds)))
        : [];
      const walletList = walletIds.length > 0
        ? await db.select().from(wallets).where(and(eq(wallets.tenantId, tenantId), inArray(wallets.id, walletIds)))
        : [];
      const locationList = locationIds.length > 0
        ? await db.select().from(paymentLocations).where(and(eq(paymentLocations.tenantId, tenantId), inArray(paymentLocations.id, locationIds)))
        : [];

      const customerMap = new Map(customerList.map(c => [c.id, c]));
      const walletMap = new Map(walletList.map(w => [w.id, w]));
      const locationMap = new Map(locationList.map(l => [l.id, l]));

      const itemsWithRelations = items.map(i => ({
        ...i,
        customer: customerMap.get(i.customerId || 0) || null,
        wallet: walletMap.get(i.walletId) || null,
        location: locationMap.get(i.locationId || 0) || null,
      }));

      const countResult = await db.select({ count: sql<number>`count(*)` }).from(deposits).where(where);
      return { items: itemsWithRelations, total: countResult[0]?.count ?? 0 };
    }),

  get: authedQuery
    .input(z.object({ id: z.number() }))
    .query(async ({ input, ctx }) => {
      const db = getDb();
      const tenantId = ctx.user!.tenantId as number;
      const deposit = await db.query.deposits.findFirst({
        where: and(eq(deposits.id, input.id), eq(deposits.tenantId, tenantId)),
      });
      if (!deposit) throw new TRPCError({ code: "NOT_FOUND", message: "Deposit not found" });
      return deposit;
    }),

  create: authedQuery
    .input(z.object({
      walletId: z.number(),
      customerId: z.number().optional(),
      amount: z.string().refine((value) => !isNaN(Number(value)) && Number(value) > 0, { message: "Amount must be positive" }),
      paymentMethod: z.enum(["cash", "bank_transfer", "cheque"]),
      referenceNumber: z.string().optional(),
      locationId: z.number().optional(),
      notes: z.string().optional(),
    }))
    .mutation(async ({ input, ctx }) => {
      const db = getDb();
      const tenantId = ctx.user!.tenantId as number;
      const amount = Number(input.amount);

      // Validate wallet
      const wallet = await db.query.wallets.findFirst({
        where: and(eq(wallets.id, input.walletId), eq(wallets.tenantId, tenantId)),
      });
      if (!wallet) throw new TRPCError({ code: "NOT_FOUND", message: "Wallet not found" });

      const depositCode = await nextNumber(db, tenantId, "MZR");

      const result = await db.insert(deposits).values({
        tenantId,
        customerId: input.customerId ?? null,
        walletId: input.walletId,
        depositCode,
        amount: amount.toFixed(2),
        paymentMethod: input.paymentMethod,
        referenceNumber: input.referenceNumber,
        locationId: input.locationId ?? null,
        status: "pending",
        notes: input.notes,
        createdBy: ctx.user!.id,
      });

      const depositId = Number(result[0].insertId);

      await auditLog({
        ctx,
        action: "create",
        entityType: "deposit",
        entityId: depositId,
        newValues: { depositCode, amount: input.amount, paymentMethod: input.paymentMethod, status: "pending" },
      });

      // Notify admins
      try {
        await db.insert(notifications).values({
          tenantId,
          userId: ctx.user!.id,
          title: "New Deposit Request",
          message: `Deposit ${depositCode} for $${amount.toLocaleString()} is awaiting approval.`,
          type: "info",
          category: "wallet",
          referenceType: "deposit",
          referenceId: depositId,
        });
      } catch { /* non-critical */ }

      return { id: depositId, depositCode };
    }),

  updateStatus: authedQuery
    .input(z.object({
      id: z.number(),
      status: z.enum(["pending", "under_review", "approved", "rejected", "expired"]),
      notes: z.string().optional(),
    }))
    .mutation(async ({ input, ctx }) => {
      const db = getDb();
      const tenantId = ctx.user!.tenantId as number;
      const deposit = await db.query.deposits.findFirst({
        where: and(eq(deposits.id, input.id), eq(deposits.tenantId, tenantId)),
      });
      if (!deposit) throw new TRPCError({ code: "NOT_FOUND", message: "Deposit not found" });

      const oldStatus = deposit.status;
      const amount = Number(deposit.amount);

      // Concurrency protection: prevent double-approval
      if (input.status === "approved" && oldStatus === "approved") {
        throw new TRPCError({ code: "CONFLICT", message: "Deposit already approved" });
      }

      // On approval: update deposit status + credit wallet + post accounting ΓÇö ALL inside one transaction
      if (input.status === "approved" && oldStatus !== "approved") {
        await db.transaction(async (tx) => {
          // Update deposit status inside transaction
          await tx.update(deposits).set({
            status: input.status,
            approvedBy: ctx.user!.id,
            approvedAt: new Date(),
            notes: input.notes ? `${deposit.notes || ""}\n${input.notes}` : deposit.notes,
          }).where(and(eq(deposits.id, input.id), eq(deposits.tenantId, tenantId)));

          const wallet = await tx.query.wallets.findFirst({
            where: and(eq(wallets.id, deposit.walletId), eq(wallets.tenantId, tenantId)),
          });
          if (!wallet) throw new TRPCError({ code: "NOT_FOUND", message: "Wallet not found" });

          const newBalance = Number(wallet.balance) + amount;
          await tx.update(wallets).set({ balance: newBalance.toFixed(2) }).where(eq(wallets.id, wallet.id));

          await tx.insert(walletTransactions).values({
            walletId: wallet.id,
            tenantId,
            type: "credit",
            amount: amount.toFixed(2),
            balanceAfter: newBalance.toFixed(2),
            description: `Deposit approved: ${deposit.depositCode}`,
            referenceType: "deposit",
            referenceId: deposit.id,
            createdBy: ctx.user!.id,
          });

          // Post accounting
          await postDepositAccounting(tx, deposit, tenantId, ctx.user!.id);

          // Create customer transaction if linked
          if (deposit.customerId) {
            await tx.insert(customerTransactions).values({
              tenantId,
              customerId: deposit.customerId,
              type: "deposit",
              amount: amount.toFixed(2),
              balance: amount.toFixed(2),
              description: `Deposit ${deposit.depositCode}`,
              referenceNumber: deposit.depositCode,
              createdBy: ctx.user!.id,
            });
          }
        });
      } else {
        // Non-approval updates (rejected, expired, etc.) ΓÇö update outside transaction
        await db.update(deposits).set({
          status: input.status,
          approvedBy: input.status === "approved" || input.status === "rejected" ? ctx.user!.id : deposit.approvedBy,
          approvedAt: input.status === "approved" || input.status === "rejected" ? new Date() : deposit.approvedAt,
          notes: input.notes ? `${deposit.notes || ""}\n${input.notes}` : deposit.notes,
        }).where(and(eq(deposits.id, input.id), eq(deposits.tenantId, tenantId)));
      }

      await auditLog({
        ctx,
        action: input.status === "approved" ? "approve" : input.status === "rejected" ? "reject" : "update_status",
        entityType: "deposit",
        entityId: input.id,
        oldValues: { status: oldStatus },
        newValues: { status: input.status, notes: input.notes },
      });

      // Notify creator
      try {
        await db.insert(notifications).values({
          tenantId,
          userId: deposit.createdBy ?? ctx.user!.id,
          title: `Deposit ${input.status === "approved" ? "Approved" : input.status === "rejected" ? "Rejected" : "Updated"}`,
          message: `Deposit ${deposit.depositCode} has been ${input.status}.`,
          type: input.status === "approved" ? "success" : input.status === "rejected" ? "warning" : "info",
          category: "wallet",
          referenceType: "deposit",
          referenceId: deposit.id,
        });

        // Notify finance / admin on approval
        if (input.status === "approved") {
          const financeUsers = await db.select({ id: users.id }).from(users).where(
            and(eq(users.tenantId, tenantId), inArray(users.role, ["admin", "accountant", "super_admin"]))
          );
          if (financeUsers.length > 0) {
            await db.insert(notifications).values(
              financeUsers.map((u) => ({
                tenantId,
                userId: u.id,
                title: "Deposit Approved",
                message: `Deposit ${deposit.depositCode} has been approved.`,
                type: "success" as const,
                category: "wallet" as const,
                referenceType: "deposit" as const,
                referenceId: deposit.id,
              }))
            );
          }
        }
      } catch { /* non-critical */ }

      return { success: true };
    }),

  stats: authedQuery.query(async ({ ctx }) => {
    const db = getDb();
    const tenantId = ctx.user!.tenantId as number;
    const statusCounts = await db
      .select({ status: deposits.status, count: sql<number>`count(*)`, total: sql<number>`COALESCE(SUM(amount), 0)` })
      .from(deposits)
      .where(eq(deposits.tenantId, tenantId))
      .groupBy(deposits.status);
    return { statusCounts };
  }),
});

