    };
  }),
});

import { z } from "zod";
import { TRPCError } from "@trpc/server";
import { createRouter, authedQuery, agentQuery, tenantAdminQuery } from "./middleware";
import { getDb } from "./queries/connection";
import { expenses, expenseCategories, chartOfAccounts, journalEntries, journalEntryLines, ledgerEntries, notifications } from "@db/schema";
import { eq, desc, sql, and, isNull } from "drizzle-orm";
import { auditLog } from "./lib/audit";

function ensureExpenseTenant(ctx: any, label = "") {
  const tid = ctx.user?.tenantId;
  console.log(`[Expense router] ${label} tenantId:`, tid);
  if (tid == null) {
    console.log("[Expense router] missing tenantId", ctx.user);
    throw new TRPCError({ code: "BAD_REQUEST", message: "Tenant context missing" });
  }
  return tid as number;
}

async function getOrCreateExpenseAccount(
  db: import("./queries/connection").DbOrTx,
  categoryName: string,
  tenantId: number,
) {
  // Try to find existing expense account by name
  const existing = await db.query.chartOfAccounts.findFirst({
    where: and(
      eq(chartOfAccounts.name, categoryName),
      eq(chartOfAccounts.type, "expense"),
      eq(chartOfAccounts.tenantId, tenantId),
    ),
  });
  if (existing) return existing;

  // Find next available code in 5xxx range
  const existingExpenses = await db
    .select({ code: chartOfAccounts.code })
    .from(chartOfAccounts)
    .where(and(eq(chartOfAccounts.tenantId, tenantId), eq(chartOfAccounts.type, "expense")));

  const codes = existingExpenses.map(e => Number(e.code)).filter(c => !isNaN(c) && c >= 5000 && c < 6000);
  const nextCode = codes.length > 0 ? Math.max(...codes) + 1 : 5001;

  const result = await db.insert(chartOfAccounts).values({
    tenantId,
    code: nextCode.toString(),
    name: categoryName,
    type: "expense",
    currentBalance: "0.00",
    status: "active",
    currency: "USD",
  });
  const id = Number(result[0].insertId);
  return { id, code: nextCode.toString(), name: categoryName, type: "expense" as const, currentBalance: "0.00" };
}

async function postExpenseAccounting(
  db: import("./queries/connection").DbOrTx,
  expense: typeof expenses.$inferSelect,
  tenantId: number,
  userId: number,
) {
  // Prevent duplicate posting
  const existingJournal = await db.query.journalEntries.findFirst({
    where: and(
      eq(journalEntries.referenceType, "expense"),
      eq(journalEntries.referenceId, expense.id),
      eq(journalEntries.tenantId, tenantId),
    ),
  });
  if (existingJournal) return { skipped: true, reason: "Already posted" };

  // Get category name
  const category = await db.query.expenseCategories.findFirst({
    where: and(eq(expenseCategories.id, expense.categoryId || 0), eq(expenseCategories.tenantId, tenantId)),
  });
  const categoryName = category?.name || "General Expense";

  // Get or create expense account
  const expenseAccount = await getOrCreateExpenseAccount(db, categoryName, tenantId);

  // Get cash account (1000)
  const cashAccount = await db.query.chartOfAccounts.findFirst({
    where: and(eq(chartOfAccounts.code, "1000"), eq(chartOfAccounts.tenantId, tenantId)),
  });
  if (!cashAccount) {
    return { skipped: true, reason: "Cash account not found" };
  }

  const amount = Number(expense.amount);

  // Create journal entry
  const journalResult = await db.insert(journalEntries).values({
    tenantId,
    entryNumber: `JE-EXP-${Date.now()}`,
    date: new Date(),
    description: `Expense: ${expense.title}`,
    referenceType: "expense",
    referenceId: expense.id,
    totalDebit: amount.toFixed(2),
    totalCredit: amount.toFixed(2),
    status: "posted",
    postedBy: userId,
    postedAt: new Date(),
  });
  const journalId = Number(journalResult[0].insertId ?? 0);

  if (journalId > 0) {
    await db.insert(journalEntryLines).values([
      {
        journalEntryId: journalId,
        accountId: expenseAccount.id,
        description: expense.title,
        debit: amount.toFixed(2),
        credit: "0.00",
      },
      {
        journalEntryId: journalId,
        accountId: cashAccount.id,
        description: "Cash/Bank payment",
        debit: "0.00",
        credit: amount.toFixed(2),
      },
    ]);

    // Create ledger entries
    for (const line of [
      { accountId: expenseAccount.id, debit: amount.toFixed(2), credit: "0.00", description: expense.title },
      { accountId: cashAccount.id, debit: "0.00", credit: amount.toFixed(2), description: "Cash/Bank payment" },
    ]) {
      const account = await db.query.chartOfAccounts.findFirst({
        where: and(eq(chartOfAccounts.id, line.accountId), eq(chartOfAccounts.tenantId, tenantId)),
      });
      const currentBalance = Number(account?.currentBalance ?? 0);
      const newBalance = currentBalance + Number(line.debit) - Number(line.credit);
      await db.insert(ledgerEntries).values({
        tenantId,
        journalEntryId: journalId,
        accountId: line.accountId,
        date: new Date(),
        description: line.description,
        debit: line.debit,
        credit: line.credit,
        balance: newBalance.toFixed(2),
      });
      await db.update(chartOfAccounts).set({ currentBalance: newBalance.toFixed(2) }).where(
        and(eq(chartOfAccounts.id, line.accountId), eq(chartOfAccounts.tenantId, tenantId)),
      );
    }
  }

  return { success: true, journalId };
}

export const expenseRouter = createRouter({
  list: authedQuery
    .input(z.object({
      status: z.string().optional(),
      categoryId: z.number().optional(),
      search: z.string().optional(),
      page: z.number().default(1),
      limit: z.number().default(20),
    }).optional())
    .query(async ({ input, ctx }) => {
      const db = getDb();
      const tenantId = ensureExpenseTenant(ctx, "list");
      const conditions = [eq(expenses.tenantId, tenantId), isNull(expenses.deletedAt)];
      if (input?.status) conditions.push(eq(expenses.status, input.status as "pending" | "approved" | "rejected" | "reimbursed"));
      if (input?.categoryId) conditions.push(eq(expenses.categoryId, input.categoryId));
      if (input?.search) {
        conditions.push(sql`${expenses.title} LIKE ${`%${input.search}%`}`);
      }
      const where = conditions.length > 1 ? and(...conditions) : conditions[0];

      const items = await db.query.expenses.findMany({
        where,
        limit: input?.limit ?? 20,
        offset: ((input?.page ?? 1) - 1) * (input?.limit ?? 20),
        orderBy: [desc(expenses.createdAt)],
        with: { category: true },
      });

      const countResult = await db.select({ count: sql<number>`count(*)` }).from(expenses).where(where);
      return { items, total: countResult[0]?.count ?? 0 };
    }),

  get: authedQuery
    .input(z.object({ id: z.number() }))
    .query(async ({ input, ctx }) => {
      const db = getDb();
      const tenantId = ensureExpenseTenant(ctx, "get");
      console.log("[Expense query] get input:", input);
      return db.query.expenses.findFirst({
        where: and(eq(expenses.id, input.id), eq(expenses.tenantId, tenantId)),
        with: { category: true },
      });
    }),

  create: agentQuery
    .input(z.object({
      categoryId: z.number(),
      title: z.string().min(1),
      description: z.string().optional(),
      amount: z.string().refine((value) => !isNaN(Number(value)) && Number(value) >= 0, {
        message: "Amount must be a valid non-negative number",
      }),
      expenseDate: z.string().refine((value) => !isNaN(new Date(value).getTime()), {
        message: "Valid expense date is required",
      }),
      paymentMethod: z.enum(["cash", "card", "bank_transfer", "cheque", "wallet", "other"]).default("cash"),
      vendor: z.string().optional(),
      receiptNumber: z.string().optional(),
      notes: z.string().optional(),
    }))
    .mutation(async ({ input, ctx }) => {
      const db = getDb();
      const tenantId = ensureExpenseTenant(ctx, "create");
      console.log("[Expense create] input:", input);
      const result = await db.insert(expenses).values({
        tenantId,
        categoryId: input.categoryId,
        title: input.title,
        description: input.description,
        amount: input.amount,
        expenseDate: new Date(input.expenseDate),
        paymentMethod: input.paymentMethod,
        vendor: input.vendor,
        receiptNumber: input.receiptNumber,
        notes: input.notes,
        status: "pending",
        submittedBy: ctx.user!.id,
      });
      await auditLog({
        ctx,
        action: "create",
        entityType: "expense",
        entityId: Number(result[0].insertId),
        newValues: { title: input.title, amount: input.amount, status: "pending" },
      });

      // Notify admins of new expense
      try {
        await db.insert(notifications).values({
          tenantId: ctx.user!.tenantId as number,
          userId: ctx.user!.id,
          title: "New Expense Submitted",
          message: `Expense "${input.title}" ($${input.amount}) is awaiting approval.`,
          type: "info",
          category: "expense",
          referenceType: "expense",
          referenceId: Number(result[0].insertId),
        });
      } catch { /* non-critical */ }

      return { id: Number(result[0].insertId) };
    }),

  updateStatus: tenantAdminQuery
    .input(z.object({
      id: z.number(),
      status: z.enum(["pending", "approved", "rejected", "reimbursed"]),
    }))
    .mutation(async ({ input, ctx }) => {
      const db = getDb();
      const tenantId = ctx.user!.tenantId as number;
      const existing = await db.query.expenses.findFirst({
        where: and(eq(expenses.id, input.id), eq(expenses.tenantId, tenantId)),
      });
      if (!existing) {
        throw new TRPCError({ code: "NOT_FOUND", message: "Expense not found" });
      }

      // Concurrency protection: prevent double-approval
      if (input.status === "approved" && existing.status === "approved") {
        throw new TRPCError({ code: "CONFLICT", message: "Expense already approved" });
      }

      await db.update(expenses).set({ status: input.status, approvedBy: ctx.user!.id }).where(
        and(eq(expenses.id, input.id), eq(expenses.tenantId, tenantId)),
      );

      // Auto-post accounting when approved ΓÇö inside transaction
      if (input.status === "approved" && existing.status !== "approved") {
        await db.transaction(async (tx) => {
          await postExpenseAccounting(tx, existing, tenantId, ctx.user!.id);
        });
      }

      await auditLog({
        ctx,
        action: input.status === "approved" ? "approve" : input.status === "rejected" ? "reject" : "update_status",
        entityType: "expense",
        entityId: input.id,
        oldValues: { status: existing.status },
        newValues: { status: input.status },
      });

      // Notify on approval/rejection
      if (["approved", "rejected"].includes(input.status)) {
        try {
          await db.insert(notifications).values({
            tenantId,
            userId: existing.submittedBy ?? ctx.user!.id,
            title: `Expense ${input.status === "approved" ? "Approved" : "Rejected"}`,
            message: `Expense "${existing.title}" has been ${input.status}.`,
            type: input.status === "approved" ? "success" : "warning",
            category: "expense",
            referenceType: "expense",
            referenceId: input.id,
          });
        } catch { /* non-critical */ }
      }

      return { success: true };
    }),

  categories: authedQuery.query(async ({ ctx }) => {
    const db = getDb();
    return db.query.expenseCategories.findMany({
      where: eq(expenseCategories.tenantId, ctx.user!.tenantId as number),
      orderBy: [expenseCategories.name],
    });
  }),

  stats: authedQuery.query(async ({ ctx }) => {
    const db = getDb();
    const tenantId = ctx.user!.tenantId as number;
    const statusCounts = await db
      .select({ status: expenses.status, count: sql<number>`count(*)`, total: sql<number>`COALESCE(SUM(amount), 0)` })
      .from(expenses)
      .where(eq(expenses.tenantId, tenantId))
      .groupBy(expenses.status);

    const monthly = await db
      .select({
        month: sql<string>`DATE_FORMAT(expense_date, '%Y-%m')`,
        total: sql<number>`COALESCE(SUM(amount), 0)`,
      })
      .from(expenses)
      .where(eq(expenses.tenantId, tenantId))
      .groupBy(sql`DATE_FORMAT(expense_date, '%Y-%m')`)
      .orderBy(sql`DATE_FORMAT(expense_date, '%Y-%m')`);

    return { statusCounts, monthly };
  }),

  delete: tenantAdminQuery
    .input(z.object({ id: z.number() }))
    .mutation(async ({ input, ctx }) => {
      const db = getDb();
      await db.update(expenses).set({
        deletedAt: new Date(),
        deletedBy: ctx.user!.id,
      }).where(and(eq(expenses.id, input.id), eq(expenses.tenantId, ctx.user!.tenantId as number)));
      return { success: true };
    }),
});

import { z } from "zod";
import { TRPCError } from "@trpc/server";
import { createRouter, authedQuery, tenantAdminQuery } from "./middleware";
import { getDb } from "./queries/connection";
import { invoices, invoiceItems, customers, tickets, ticketPassengers, airlines, customerTransactions, chartOfAccounts, journalEntries, journalEntryLines, ledgerEntries, notifications } from "@db/schema";
import { eq, desc, sql, and, isNull, inArray } from "drizzle-orm";
import { nextNumber } from "./lib/numbering";
import jsPDF from "jspdf";
import autoTable from "jspdf-autotable";

export const invoiceRouter = createRouter({
  list: authedQuery
    .input(z.object({
      status: z.string().optional(),
      customerId: z.number().optional(),
      search: z.string().optional(),
      page: z.number().default(1),
      limit: z.number().default(20),
    }).optional())
    .query(async ({ input, ctx }) => {
      const db = getDb();
      const tenantId = ctx.user!.tenantId as number;
      const conditions = [eq(invoices.tenantId, tenantId), isNull(invoices.deletedAt)];
      if (input?.status) conditions.push(eq(invoices.status, input.status as "draft" | "sent" | "partial" | "paid" | "overdue" | "cancelled"));
      if (input?.customerId) conditions.push(eq(invoices.customerId, input.customerId));
      if (input?.search) conditions.push(sql`${invoices.invoiceNumber} LIKE ${`%${input.search}%`}`);
      const where = conditions.length > 1 ? and(...conditions) : conditions[0];

      const items = await db.select().from(invoices).where(where).limit(input?.limit ?? 20).offset(((input?.page ?? 1) - 1) * (input?.limit ?? 20)).orderBy(desc(invoices.createdAt));
      const customerIds = [...new Set(items.map(i => i.customerId).filter(Boolean))] as number[];
      const customerList = customerIds.length > 0
        ? await db.select().from(customers).where(and(eq(customers.tenantId, tenantId), inArray(customers.id, customerIds)))
        : [];
      const customerMap = new Map(customerList.map(c => [c.id, c]));

      const itemsWithCustomer = items.map(i => ({
        ...i,
        customer: customerMap.get(i.customerId) || null,
      }));

      const countResult = await db.select({ count: sql<number>`count(*)` }).from(invoices).where(where);
      return { items: itemsWithCustomer, total: Number(countResult[0]?.count ?? 0) };
    }),

  get: authedQuery
    .input(z.object({ id: z.number() }))
    .query(async ({ input, ctx }) => {
      const db = getDb();
      const tenantId = ctx.user!.tenantId as number;
      const invoiceRow = await db.select().from(invoices).where(
        and(eq(invoices.id, input.id), eq(invoices.tenantId, tenantId)),
      ).limit(1);
      if (!invoiceRow[0]) return null;
      const inv = invoiceRow[0];

      const [itemsList, customerRow, ticketRow] = await Promise.all([
        db.select().from(invoiceItems).where(eq(invoiceItems.invoiceId, inv.id)),
        inv.customerId ? db.select().from(customers).where(
          and(eq(customers.id, inv.customerId), eq(customers.tenantId, tenantId))
        ).limit(1).then(r => r[0] || null) : Promise.resolve(null),
        inv.ticketId ? db.select().from(tickets).where(
          and(eq(tickets.id, inv.ticketId), eq(tickets.tenantId, tenantId))
        ).limit(1).then(r => r[0] || null) : Promise.resolve(null),
      ]);

      return { ...inv, items: itemsList, customer: customerRow, ticket: ticketRow };
    }),

  generateFromTicket: tenantAdminQuery
    .input(z.object({ ticketId: z.number() }))
    .mutation(async ({ input, ctx }) => {
      const db = getDb();
      const tenantId = ctx.user!.tenantId as number;

      const ticketRow = await db.select().from(tickets).where(
        and(eq(tickets.id, input.ticketId), eq(tickets.tenantId, tenantId)),
      ).limit(1);
      const ticket = ticketRow[0];
      if (!ticket) throw new TRPCError({ code: "NOT_FOUND", message: "Ticket not found" });
      if (!ticket.customerId) throw new TRPCError({ code: "BAD_REQUEST", message: "Ticket has no customer" });

      const [airlineRow, passengersList] = await Promise.all([
        ticket.airlineId ? db.select().from(airlines).where(and(eq(airlines.id, ticket.airlineId), eq(airlines.tenantId, tenantId))).limit(1).then(r => r[0] || null) : Promise.resolve(null),
        db.select().from(ticketPassengers).where(eq(ticketPassengers.ticketId, ticket.id)),
      ]);

      const customer = await db.query.customers.findFirst({
        where: and(eq(customers.id, ticket.customerId), eq(customers.tenantId, tenantId)),
      });
      if (!customer) throw new TRPCError({ code: "NOT_FOUND", message: "Customer not found" });

      // Check if invoice already exists for this ticket
      const existing = await db.query.invoices.findFirst({
        where: and(eq(invoices.ticketId, ticket.id), eq(invoices.tenantId, tenantId)),
      });
      if (existing) return { id: existing.id, invoiceNumber: existing.invoiceNumber };

      const invoiceNumber = await nextNumber(db, tenantId, "INV");

      const subtotal = Number(ticket.totalAmount) - Number(ticket.taxAmount);
      const tax = Number(ticket.taxAmount);
      const total = Number(ticket.totalAmount);

      const invoiceResult = await db.insert(invoices).values({
        tenantId,
        customerId: customer.id,
        invoiceNumber,
        ticketId: ticket.id,
        issueDate: new Date(),
        dueDate: new Date(Date.now() + 14 * 24 * 60 * 60 * 1000), // 14 days due
        subtotal: subtotal.toFixed(2),
        taxAmount: tax.toFixed(2),
        totalAmount: total.toFixed(2),
        paidAmount: "0.00",
        status: "sent",
        notes: `Generated from ticket ${ticket.ticketNumber}`,
        createdBy: ctx.user!.id,
      });
      const invoiceId = Number(invoiceResult[0].insertId);

      // Create invoice items
      const paxNames = passengersList.map(p => `${p.firstName} ${p.lastName}`).join(", ") || "";
      await db.insert(invoiceItems).values([
        {
          invoiceId,
          description: `Flight: ${ticket.routeFrom} ΓåÆ ${ticket.routeTo} | ${airlineRow?.name || ""} | ${paxNames}`,
          quantity: 1,
          unitPrice: subtotal.toFixed(2),
          totalPrice: subtotal.toFixed(2),
        },
      ]);

      return { id: invoiceId, invoiceNumber };
    }),

  updateStatus: tenantAdminQuery
    .input(z.object({
      id: z.number(),
      status: z.enum(["draft", "sent", "partial", "paid", "overdue", "cancelled"]),
    }))
    .mutation(async ({ input, ctx }) => {
      const db = getDb();
      await db.update(invoices).set({ status: input.status }).where(
        and(eq(invoices.id, input.id), eq(invoices.tenantId, ctx.user!.tenantId as number)),
      );
      return { success: true };
    }),

  recordPayment: tenantAdminQuery
    .input(z.object({
      id: z.number(),
      amount: z.string().min(1),
      paymentMethod: z.string().default("cash"),
      referenceNumber: z.string().optional(),
      description: z.string().optional(),
    }))
    .mutation(async ({ input, ctx }) => {
      const db = getDb();
      const tenantId = ctx.user!.tenantId as number;
      const amount = Number(input.amount);
      if (isNaN(amount) || amount <= 0) {
        throw new TRPCError({ code: "BAD_REQUEST", message: "Amount must be positive" });
      }

      const invoiceRow = await db.select().from(invoices).where(
        and(eq(invoices.id, input.id), eq(invoices.tenantId, tenantId)),
      ).limit(1);
      const invoice = invoiceRow[0];
      if (!invoice) throw new TRPCError({ code: "NOT_FOUND", message: "Invoice not found" });
      if (!invoice.customerId) throw new TRPCError({ code: "BAD_REQUEST", message: "Invoice has no customer" });

      const customer = invoice.customerId
        ? await db.select().from(customers).where(
            and(eq(customers.id, invoice.customerId), eq(customers.tenantId, tenantId))
          ).limit(1).then(r => r[0] || null)
        : null;

      await db.transaction(async (tx) => {
        // Update invoice paid amount and status
        const newPaid = Number(invoice.paidAmount) + amount;
        const newStatus = newPaid >= Number(invoice.totalAmount) ? "paid" : "partial";
        await tx.update(invoices).set({
          paidAmount: newPaid.toFixed(2),
          status: newStatus as "draft" | "sent" | "partial" | "paid" | "overdue" | "cancelled",
        }).where(and(eq(invoices.id, input.id), eq(invoices.tenantId, tenantId)));

        // Create customer transaction
        const balanceResult = await tx
          .select({ total: sql<number>`COALESCE(SUM(CASE WHEN type = 'receivable' THEN amount WHEN type IN ('payment','deposit','credit','refund') THEN -amount ELSE 0 END), 0)` })
          .from(customerTransactions)
          .where(and(eq(customerTransactions.tenantId, tenantId), eq(customerTransactions.customerId, invoice.customerId)));
        const currentBalance = Number(balanceResult[0]?.total ?? 0);

        await tx.insert(customerTransactions).values({
          tenantId,
          customerId: invoice.customerId,
          invoiceId: invoice.id,
          type: "payment",
          amount: amount.toFixed(2),
          balance: Math.max(0, currentBalance - amount).toFixed(2),
          description: input.description || `Invoice payment (${input.paymentMethod})`,
          referenceNumber: input.referenceNumber,
          createdBy: ctx.user!.id,
        });

        // Create accounting journal (Debit Cash, Credit AR)
        const cashAccount = await tx.query.chartOfAccounts.findFirst({
          where: and(eq(chartOfAccounts.code, "1000"), eq(chartOfAccounts.tenantId, tenantId)),
        });
        const arAccount = await tx.query.chartOfAccounts.findFirst({
          where: and(eq(chartOfAccounts.code, "1200"), eq(chartOfAccounts.tenantId, tenantId)),
        });

        if (cashAccount && arAccount) {
          const journalResult = await tx.insert(journalEntries).values({
            tenantId,
            entryNumber: `JE-${Date.now()}`,
            date: new Date(),
            description: `Invoice payment: ${invoice.invoiceNumber}`,
            referenceType: "invoice_payment",
            referenceId: invoice.id,
            totalDebit: amount.toFixed(2),
            totalCredit: amount.toFixed(2),
            status: "posted",
          });
          const journalId = Number(journalResult[0].insertId ?? 0);
          if (journalId > 0) {
            await tx.insert(journalEntryLines).values([
              { journalEntryId: journalId, accountId: cashAccount.id, description: "Cash received", debit: amount.toFixed(2), credit: "0.00" },
              { journalEntryId: journalId, accountId: arAccount.id, description: "AR reduction", debit: "0.00", credit: amount.toFixed(2) },
            ]);

            for (const line of [
              { accountId: cashAccount.id, debit: amount.toFixed(2), credit: "0.00", description: "Cash received" },
              { accountId: arAccount.id, debit: "0.00", credit: amount.toFixed(2), description: "AR reduction" },
            ]) {
              const account = await tx.query.chartOfAccounts.findFirst({
                where: and(eq(chartOfAccounts.id, line.accountId), eq(chartOfAccounts.tenantId, tenantId)),
              });
              const currentBal = Number(account?.currentBalance ?? 0);
              const newBal = currentBal + Number(line.debit) - Number(line.credit);
              await tx.insert(ledgerEntries).values({
                tenantId,
                journalEntryId: journalId,
                accountId: line.accountId,
                date: new Date(),
                description: line.description,
                debit: line.debit,
                credit: line.credit,
                balance: newBal.toFixed(2),
              });
              await tx.update(chartOfAccounts).set({ currentBalance: newBal.toFixed(2) }).where(
                and(eq(chartOfAccounts.id, line.accountId), eq(chartOfAccounts.tenantId, tenantId)),
              );
            }
          }
        }
      });

      // Notification (outside tx)
      try {
        await db.insert(notifications).values({
          tenantId,
          userId: ctx.user!.id,
          title: "Invoice Payment Received",
          message: `$${amount.toLocaleString()} received for invoice ${invoice.invoiceNumber}${customer ? ` from ${customer.firstName || ""} ${customer.lastName || ""}`.trim() : ""}.`,
          type: "success",
          category: "accounting",
          referenceType: "invoice",
          referenceId: invoice.id,
        });
      } catch { /* non-critical */ }

      return { success: true };
    }),

  pdf: authedQuery
    .input(z.object({ id: z.number() }))
    .query(async ({ input, ctx }) => {
      const db = getDb();
      const tenantId = ctx.user!.tenantId as number;
      const invoiceRow = await db.select().from(invoices).where(
        and(eq(invoices.id, input.id), eq(invoices.tenantId, tenantId)),
      ).limit(1);
      if (!invoiceRow[0]) throw new TRPCError({ code: "NOT_FOUND", message: "Invoice not found" });
      const inv = invoiceRow[0];

      const [itemsList, customerRow, ticketRow] = await Promise.all([
        db.select().from(invoiceItems).where(eq(invoiceItems.invoiceId, inv.id)),
        inv.customerId ? db.select().from(customers).where(
          and(eq(customers.id, inv.customerId), eq(customers.tenantId, tenantId))
        ).limit(1).then(r => r[0] || null) : Promise.resolve(null),
        inv.ticketId ? db.select().from(tickets).where(
          and(eq(tickets.id, inv.ticketId), eq(tickets.tenantId, tenantId))
        ).limit(1).then(r => r[0] || null) : Promise.resolve(null),
      ]);

      const invoice = { ...inv, items: itemsList, customer: customerRow, ticket: ticketRow };

      const doc = new jsPDF();
      const pageWidth = doc.internal.pageSize.getWidth();
      const margin = 14;

      doc.setFontSize(20);
      doc.setTextColor(99, 102, 241);
      doc.text("INVOICE", margin, 20);

      doc.setFontSize(10);
      doc.setTextColor(100, 100, 100);
      doc.text(`Invoice #: ${invoice.invoiceNumber}`, pageWidth - margin, 16, { align: "right" });
      doc.text(`Issue Date: ${new Date(invoice.issueDate).toLocaleDateString()}`, pageWidth - margin, 21, { align: "right" });
      if (invoice.dueDate) {
        doc.text(`Due Date: ${new Date(invoice.dueDate).toLocaleDateString()}`, pageWidth - margin, 26, { align: "right" });
      }
      doc.text(`Status: ${invoice.status.toUpperCase()}`, pageWidth - margin, 31, { align: "right" });

      doc.setFontSize(12);
      doc.setTextColor(0, 0, 0);
      doc.text("Bill To:", margin, 38);
      doc.setFontSize(10);
      doc.setTextColor(60, 60, 60);
      const c = invoice.customer;
      if (c) {
        const name = `${c.firstName || ""} ${c.lastName || ""}`.trim();
        doc.text(name || "Customer", margin, 44);
        if (c.company) doc.text(c.company, margin, 49);
        if (c.email) doc.text(c.email, margin, 54);
        if (c.phone) doc.text(c.phone, margin, 59);
        if (c.address) doc.text(c.address, margin, 64);
      }

      const items = (invoice.items || []).map((item: any) => [
        item.description,
        String(item.quantity),
        `$${Number(item.unitPrice).toLocaleString()}`,
        `$${Number(item.totalPrice).toLocaleString()}`,
      ]);

      autoTable(doc, {
        startY: 72,
        head: [["Description", "Qty", "Unit Price", "Total"]],
        body: items,
        theme: "grid",
        headStyles: { fillColor: [99, 102, 241], textColor: 255, fontSize: 10 },
        bodyStyles: { fontSize: 10 },
        columnStyles: {
          0: { cellWidth: "auto" },
          1: { cellWidth: 20, halign: "center" },
          2: { cellWidth: 40, halign: "right" },
          3: { cellWidth: 40, halign: "right" },
        },
      });

      const finalY = (doc as any).lastAutoTable?.finalY || 120;
      const totalsX = pageWidth - margin - 60;

      doc.setFontSize(10);
      doc.setTextColor(60, 60, 60);
      doc.text("Subtotal:", totalsX, finalY + 10, { align: "left" });
      doc.text(`$${Number(invoice.subtotal).toLocaleString()}`, pageWidth - margin, finalY + 10, { align: "right" });

      doc.text("Tax:", totalsX, finalY + 16, { align: "left" });
      doc.text(`$${Number(invoice.taxAmount).toLocaleString()}`, pageWidth - margin, finalY + 16, { align: "right" });

      doc.setFontSize(12);
      doc.setTextColor(0, 0, 0);
      doc.text("Total:", totalsX, finalY + 24, { align: "left" });
      doc.text(`$${Number(invoice.totalAmount).toLocaleString()}`, pageWidth - margin, finalY + 24, { align: "right" });

      doc.setFontSize(10);
      doc.setTextColor(60, 60, 60);
      doc.text("Paid:", totalsX, finalY + 30, { align: "left" });
      doc.text(`$${Number(invoice.paidAmount).toLocaleString()}`, pageWidth - margin, finalY + 30, { align: "right" });

      const balance = Number(invoice.totalAmount) - Number(invoice.paidAmount);
      if (balance > 0) {
        doc.setTextColor(200, 50, 50);
        doc.text("Balance Due:", totalsX, finalY + 36, { align: "left" });
        doc.text(`$${balance.toLocaleString()}`, pageWidth - margin, finalY + 36, { align: "right" });
      }

      if (invoice.notes) {
        doc.setTextColor(60, 60, 60);
        doc.setFontSize(9);
        doc.text("Notes:", margin, finalY + 48);
        doc.text(invoice.notes, margin, finalY + 53);
      }

      doc.setFontSize(8);
      doc.setTextColor(150, 150, 150);
      doc.text("Thank you for your business.", pageWidth / 2, doc.internal.pageSize.getHeight() - 10, { align: "center" });

      const dataUrl = doc.output("datauristring");
      return { dataUrl };
    }),
});

import * as jose from "jose";
import { env } from "../lib/env";
import type { SessionPayload } from "./types";
import { randomUUID } from "crypto";

const JWT_ALG = "HS256";
const ISSUER = "psb-erp";
const EXPIRY = "24h"; // Shorter token expiry

function getSigningKey(): Uint8Array | Buffer {
  const secret = env.appSecret;
  if (!secret || secret.length === 0) {
    throw new Error("APP_SECRET missing in environment");
  }
  if (secret.length < 32 && env.isProduction) {
    throw new Error("APP_SECRET must be at least 32 characters in production.");
  }
  if (secret.length < 32) {
    console.warn("[session] APP_SECRET is shorter than recommended (32+ chars).");
  }
  return new TextEncoder().encode(secret);
}

export async function signSessionToken(
  payload: SessionPayload,
): Promise<string> {
  console.log("[session]", "APP_SECRET exists:", !!process.env.APP_SECRET);
  const key = getSigningKey();
  const builder = new jose.SignJWT(payload)
    .setProtectedHeader({ alg: JWT_ALG })
    .setIssuedAt()
    .setExpirationTime(EXPIRY)
    .setJti(randomUUID())
    .setIssuer(ISSUER);

  if (payload.clientId) {
    builder.setAudience(payload.clientId);
  }

  return builder.sign(key);
}

export async function verifySessionToken(
  token: string,
): Promise<SessionPayload | null> {
  if (!token) {
    console.warn("[session] No token provided for verification.");
    return null;
  }
  try {
    console.log("[verify]", "APP_SECRET exists:", !!process.env.APP_SECRET);
    const key = getSigningKey();
    const verifyOpts: Record<string, any> = { algorithms: [JWT_ALG], issuer: ISSUER };
    if (env.appId) {
      verifyOpts.audience = env.appId;
    }
    const { payload } = await jose.jwtVerify(token, key, verifyOpts);
    const { unionId, clientId } = payload as Record<string, unknown>;
    if (!unionId || !clientId) {
      console.warn("[session] JWT payload missing required fields.");
      return null;
    }
    return { unionId: String(unionId), clientId: String(clientId) } as SessionPayload;
  } catch (error: any) {
    console.warn("[session] JWT verification failed:", error?.message || error);
    return null;
  }
}

if (!env.appSecret) {
  throw new Error("APP_SECRET missing in environment");
}

interface RequestConfig extends RequestInit {
  baseUrl?: string;
  params?: Record<string, string | number>;
  timeout?: number;
}

export class HttpClient {
  private baseUrl: string;
  private defaultHeaders: Record<string, string>;

  constructor(baseURL: string, opts?: { headers?: Record<string, string> }) {
    this.baseUrl = baseURL;
    this.defaultHeaders = {
      "Content-Type": "application/json",
      ...opts?.headers,
    };
  }

  async request<T>(endpoint: string, config: RequestConfig = {}): Promise<T> {
    const {
      method = "GET",
      params,
      body,
      headers,
      timeout = 30000,
      ...rest
    } = config;

    const url = new URL(`${this.baseUrl}${endpoint}`);
    if (params) {
      Object.entries(params).forEach(([key, value]) =>
        url.searchParams.append(key, value.toString()),
      );
    }

    const controller = new AbortController();
    const timeoutId = setTimeout(() => controller.abort(), timeout);

    try {
      const response = await fetch(url.toString(), {
        ...rest,
        method,
        headers: { ...this.defaultHeaders, ...headers },
        body: body ? JSON.stringify(body) : undefined,
        signal: controller.signal,
      });

      clearTimeout(timeoutId);

      if (!response.ok) {
        const errorData = (await response
          .json()
          .catch(() => ({}))) as Record<string, string>;
        throw new Error(errorData.message || `HTTP Error: ${response.status}`);
      }

      return (await response.json()) as T;
    } catch (error: any) {
      if (error.name === "AbortError") {
        throw new Error("Request timeout");
      }
      throw error;
    }
  }

  get<T>(
    url: string,
    params?: RequestConfig["params"],
    config?: RequestConfig,
  ) {
    return this.request<T>(url, { ...config, method: "GET", params });
  }

  post<T>(url: string, body?: any, config?: RequestConfig) {
    return this.request<T>(url, { ...config, method: "POST", body });
  }
}

/**
 * Centralized System Settings Service
 *
 * Provides typed access to tenant-scoped configuration stored in
 * the `system_settings` table. Supports both predefined typed settings
 * and arbitrary key-value storage.
 *
 * Categories:
 * - general: company info
 * - currency: default_currency, supported_currencies
 * - tax: default_tax_rate, tax_inclusive_pricing
 * - commission: default_commission_rate, commission_auto_post
 * - approval: *_approval_required flags
 * - numbering: prefix overrides, year_reset
 * - notifications: notification preferences
 */

import { eq, and } from "drizzle-orm";
import { systemSettings } from "@db/schema";
import type { DbOrTx } from "../queries/connection";

export type SettingCategory =
  | "general"
  | "currency"
  | "tax"
  | "commission"
  | "approval"
  | "numbering"
  | "notifications";

export interface SettingDefinition {
  key: string;
  category: SettingCategory;
  defaultValue: string;
  description: string;
  type: "string" | "number" | "boolean" | "json";
}

/** Predefined typed settings registry */
export const SETTING_DEFINITIONS: SettingDefinition[] = [
  // General
  { key: "company_name", category: "general", defaultValue: "", type: "string", description: "Company legal name" },
  { key: "company_address", category: "general", defaultValue: "", type: "string", description: "Company address" },
  { key: "company_phone", category: "general", defaultValue: "", type: "string", description: "Company phone" },
  { key: "company_email", category: "general", defaultValue: "", type: "string", description: "Company email" },

  // Currency
  { key: "default_currency", category: "currency", defaultValue: "USD", type: "string", description: "Default currency code" },
  { key: "supported_currencies", category: "currency", defaultValue: '["USD","AFN","EUR","AED"]', type: "json", description: "Supported currency codes" },

  // Tax
  { key: "default_tax_rate", category: "tax", defaultValue: "0", type: "number", description: "Default tax rate percentage" },
  { key: "tax_inclusive_pricing", category: "tax", defaultValue: "false", type: "boolean", description: "Prices include tax by default" },

  // Commission
  { key: "default_commission_rate", category: "commission", defaultValue: "0", type: "number", description: "Default commission rate percentage" },
  { key: "commission_auto_post", category: "commission", defaultValue: "true", type: "boolean", description: "Auto-post commission journal entries" },

  // Approval
  { key: "ticket_approval_required", category: "approval", defaultValue: "true", type: "boolean", description: "Tickets require manager approval" },
