function ensureTenant(ctx: any, label = "") {
  const tid = ctx.user?.tenantId;
  console.log(`[Payable router] ${label} tenantId:`, tid);
  if (tid == null) {
    console.log("[Payable router] missing tenantId", ctx.user);
    throw new TRPCError({ code: "BAD_REQUEST", message: "Tenant context missing" });
  }
  return tid as number;
}

async function getOrCreateApAccount(db: import("./queries/connection").DbOrTx, tenantId: number) {
  let ap = await db.query.chartOfAccounts.findFirst({
    where: and(eq(chartOfAccounts.code, "2000"), eq(chartOfAccounts.tenantId, tenantId)),
  });
  if (!ap) {
    const result = await db.insert(chartOfAccounts).values({
      tenantId,
      code: "2000",
      name: "Accounts Payable",
      type: "liability",
      currentBalance: "0.00",
      status: "active",
      currency: "USD",
    });
    ap = await db.query.chartOfAccounts.findFirst({ where: eq(chartOfAccounts.id, Number(result[0].insertId)) });
  }
  return ap;
}

async function getOrCreateExpenseAccount(db: import("./queries/connection").DbOrTx, category: string, tenantId: number) {
  const codeMap: Record<string, string> = {
    flight: "5100",
    hotel: "5110",
    car_rental: "5120",
    tour: "5130",
    insurance: "5140",
    visa: "5150",
    general: "5000",
  };
  const code = codeMap[category.toLowerCase()] || "5000";
  let account = await db.query.chartOfAccounts.findFirst({
    where: and(eq(chartOfAccounts.code, code), eq(chartOfAccounts.tenantId, tenantId)),
  });
  if (!account) {
    const nameMap: Record<string, string> = {
      "5100": "Flight Expense",
      "5110": "Hotel Expense",
      "5120": "Car Rental Expense",
      "5130": "Tour Package Expense",
      "5140": "Travel Insurance Expense",
      "5150": "Visa Processing Expense",
      "5000": "General Expense",
    };
    const result = await db.insert(chartOfAccounts).values({
      tenantId,
      code,
      name: nameMap[code] || category,
      type: "expense",
      currentBalance: "0.00",
      status: "active",
      currency: "USD",
    });
    account = await db.query.chartOfAccounts.findFirst({ where: eq(chartOfAccounts.id, Number(result[0].insertId)) });
  }
  return account;
}

export const payableRouter = createRouter({
  // ΓöÇΓöÇΓöÇ LIST BILLS ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
  bills: authedQuery
    .input(z.object({
      search: z.string().optional(),
      status: z.string().optional(),
      supplierId: z.number().optional(),
      fromDate: z.string().optional(),
      toDate: z.string().optional(),
      page: z.number().default(1),
      limit: z.number().default(20),
    }).optional())
    .query(async ({ input, ctx }) => {
      const db = getDb();
      const tenantId = ensureTenant(ctx, "bills");
      console.log("[Payables query] bills input:", input);
      const conditions = [eq(bills.tenantId, tenantId), isNull(bills.deletedAt)];

      if (input?.supplierId) conditions.push(eq(bills.supplierId, input.supplierId));
      if (input?.status) conditions.push(eq(bills.status, input.status as any));
      if (input?.fromDate) conditions.push(sql`${bills.issueDate} >= ${input.fromDate}`);
      if (input?.toDate) conditions.push(sql`${bills.issueDate} <= ${input.toDate}`);
      if (input?.search) {
        conditions.push(sql`(
          ${bills.billNumber} LIKE ${`%${input.search}%`} OR
          ${bills.referenceNumber} LIKE ${`%${input.search}%`}
        )`);
      }

      const where = and(...conditions);

      const items = await db.select().from(bills)
        .where(where)
        .limit(input?.limit ?? 20)
        .offset(((input?.page ?? 1) - 1) * (input?.limit ?? 20))
        .orderBy(desc(bills.createdAt));

      const supplierIds = [...new Set(items.map(b => b.supplierId).filter(Boolean))];
      const supplierList = supplierIds.length > 0
        ? await db.select().from(suppliers).where(and(eq(suppliers.tenantId, tenantId), inArray(suppliers.id, supplierIds)))
        : [];
      const supplierMap = new Map(supplierList.map(s => [s.id, s]));

      const totalResult = await db.select({ count: sql<number>`count(*)` }).from(bills).where(where);

      return {
        items: items.map(b => ({ ...b, supplier: supplierMap.get(b.supplierId) || null })),
        total: totalResult[0]?.count ?? 0,
      };
    }),

  // ΓöÇΓöÇΓöÇ GET BILL DETAIL ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
  billDetail: authedQuery
    .input(z.object({ id: z.number() }))
    .query(async ({ input, ctx }) => {
      const db = getDb();
      const tenantId = ensureTenant(ctx, "billDetail");
      console.log("[Payables query] billDetail input:", input);

      const bill = await db.select().from(bills)
        .where(and(eq(bills.id, input.id), eq(bills.tenantId, tenantId)))
        .limit(1);
      if (!bill[0]) throw new TRPCError({ code: "NOT_FOUND", message: "Bill not found" });

      const items = await db.select().from(billItems)
        .where(and(eq(billItems.billId, input.id), eq(billItems.tenantId, tenantId)));

      const supplierData = await db.select().from(suppliers)
        .where(and(eq(suppliers.id, bill[0].supplierId), eq(suppliers.tenantId, tenantId)))
        .limit(1);

      const payments = await db.select().from(supplierPayments)
        .where(and(eq(supplierPayments.billId, input.id), eq(supplierPayments.tenantId, tenantId)))
        .orderBy(desc(supplierPayments.createdAt));

      return { bill: bill[0], items, supplier: supplierData[0] || null, payments };
    }),

  // ΓöÇΓöÇΓöÇ CREATE BILL ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
  createBill: tenantAdminQuery
    .input(z.object({
      supplierId: z.number(),
      referenceNumber: z.string().optional(),
      issueDate: z.string(),
      dueDate: z.string(),
      description: z.string().optional(),
      category: z.string().optional(),
      currency: z.string().length(3).default("USD"),
      items: z.array(z.object({
        description: z.string().min(1),
        quantity: z.number().min(0.01).default(1),
        unitPrice: z.number().min(0),
        accountId: z.number().optional(),
      })).min(1),
      taxAmount: z.number().min(0).default(0),
      discountAmount: z.number().min(0).default(0),
    }))
    .mutation(async ({ input, ctx }) => {
      const db = getDb();
      const tenantId = ensureTenant(ctx, "createBill");
      console.log("[Payables create] createBill input:", input);

      const { billId, billNumber, totalAmount } = await db.transaction(async (tx) => {
        // Verify supplier
        const supplier = await tx.select().from(suppliers)
          .where(and(eq(suppliers.id, input.supplierId), eq(suppliers.tenantId, tenantId)))
          .limit(1);
        if (!supplier[0]) throw new TRPCError({ code: "NOT_FOUND", message: "Supplier not found" });

        const subtotal = input.items.reduce((sum, item) => sum + (item.quantity * item.unitPrice), 0);
        const totalAmount = subtotal + input.taxAmount - input.discountAmount;
        const billNumber = await nextNumber(tx, tenantId, "BILL");

        const billResult = await tx.insert(bills).values({
          tenantId,
          supplierId: input.supplierId,
          billNumber,
          referenceNumber: input.referenceNumber || null,
          issueDate: new Date(input.issueDate),
          dueDate: new Date(input.dueDate),
          subtotal: subtotal.toFixed(2),
          taxAmount: input.taxAmount.toFixed(2),
          discountAmount: input.discountAmount.toFixed(2),
          totalAmount: totalAmount.toFixed(2),
          amountPaid: "0.00",
          balanceDue: totalAmount.toFixed(2),
          currency: input.currency,
          description: input.description || null,
          status: "open",
          category: input.category || null,
        });

        const billId = Number(billResult[0].insertId);

        // Insert bill items
        const category = input.category || "general";
        for (const item of input.items) {
          let accountId = item.accountId;
          if (!accountId) {
            const expenseAccount = await getOrCreateExpenseAccount(tx, category, tenantId);
            accountId = Number(expenseAccount!.id);
          }
          await tx.insert(billItems).values({
            tenantId,
            billId,
            description: item.description,
            quantity: item.quantity.toFixed(2),
            unitPrice: item.unitPrice.toFixed(2),
            total: (item.quantity * item.unitPrice).toFixed(2),
            accountId: accountId || null,
          });
        }

        // Post journal entry: Expense Dr, AP Cr
        const apAccount = await getOrCreateApAccount(tx, tenantId);
        const expenseAccount = await getOrCreateExpenseAccount(tx, category, tenantId);

        if (!apAccount || !expenseAccount) {
          throw new TRPCError({ code: "INTERNAL_SERVER_ERROR", message: "Required COA accounts missing" });
        }

        const jeResult = await tx.insert(journalEntries).values({
          tenantId,
          entryNumber: `JE-${Date.now()}`,
          date: new Date(input.issueDate),
          description: `Bill ${billNumber} - ${supplier[0].companyName}`,
          referenceType: "bill",
          referenceId: billId,
          totalDebit: totalAmount.toFixed(2),
          totalCredit: totalAmount.toFixed(2),
          status: "posted",
        });
        const journalEntryId = Number(jeResult[0].insertId);

        // Journal lines
        await tx.insert(journalEntryLines).values([
          {
            journalEntryId,
            accountId: Number(expenseAccount.id),
            description: `Expense for bill ${billNumber}`,
            debit: totalAmount.toFixed(2),
            credit: "0.00",
          },
          {
            journalEntryId,
            accountId: Number(apAccount.id),
            description: `AP for bill ${billNumber}`,
            debit: "0.00",
            credit: totalAmount.toFixed(2),
          },
        ]);

        // Ledger entries
        const expenseLedgerBalance = await tx.select({
          balance: sql<number>`COALESCE(SUM(debit - credit), 0)`,
        }).from(ledgerEntries).where(eq(ledgerEntries.accountId, Number(expenseAccount.id)));
        const newExpenseBalance = Number(expenseLedgerBalance[0]?.balance ?? 0) + totalAmount;

        const apLedgerBalance = await tx.select({
          balance: sql<number>`COALESCE(SUM(debit - credit), 0)`,
        }).from(ledgerEntries).where(eq(ledgerEntries.accountId, Number(apAccount.id)));
        const newApBalance = Number(apLedgerBalance[0]?.balance ?? 0) - totalAmount;

        await tx.insert(ledgerEntries).values([
          {
            tenantId,
            journalEntryId,
            accountId: Number(expenseAccount.id),
            date: new Date(input.issueDate),
            description: `Expense for bill ${billNumber}`,
            debit: totalAmount.toFixed(2),
            credit: "0.00",
            balance: newExpenseBalance.toFixed(2),
            entryType: "transaction",
            referenceType: "bill",
            referenceId: billId,
          },
          {
            tenantId,
            journalEntryId,
            accountId: Number(apAccount.id),
            date: new Date(input.issueDate),
            description: `AP for bill ${billNumber}`,
            debit: "0.00",
            credit: totalAmount.toFixed(2),
            balance: newApBalance.toFixed(2),
            entryType: "transaction",
            referenceType: "bill",
            referenceId: billId,
          },
        ]);

        // Update COA balances
        await tx.update(chartOfAccounts).set({
          currentBalance: newExpenseBalance.toFixed(2),
        }).where(eq(chartOfAccounts.id, Number(expenseAccount.id)));
        await tx.update(chartOfAccounts).set({
          currentBalance: newApBalance.toFixed(2),
        }).where(eq(chartOfAccounts.id, Number(apAccount.id)));

        // Update bill with journal entry
        await tx.update(bills).set({ journalEntryId }).where(eq(bills.id, billId));

        // Update supplier balance due
        const newSupplierBalance = Number(supplier[0].balanceDue) + totalAmount;
        await tx.update(suppliers).set({
          balanceDue: newSupplierBalance.toFixed(2),
        }).where(eq(suppliers.id, input.supplierId));

        return { billId, billNumber, totalAmount };
      });

      await auditLog({
        ctx, action: "bill_created", entityType: "bill", entityId: billId,
        newValues: { billNumber, totalAmount, supplierId: input.supplierId },
      });

      return { id: billId, billNumber, totalAmount };
    }),

  // ΓöÇΓöÇΓöÇ UPDATE BILL STATUS ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
  updateBillStatus: tenantAdminQuery
    .input(z.object({ id: z.number(), status: z.enum(["draft", "open", "partial", "paid", "overdue", "cancelled"]) }))
    .mutation(async ({ input, ctx }) => {
      const db = getDb();
      const tenantId = ensureTenant(ctx, "updateBillStatus");
      console.log("[Payables update] updateBillStatus input:", input);

      const existing = await db.select().from(bills)
        .where(and(eq(bills.id, input.id), eq(bills.tenantId, tenantId)))
        .limit(1);
      if (!existing[0]) throw new TRPCError({ code: "NOT_FOUND", message: "Bill not found" });

      await db.update(bills).set({ status: input.status })
        .where(and(eq(bills.id, input.id), eq(bills.tenantId, tenantId)));

      await auditLog({ ctx, action: "bill_status_updated", entityType: "bill", entityId: input.id, newValues: { status: input.status } });
      return { success: true };
    }),

  // ΓöÇΓöÇΓöÇ CREATE PAYMENT ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
  createPayment: tenantAdminQuery
    .input(z.object({
      supplierId: z.number(),
      billId: z.number().optional(),
      amount: z.number().min(0.01),
      paymentMethod: z.enum(["cash", "bank_transfer", "cheque", "credit_card", "wallet"]),
      paymentDate: z.string(),
      referenceNumber: z.string().optional(),
      bankAccountId: z.number().optional(),
      notes: z.string().optional(),
    }))
    .mutation(async ({ input, ctx }) => {
      const db = getDb();
      const tenantId = ensureTenant(ctx, "createPayment");
      console.log("[Payables create] createPayment input:", input);

      // Concurrency check: verify supplier exists outside tx (read-only)
      const supplier = await db.select().from(suppliers)
        .where(and(eq(suppliers.id, input.supplierId), eq(suppliers.tenantId, tenantId)))
        .limit(1);
      if (!supplier[0]) throw new TRPCError({ code: "NOT_FOUND", message: "Supplier not found" });

      // If billId provided, verify outside tx (will re-verify inside)
      let bill = null;
      if (input.billId) {
        bill = await db.select().from(bills)
          .where(and(eq(bills.id, input.billId), eq(bills.tenantId, tenantId), eq(bills.supplierId, input.supplierId)))
          .limit(1);
        if (!bill[0]) throw new TRPCError({ code: "NOT_FOUND", message: "Bill not found" });
        if (Number(bill[0].balanceDue) < input.amount) {
          throw new TRPCError({ code: "BAD_REQUEST", message: "Payment amount exceeds bill balance" });
        }
      }

      const { paymentId, paymentNumber } = await db.transaction(async (tx) => {
        const paymentNumber = await nextNumber(tx, tenantId, "SP");

        // Post journal: AP Dr, Cash/Bank Cr
        const apAccount = await getOrCreateApAccount(tx, tenantId);
        const cashAccount = await tx.query.chartOfAccounts.findFirst({
          where: and(eq(chartOfAccounts.code, "1000"), eq(chartOfAccounts.tenantId, tenantId)),
        });
        if (!apAccount || !cashAccount) {
          throw new TRPCError({ code: "INTERNAL_SERVER_ERROR", message: "Required COA accounts missing" });
        }

        const jeResult = await tx.insert(journalEntries).values({
          tenantId,
          entryNumber: `JE-${Date.now()}`,
          date: new Date(input.paymentDate),
          description: `Payment ${paymentNumber} to ${supplier[0].companyName}`,
          referenceType: "supplier_payment",
          totalDebit: input.amount.toFixed(2),
          totalCredit: input.amount.toFixed(2),
          status: "posted",
        });
        const journalEntryId = Number(jeResult[0].insertId);

        await tx.insert(journalEntryLines).values([
          {
            journalEntryId,
            accountId: Number(apAccount.id),
            description: `AP payment ${paymentNumber}`,
            debit: input.amount.toFixed(2),
            credit: "0.00",
          },
          {
            journalEntryId,
            accountId: Number(cashAccount.id),
            description: `Cash payment ${paymentNumber}`,
            debit: "0.00",
            credit: input.amount.toFixed(2),
          },
        ]);

        // Ledger
        const apLedgerBalance = await tx.select({ balance: sql<number>`COALESCE(SUM(debit - credit), 0)` })
          .from(ledgerEntries).where(eq(ledgerEntries.accountId, Number(apAccount.id)));
        const newApBalance = Number(apLedgerBalance[0]?.balance ?? 0) + input.amount;

        const cashLedgerBalance = await tx.select({ balance: sql<number>`COALESCE(SUM(debit - credit), 0)` })
          .from(ledgerEntries).where(eq(ledgerEntries.accountId, Number(cashAccount.id)));
        const newCashBalance = Number(cashLedgerBalance[0]?.balance ?? 0) - input.amount;

        await tx.insert(ledgerEntries).values([
          {
            tenantId,
            journalEntryId,
            accountId: Number(apAccount.id),
            date: new Date(input.paymentDate),
            description: `AP payment ${paymentNumber}`,
            debit: input.amount.toFixed(2),
            credit: "0.00",
            balance: newApBalance.toFixed(2),
            entryType: "transaction",
            referenceType: "supplier_payment",
          },
          {
            tenantId,
            journalEntryId,
            accountId: Number(cashAccount.id),
            date: new Date(input.paymentDate),
            description: `Cash payment ${paymentNumber}`,
            debit: "0.00",
            credit: input.amount.toFixed(2),
            balance: newCashBalance.toFixed(2),
            entryType: "transaction",
            referenceType: "supplier_payment",
          },
        ]);

        // Update COA
        await tx.update(chartOfAccounts).set({ currentBalance: newApBalance.toFixed(2) }).where(eq(chartOfAccounts.id, Number(apAccount.id)));
        await tx.update(chartOfAccounts).set({ currentBalance: newCashBalance.toFixed(2) }).where(eq(chartOfAccounts.id, Number(cashAccount.id)));

        // Create payment record
        const paymentResult = await tx.insert(supplierPayments).values({
          tenantId,
          supplierId: input.supplierId,
          billId: input.billId || null,
          paymentNumber,
          amount: input.amount.toFixed(2),
          paymentMethod: input.paymentMethod,
          paymentDate: new Date(input.paymentDate),
          referenceNumber: input.referenceNumber || null,
          bankAccountId: input.bankAccountId || null,
          notes: input.notes || null,
          journalEntryId,
        });
        const paymentId = Number(paymentResult[0].insertId);

        // Update bill if applicable
        if (bill && bill[0] && input.billId) {
          const newAmountPaid = Number(bill[0].amountPaid) + input.amount;
          const newBalanceDue = Number(bill[0].balanceDue) - input.amount;
          const newStatus = newBalanceDue <= 0 ? "paid" : "partial";
          await tx.update(bills).set({
            amountPaid: newAmountPaid.toFixed(2),
            balanceDue: newBalanceDue.toFixed(2),
            status: newStatus,
          }).where(eq(bills.id, input.billId));
        }

        // Update supplier balance
        const newSupplierBalance = Math.max(0, Number(supplier[0].balanceDue) - input.amount);
        await tx.update(suppliers).set({
          balanceDue: newSupplierBalance.toFixed(2),
        }).where(eq(suppliers.id, input.supplierId));

        return { paymentId, paymentNumber };
      });

      await auditLog({
        ctx, action: "supplier_payment_created", entityType: "supplier_payment", entityId: paymentId,
        newValues: { paymentNumber, amount: input.amount, supplierId: input.supplierId, billId: input.billId },
      });

      return { id: paymentId, paymentNumber };
    }),

  // ΓöÇΓöÇΓöÇ LIST PAYMENTS ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
  payments: authedQuery
    .input(z.object({
      supplierId: z.number().optional(),
      billId: z.number().optional(),
      page: z.number().default(1),
      limit: z.number().default(20),
    }).optional())
    .query(async ({ input, ctx }) => {
      const db = getDb();
      const tenantId = ctx.user!.tenantId as number;
      const conditions = [eq(supplierPayments.tenantId, tenantId)];

      if (input?.supplierId) conditions.push(eq(supplierPayments.supplierId, input.supplierId));
      if (input?.billId) conditions.push(eq(supplierPayments.billId, input.billId));

      const where = and(...conditions);

      const items = await db.select().from(supplierPayments)
        .where(where)
        .limit(input?.limit ?? 20)
        .offset(((input?.page ?? 1) - 1) * (input?.limit ?? 20))
        .orderBy(desc(supplierPayments.createdAt));

      const supplierIds = [...new Set(items.map(p => p.supplierId).filter(Boolean))];
      const supplierList = supplierIds.length > 0
        ? await db.select().from(suppliers).where(and(eq(suppliers.tenantId, tenantId), inArray(suppliers.id, supplierIds)))
        : [];
      const supplierMap = new Map(supplierList.map(s => [s.id, s]));

      return { items: items.map(p => ({ ...p, supplier: supplierMap.get(p.supplierId) || null })) };
    }),

  // ΓöÇΓöÇΓöÇ AGING REPORT ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
  agingReport: authedQuery
    .input(z.object({ asOfDate: z.string().optional() }))
    .query(async ({ input, ctx }) => {
      const db = getDb();
      const tenantId = ctx.user!.tenantId as number;
      const asOf = input?.asOfDate || new Date().toISOString().split("T")[0];

      const openBills = await db.select().from(bills)
        .where(and(
          eq(bills.tenantId, tenantId),
          eq(bills.status, "open"),
          sql`${bills.dueDate} <= ${asOf}`,
        ));

      const supplierIds = [...new Set(openBills.map(b => b.supplierId))];
      const supplierList = supplierIds.length > 0
        ? await db.select().from(suppliers).where(and(eq(suppliers.tenantId, tenantId), inArray(suppliers.id, supplierIds)))
        : [];
      const supplierMap = new Map(supplierList.map(s => [s.id, s]));

      const now = new Date(asOf);
      const buckets = {
        current: [] as typeof openBills,
        d1_30: [] as typeof openBills,
        d31_60: [] as typeof openBills,
        d61_90: [] as typeof openBills,
        over90: [] as typeof openBills,
      };

      for (const bill of openBills) {
        const due = new Date(bill.dueDate);
        const daysDiff = Math.floor((now.getTime() - due.getTime()) / (1000 * 60 * 60 * 24));
        if (daysDiff <= 0) buckets.current.push(bill);
        else if (daysDiff <= 30) buckets.d1_30.push(bill);
        else if (daysDiff <= 60) buckets.d31_60.push(bill);
        else if (daysDiff <= 90) buckets.d61_90.push(bill);
        else buckets.over90.push(bill);
      }

      const sum = (billList: typeof openBills) => billList.reduce((s, b) => s + Number(b.balanceDue), 0);

      return {
        asOfDate: asOf,
        summary: {
          current: sum(buckets.current),
          days1To30: sum(buckets.d1_30),
          days31To60: sum(buckets.d31_60),
          days61To90: sum(buckets.d61_90),
          over90: sum(buckets.over90),
          total: sum(openBills),
        },
        details: openBills.map(b => ({
          ...b,
          supplier: supplierMap.get(b.supplierId) || null,
          daysOverdue: Math.max(0, Math.floor((now.getTime() - new Date(b.dueDate).getTime()) / (1000 * 60 * 60 * 24))),
        })),
      };
    }),

  // ΓöÇΓöÇΓöÇ PAYABLE STATS ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
  stats: authedQuery.query(async ({ ctx }) => {
    const db = getDb();
    const tenantId = ctx.user!.tenantId as number;

    const totalBills = await db.select({ count: sql<number>`count(*)`, total: sql<number>`COALESCE(SUM(total_amount), 0)` })
      .from(bills).where(eq(bills.tenantId, tenantId));
    const totalDue = await db.select({ total: sql<number>`COALESCE(SUM(balance_due), 0)` })
      .from(bills).where(and(eq(bills.tenantId, tenantId), eq(bills.status, "open")));
    const overdue = await db.select({ count: sql<number>`count(*)`, total: sql<number>`COALESCE(SUM(balance_due), 0)` })
      .from(bills).where(and(eq(bills.tenantId, tenantId), eq(bills.status, "overdue")));
    const totalPayments = await db.select({ total: sql<number>`COALESCE(SUM(amount), 0)` })
      .from(supplierPayments).where(eq(supplierPayments.tenantId, tenantId));
    const upcomingDue = await db.select({ count: sql<number>`count(*)`, total: sql<number>`COALESCE(SUM(balance_due), 0)` })
      .from(bills)
      .where(and(
        eq(bills.tenantId, tenantId),
        eq(bills.status, "open"),
        sql`${bills.dueDate} >= ${new Date().toISOString().split("T")[0]}`,
        sql`${bills.dueDate} <= DATE_ADD(CURDATE(), INTERVAL 7 DAY)`,
      ));

    return {
      totalBills: totalBills[0]?.count ?? 0,
      totalBilled: Number(totalBills[0]?.total ?? 0),
      totalDue: Number(totalDue[0]?.total ?? 0),
      overdueBills: overdue[0]?.count ?? 0,
      overdueAmount: Number(overdue[0]?.total ?? 0),
      totalPayments: Number(totalPayments[0]?.total ?? 0),
      upcomingDueCount: upcomingDue[0]?.count ?? 0,
      upcomingDueAmount: Number(upcomingDue[0]?.total ?? 0),
    };
  }),
});

import { z } from "zod";
import { TRPCError } from "@trpc/server";
import { createRouter, authedQuery } from "./middleware";
import { getDb } from "./queries/connection";
import { suppliers, supplierContacts, bills, supplierPayments } from "@db/schema";
import { eq, desc, sql, and } from "drizzle-orm";
import { auditLog } from "./lib/audit";
import { nextNumber } from "./lib/numbering";

function ensureTenant(ctx: any, label = "") {
  const tid = ctx.user?.tenantId;
  console.log(`[Supplier router] ${label} tenantId:`, tid);
  if (tid == null) {
    console.log("[Supplier router] missing tenantId", ctx.user);
    throw new TRPCError({ code: "BAD_REQUEST", message: "Tenant context missing" });
  }
  return tid as number;
}

export const supplierRouter = createRouter({
  // ΓöÇΓöÇΓöÇ LIST SUPPLIERS ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
  list: authedQuery
    .input(z.object({
      search: z.string().optional(),
      type: z.string().optional(),
      status: z.string().optional(),
      page: z.number().default(1),
      limit: z.number().default(20),
    }).optional())
    .query(async ({ input, ctx }) => {
      const db = getDb();
      const tenantId = ensureTenant(ctx, "list");
      console.log("[Supplier query] list input:", input);
      const conditions = [eq(suppliers.tenantId, tenantId)];

      if (input?.search) {
        conditions.push(sql`(
          ${suppliers.companyName} LIKE ${`%${input.search}%`} OR
          ${suppliers.tradeName} LIKE ${`%${input.search}%`} OR
          ${suppliers.email} LIKE ${`%${input.search}%`} OR
          ${suppliers.supplierCode} LIKE ${`%${input.search}%`}
        )`);
      }
      if (input?.type) conditions.push(eq(suppliers.supplierType, input.type as any));
      if (input?.status) conditions.push(eq(suppliers.status, input.status as any));

      const where = and(...conditions);

      const items = await db.select().from(suppliers)
        .where(where)
        .limit(input?.limit ?? 20)
        .offset(((input?.page ?? 1) - 1) * (input?.limit ?? 20))
        .orderBy(desc(suppliers.createdAt));

      const totalResult = await db.select({ count: sql<number>`count(*)` }).from(suppliers).where(where);
      return { items, total: totalResult[0]?.count ?? 0 };
    }),

  // ΓöÇΓöÇΓöÇ GET SINGLE SUPPLIER ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
  get: authedQuery
    .input(z.object({ id: z.number() }))
    .query(async ({ input, ctx }) => {
      const db = getDb();
      const tenantId = ensureTenant(ctx, "get");
      console.log("[Supplier query] get input:", input);
      const supplier = await db.select().from(suppliers)
        .where(and(eq(suppliers.id, input.id), eq(suppliers.tenantId, tenantId)))
        .limit(1);
      if (!supplier[0]) throw new TRPCError({ code: "NOT_FOUND", message: "Supplier not found" });
      return supplier[0];
    }),

  // ΓöÇΓöÇΓöÇ SUPPLIER DETAIL (with related data) ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
  detail: authedQuery
    .input(z.object({ id: z.number() }))
    .query(async ({ input, ctx }) => {
      const db = getDb();
      const tenantId = ensureTenant(ctx, "detail");
      console.log("[Supplier query] detail input:", input);

      const supplier = await db.select().from(suppliers)
        .where(and(eq(suppliers.id, input.id), eq(suppliers.tenantId, tenantId)))
        .limit(1);
      if (!supplier[0]) throw new TRPCError({ code: "NOT_FOUND", message: "Supplier not found" });

      const contacts = await db.select().from(supplierContacts)
        .where(and(eq(supplierContacts.supplierId, input.id), eq(supplierContacts.tenantId, tenantId)))
        .orderBy(desc(supplierContacts.isPrimary));

      const recentBills = await db.select().from(bills)
        .where(and(eq(bills.supplierId, input.id), eq(bills.tenantId, tenantId)))
        .orderBy(desc(bills.createdAt))
        .limit(10);

      const recentPayments = await db.select().from(supplierPayments)
        .where(and(eq(supplierPayments.supplierId, input.id), eq(supplierPayments.tenantId, tenantId)))
        .orderBy(desc(supplierPayments.createdAt))
        .limit(10);

      const billStats = await db.select({
        totalBills: sql<number>`count(*)`,
        totalAmount: sql<number>`COALESCE(SUM(${bills.totalAmount}), 0)`,
        totalPaid: sql<number>`COALESCE(SUM(${bills.amountPaid}), 0)`,
        totalDue: sql<number>`COALESCE(SUM(${bills.balanceDue}), 0)`,
        openBills: sql<number>`SUM(CASE WHEN ${bills.status} IN ('open','partial','overdue') THEN 1 ELSE 0 END)`,
        overdueBills: sql<number>`SUM(CASE WHEN ${bills.status} = 'overdue' THEN 1 ELSE 0 END)`,
      }).from(bills)
        .where(and(eq(bills.supplierId, input.id), eq(bills.tenantId, tenantId)));

      return {
        supplier: supplier[0],
        contacts,
        recentBills,
        recentPayments,
        stats: {
          totalBills: Number(billStats[0]?.totalBills ?? 0),
          totalAmount: Number(billStats[0]?.totalAmount ?? 0),
          totalPaid: Number(billStats[0]?.totalPaid ?? 0),
          totalDue: Number(billStats[0]?.totalDue ?? 0),
          openBills: Number(billStats[0]?.openBills ?? 0),
          overdueBills: Number(billStats[0]?.overdueBills ?? 0),
        },
      };
    }),

  // ΓöÇΓöÇΓöÇ CREATE SUPPLIER ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
  create: authedQuery
    .input(z.object({
      companyName: z.string().min(1),
      tradeName: z.string().optional(),
      supplierType: z.enum(["airline", "hotel", "tour_operator", "car_rental", "insurance", "visa_service", "other"]).default("other"),
      taxId: z.string().optional(),
      email: z.string().email().optional(),
      phone: z.string().optional(),
      address: z.string().optional(),
      city: z.string().optional(),
      country: z.string().optional(),
      website: z.string().optional(),
      creditLimit: z.number().min(0).default(0),
      paymentTerms: z.number().min(0).default(30),
      currency: z.string().length(3).default("USD"),
      notes: z.string().optional(),
      contacts: z.array(z.object({
        name: z.string().min(1),
        position: z.string().optional(),
        email: z.string().email().optional(),
        phone: z.string().optional(),
        isPrimary: z.boolean().default(false),
      })).optional(),
    }))
    .mutation(async ({ input, ctx }) => {
      const db = getDb();
      const tenantId = ensureTenant(ctx, "create");
      console.log("[Supplier create] input:", input);
      const supplierCode = await nextNumber(db, tenantId, "SUP");

      const result = await db.insert(suppliers).values({
        tenantId,
        supplierCode,
        companyName: input.companyName,
        tradeName: input.tradeName || null,
        supplierType: input.supplierType,
        taxId: input.taxId || null,
        email: input.email || null,
        phone: input.phone || null,
        address: input.address || null,
        city: input.city || null,
        country: input.country || null,
        website: input.website || null,
        creditLimit: input.creditLimit.toFixed(2),
        balanceDue: "0.00",
        paymentTerms: input.paymentTerms,
        currency: input.currency,
        status: "active",
        notes: input.notes || null,
      });

      const supplierId = Number(result[0].insertId);

      if (input.contacts && input.contacts.length > 0) {
        for (const c of input.contacts) {
          await db.insert(supplierContacts).values({
            tenantId,
            supplierId,
            name: c.name,
            position: c.position || null,
            email: c.email || null,
            phone: c.phone || null,
            isPrimary: c.isPrimary,
          });
        }
      }

      await auditLog({ ctx, action: "supplier_created", entityType: "supplier", entityId: supplierId, newValues: input });

      return { id: supplierId, supplierCode };
    }),

  // ΓöÇΓöÇΓöÇ UPDATE SUPPLIER ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
  update: authedQuery
    .input(z.object({
      id: z.number(),
      companyName: z.string().min(1).optional(),
      tradeName: z.string().optional(),
      supplierType: z.enum(["airline", "hotel", "tour_operator", "car_rental", "insurance", "visa_service", "other"]).optional(),
      taxId: z.string().optional(),
      email: z.string().email().optional(),
      phone: z.string().optional(),
      address: z.string().optional(),
      city: z.string().optional(),
      country: z.string().optional(),
      website: z.string().optional(),
      creditLimit: z.number().min(0).optional(),
      paymentTerms: z.number().min(0).optional(),
      currency: z.string().length(3).optional(),
      status: z.enum(["active", "inactive", "blocked"]).optional(),
      notes: z.string().optional(),
    }))
    .mutation(async ({ input, ctx }) => {
      const db = getDb();
      const tenantId = ensureTenant(ctx, "update");
      console.log("[Supplier update] input:", input);
      const { id, ...data } = input;

      const existing = await db.select().from(suppliers)
        .where(and(eq(suppliers.id, id), eq(suppliers.tenantId, tenantId)))
        .limit(1);
      if (!existing[0]) throw new TRPCError({ code: "NOT_FOUND", message: "Supplier not found" });

      const updateData: Record<string, any> = {};
      if (data.companyName !== undefined) updateData.companyName = data.companyName;
      if (data.tradeName !== undefined) updateData.tradeName = data.tradeName || null;
      if (data.supplierType !== undefined) updateData.supplierType = data.supplierType;
      if (data.taxId !== undefined) updateData.taxId = data.taxId || null;
      if (data.email !== undefined) updateData.email = data.email || null;
      if (data.phone !== undefined) updateData.phone = data.phone || null;
      if (data.address !== undefined) updateData.address = data.address || null;
      if (data.city !== undefined) updateData.city = data.city || null;
      if (data.country !== undefined) updateData.country = data.country || null;
      if (data.website !== undefined) updateData.website = data.website || null;
      if (data.creditLimit !== undefined) updateData.creditLimit = data.creditLimit.toFixed(2);
      if (data.paymentTerms !== undefined) updateData.paymentTerms = data.paymentTerms;
      if (data.currency !== undefined) updateData.currency = data.currency;
      if (data.status !== undefined) updateData.status = data.status;
      if (data.notes !== undefined) updateData.notes = data.notes || null;

      await db.update(suppliers).set(updateData)
        .where(and(eq(suppliers.id, id), eq(suppliers.tenantId, tenantId)));

      await auditLog({ ctx, action: "supplier_updated", entityType: "supplier", entityId: id, oldValues: existing[0], newValues: data });

      return { success: true };
    }),

  // ΓöÇΓöÇΓöÇ DELETE SUPPLIER ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
  delete: authedQuery
    .input(z.object({ id: z.number() }))
    .mutation(async ({ input, ctx }) => {
      const db = getDb();
      const tenantId = ensureTenant(ctx, "delete");
      console.log("[Supplier delete] input:", input);

      // Check for related bills
      const billCount = await db.select({ count: sql<number>`count(*)` }).from(bills)
        .where(and(eq(bills.supplierId, input.id), eq(bills.tenantId, tenantId)));
      if ((billCount[0]?.count ?? 0) > 0) {
        throw new TRPCError({ code: "CONFLICT", message: "Cannot delete supplier with existing bills" });
      }

      await db.delete(supplierContacts)
        .where(and(eq(supplierContacts.supplierId, input.id), eq(supplierContacts.tenantId, tenantId)));
      await db.delete(suppliers)
        .where(and(eq(suppliers.id, input.id), eq(suppliers.tenantId, tenantId)));

      await auditLog({ ctx, action: "supplier_deleted", entityType: "supplier", entityId: input.id });

      return { success: true };
    }),

  // ΓöÇΓöÇΓöÇ ADD CONTACT ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
  addContact: authedQuery
    .input(z.object({
      supplierId: z.number(),
      name: z.string().min(1),
      position: z.string().optional(),
      email: z.string().email().optional(),
      phone: z.string().optional(),
      isPrimary: z.boolean().default(false),
    }))
    .mutation(async ({ input, ctx }) => {
      const db = getDb();
      const tenantId = ensureTenant(ctx, "addContact");
      console.log("[Supplier addContact] input:", input);

      if (input.isPrimary) {
        await db.update(supplierContacts).set({ isPrimary: false })
          .where(and(eq(supplierContacts.supplierId, input.supplierId), eq(supplierContacts.tenantId, tenantId)));
      }

      const result = await db.insert(supplierContacts).values({
        tenantId,
        supplierId: input.supplierId,
        name: input.name,
        position: input.position || null,
        email: input.email || null,
        phone: input.phone || null,
        isPrimary: input.isPrimary,
      });

      return { id: Number(result[0].insertId) };
    }),

  // ΓöÇΓöÇΓöÇ DELETE CONTACT ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
  deleteContact: authedQuery
    .input(z.object({ id: z.number() }))
    .mutation(async ({ input, ctx }) => {
      const db = getDb();
      const tenantId = ensureTenant(ctx, "deleteContact");
      console.log("[Supplier deleteContact] input:", input);
      await db.delete(supplierContacts)
        .where(and(eq(supplierContacts.id, input.id), eq(supplierContacts.tenantId, tenantId)));
      return { success: true };
    }),

  // ΓöÇΓöÇΓöÇ SUPPLIER STATS ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
  stats: authedQuery.query(async ({ ctx }) => {
    const db = getDb();
    const tenantId = ensureTenant(ctx, "stats");
    console.log("[Supplier query] stats");

    const totalSuppliers = await db.select({ count: sql<number>`count(*)` }).from(suppliers).where(eq(suppliers.tenantId, tenantId));
    const activeSuppliers = await db.select({ count: sql<number>`count(*)` }).from(suppliers)
      .where(and(eq(suppliers.tenantId, tenantId), eq(suppliers.status, "active")));
    const totalPayable = await db.select({ total: sql<number>`COALESCE(SUM(balance_due), 0)` }).from(suppliers)
      .where(eq(suppliers.tenantId, tenantId));
    const overdueBills = await db.select({ count: sql<number>`count(*)` }).from(bills)
      .where(and(eq(bills.tenantId, tenantId), eq(bills.status, "overdue")));
    const typeBreakdown = await db.select({
      type: suppliers.supplierType,
      count: sql<number>`count(*)`,
    }).from(suppliers).where(eq(suppliers.tenantId, tenantId)).groupBy(suppliers.supplierType);

    return {
      totalSuppliers: totalSuppliers[0]?.count ?? 0,
      activeSuppliers: activeSuppliers[0]?.count ?? 0,
      totalPayable: Number(totalPayable[0]?.total ?? 0),
      overdueBills: overdueBills[0]?.count ?? 0,
      typeBreakdown,
    };
  }),
});

import { z } from "zod";
import { TRPCError } from "@trpc/server";
import { createRouter, authedQuery, tenantAdminQuery, agentQuery } from "./middleware";
import { getDb } from "./queries/connection";

import {
  tickets,
  ticketPassengers,
  airlines,
  wallets,
  walletTransactions,
  journalEntries,
  journalEntryLines,
  ledgerEntries,
  chartOfAccounts,
  notifications,
  customers,
  customerTransactions,
  invoices,
  invoiceItems,
  users,
} from "@db/schema";

import {
  eq,
  desc,
  asc,
  sql,
  like,
  and,
  or,
  inArray,
  isNull,
} from "drizzle-orm";
import { nextNumber } from "./lib/numbering";
import { auditLog } from "./lib/audit";

// =====================================================
// JSON metadata helper (MariaDB returns JSON as strings)
// =====================================================
function getTicketMetadata(ticket: typeof tickets.$inferSelect) {
  if (!ticket.metadata) return null;
  if (typeof ticket.metadata === "string") {
    try { return JSON.parse(ticket.metadata); } catch { return null; }
  }
  return ticket.metadata as any;
}

function ensureTicketTenant(ctx: any, label = "") {
  const tid = ctx.user?.tenantId;
  console.log(`[Ticket router] ${label} tenantId:`, tid);
  if (tid == null) {
    console.log("[Ticket router] missing tenantId", ctx.user);
    throw new TRPCError({ code: "BAD_REQUEST", message: "Tenant context missing" });
  }
  return tid as number;
}

// =====================================================
// APPROVAL HELPER
// =====================================================

async function approveTicket(
  db: import("./queries/connection").DbOrTx,
  ticket: typeof tickets.$inferSelect,
  user: { id: number; tenantId: number | null },
) {
  const tenantId = user.tenantId as number;
  const totalAmount = Number(ticket.totalAmount);
  console.log("[approve ticket]", ticket);
  console.log("[wallet deduction amount]", totalAmount);

  // Extract walletId from metadata
  const metadata = getTicketMetadata(ticket);
  let walletId = metadata?.walletId ?? null;
  console.log("[approve walletId from metadata]", walletId);

  if (!walletId) {
    // Fallback: find any active wallet for this tenant
    const fallbackWallet = await db.query.wallets.findFirst({
      where: and(eq(wallets.tenantId, tenantId), eq(wallets.status, "active")),
      orderBy: [desc(wallets.createdAt)],
    });
    if (fallbackWallet) {
      console.log("[approve fallback wallet]", fallbackWallet.id);
      walletId = fallbackWallet.id;
    }
  }

  if (!walletId) {
    throw new TRPCError({ code: "BAD_REQUEST", message: "Ticket wallet not recorded and no active wallet found" });
  }

  const userWallet = await db.query.wallets.findFirst({
    where: and(eq(wallets.id, walletId), eq(wallets.tenantId, tenantId), eq(wallets.status, "active")),
  });
  console.log("[approve wallet]", userWallet);
  if (!userWallet) {
    throw new TRPCError({ code: "BAD_REQUEST", message: "Wallet not found or inactive" });
  }
  if (Number(userWallet.balance) < totalAmount) {
    throw new TRPCError({ code: "BAD_REQUEST", message: "Insufficient wallet balance" });
  }

  const cashAccount = await db.query.chartOfAccounts.findFirst({
    where: and(eq(chartOfAccounts.code, "1000"), eq(chartOfAccounts.tenantId, tenantId)),
  });
  const arAccount = await db.query.chartOfAccounts.findFirst({
    where: and(eq(chartOfAccounts.code, "1200"), eq(chartOfAccounts.tenantId, tenantId)),
  });
  const revenueAccount = await db.query.chartOfAccounts.findFirst({
    where: and(eq(chartOfAccounts.code, "4000"), eq(chartOfAccounts.tenantId, tenantId)),
  });
  if (!cashAccount || !arAccount || !revenueAccount) {
    throw new TRPCError({ code: "BAD_REQUEST", message: "Accounting accounts missing" });
  }

  // Determine debit account: AR if customer is invoiced, Cash if walk-in
  const debitAccount = ticket.customerId ? arAccount : cashAccount;

  // Wallet deduction (atomic with guard)
  const debitResult = await db.update(wallets)
    .set({ balance: sql`${wallets.balance} - ${totalAmount.toFixed(2)}` })
    .where(and(eq(wallets.id, userWallet.id), sql`${wallets.balance} >= ${totalAmount.toFixed(2)}`));
  if (debitResult[0].affectedRows === 0) {
    throw new TRPCError({ code: "BAD_REQUEST", message: "Insufficient wallet balance" });
  }

  const updatedWallet = await db.query.wallets.findFirst({
    where: eq(wallets.id, userWallet.id),
  });

  // Wallet transaction
  await db.insert(walletTransactions).values({
    walletId: userWallet.id,
    tenantId,
    type: "debit",
    amount: totalAmount.toFixed(2),
    balanceAfter: updatedWallet!.balance,
    description: `Ticket booking: ${ticket.ticketNumber}`,
    referenceType: "ticket",
    referenceId: ticket.id,
    createdBy: user.id,
  });

  // Journal entry
  const journalResult = await db.insert(journalEntries).values({
    tenantId,
    entryNumber: `JE-${Date.now()}`,
    date: new Date(),
    description: `Ticket Sale ${ticket.ticketNumber}`,
    referenceType: "ticket",
    referenceId: ticket.id,
    status: "posted",
    totalDebit: totalAmount.toFixed(2),
    totalCredit: totalAmount.toFixed(2),
  });
  const journalId = Number(journalResult[0].insertId ?? 0);

  if (journalId > 0) {
    await db.insert(journalEntryLines).values([
      {
        journalEntryId: journalId,
        accountId: debitAccount.id,
        description: ticket.customerId ? "Accounts Receivable - Ticket Sale" : "Wallet deduction for ticket booking",
        debit: totalAmount.toFixed(2),
        credit: "0.00",
      },
      {
        journalEntryId: journalId,
        accountId: revenueAccount.id,
        description: "Ticket sales revenue",
        debit: "0.00",
        credit: totalAmount.toFixed(2),
      },
    ]);

    const journalLines = [
      { accountId: debitAccount.id, description: ticket.customerId ? "Accounts Receivable - Ticket Sale" : "Wallet deduction for ticket booking", debit: totalAmount.toFixed(2), credit: "0.00" },
      { accountId: revenueAccount.id, description: "Ticket sales revenue", debit: "0.00", credit: totalAmount.toFixed(2) },
    ];

    for (const line of journalLines) {
      const account = await db.query.chartOfAccounts.findFirst({
        where: and(eq(chartOfAccounts.id, line.accountId), eq(chartOfAccounts.tenantId, tenantId)),
      });
      const currentBalance = Number(account?.currentBalance ?? 0);
      const newAccBalance = currentBalance + Number(line.debit) - Number(line.credit);
      await db.insert(ledgerEntries).values({
        tenantId,
        journalEntryId: journalId,
        accountId: line.accountId,
        date: new Date(),
        description: line.description,
        debit: line.debit,
        credit: line.credit,
        balance: newAccBalance.toFixed(2),
      });
      await db.update(chartOfAccounts).set({ currentBalance: newAccBalance.toFixed(2) }).where(
        and(eq(chartOfAccounts.id, line.accountId), eq(chartOfAccounts.tenantId, tenantId)),
      );
    }
  }

  // Update ticket
  await db.update(tickets).set({ status: "confirmed", paymentStatus: "paid" }).where(eq(tickets.id, ticket.id));

  // =====================================================
  // CUSTOMER RECEIVABLE (if customer exists)
  // =====================================================
  if (ticket.customerId) {
    // Get current customer balance
    const balanceResult = await db
      .select({ total: sql<number>`COALESCE(SUM(CASE WHEN type = 'receivable' THEN amount WHEN type IN ('payment','deposit','credit','refund') THEN -amount ELSE 0 END), 0)` })
      .from(customerTransactions)
      .where(and(eq(customerTransactions.tenantId, tenantId), eq(customerTransactions.customerId, ticket.customerId)));
    const currentBalance = Number(balanceResult[0]?.total ?? 0);
    const newBalance = currentBalance + totalAmount;

    await db.insert(customerTransactions).values({
      tenantId,
      customerId: ticket.customerId,
      ticketId: ticket.id,
      type: "receivable",
      amount: totalAmount.toFixed(2),
      balance: newBalance.toFixed(2),
      description: `Ticket sale: ${ticket.ticketNumber}`,
      createdBy: user.id,
    });

    // Update customer stats
    await db.update(customers).set({
      totalBookings: sql`${customers.totalBookings} + 1`,
      totalRevenue: sql`${customers.totalRevenue} + ${totalAmount.toFixed(2)}`,
      lastBookingDate: new Date(),
    }).where(eq(customers.id, ticket.customerId));
  }

  // =====================================================
  // INVOICE AUTO-GENERATION (if customer exists)
  // =====================================================
  if (ticket.customerId) {
    try {
      const invoiceNumber = await nextNumber(db, tenantId, "INV");

      const invoiceResult = await db.insert(invoices).values({
        tenantId,
        customerId: ticket.customerId,
        invoiceNumber,
        ticketId: ticket.id,
        issueDate: new Date(),
        dueDate: new Date(Date.now() + 14 * 24 * 60 * 60 * 1000),
        subtotal: totalAmount.toFixed(2),
        taxAmount: Number(ticket.taxAmount).toFixed(2),
        totalAmount: totalAmount.toFixed(2),
        paidAmount: "0.00",
        status: "sent",
        notes: `Generated from ticket ${ticket.ticketNumber}`,
        createdBy: user.id,
      });
      const invoiceId = Number(invoiceResult[0].insertId);

      const paxList = await db.select().from(ticketPassengers).where(eq(ticketPassengers.ticketId, ticket.id));
      const paxNames = paxList.map(p => `${p.firstName} ${p.lastName}`).join(", ");
      const airline = await db.query.airlines.findFirst({ where: and(eq(airlines.id, ticket.airlineId || 0), eq(airlines.tenantId, tenantId)) });

      await db.insert(invoiceItems).values({
        invoiceId,
        description: `Flight: ${ticket.routeFrom} ΓåÆ ${ticket.routeTo} | ${airline?.name || ""} | ${paxNames}`,
        quantity: 1,
        unitPrice: totalAmount.toFixed(2),
        totalPrice: totalAmount.toFixed(2),
      });

      // Link receivable to invoice
      await db.update(customerTransactions)
        .set({ invoiceId })
        .where(and(
          eq(customerTransactions.tenantId, tenantId),
          eq(customerTransactions.ticketId, ticket.id),
          eq(customerTransactions.type, "receivable"),
        ));
    } catch {
      // Non-critical: invoice generation failure should not block approval
    }
  }

  // Commission accounting
  const commissionAmount = Number(ticket.commissionAmount ?? 0);
  if (commissionAmount > 0 && journalId > 0) {
    const commissionExpenseAccount = await db.query.chartOfAccounts.findFirst({
      where: and(eq(chartOfAccounts.code, "5000"), eq(chartOfAccounts.tenantId, tenantId)),
    });
    const commissionRevenueAccount = await db.query.chartOfAccounts.findFirst({
      where: and(eq(chartOfAccounts.code, "4100"), eq(chartOfAccounts.tenantId, tenantId)),
    });

    if (commissionExpenseAccount && commissionRevenueAccount) {
      await db.insert(journalEntryLines).values([
        { journalEntryId: journalId, accountId: commissionExpenseAccount.id, description: "Commission expense", debit: commissionAmount.toFixed(2), credit: "0.00" },
        { journalEntryId: journalId, accountId: commissionRevenueAccount.id, description: "Commission revenue", debit: "0.00", credit: commissionAmount.toFixed(2) },
      ]);

      for (const line of [
        { accountId: commissionExpenseAccount.id, debit: commissionAmount.toFixed(2), credit: "0.00", description: "Commission expense" },
        { accountId: commissionRevenueAccount.id, debit: "0.00", credit: commissionAmount.toFixed(2), description: "Commission revenue" },
      ]) {
        const account = await db.query.chartOfAccounts.findFirst({
          where: and(eq(chartOfAccounts.id, line.accountId), eq(chartOfAccounts.tenantId, tenantId)),
        });
        const currentBal = Number(account?.currentBalance ?? 0);
        const newBal = currentBal + Number(line.debit) - Number(line.credit);
        await db.insert(ledgerEntries).values({
          tenantId,
          journalEntryId: journalId,
          accountId: line.accountId,
          date: new Date(),
          description: line.description,
          debit: line.debit,
          credit: line.credit,
          balance: newBal.toFixed(2),
        });
        await db.update(chartOfAccounts).set({ currentBalance: newBal.toFixed(2) }).where(
          and(eq(chartOfAccounts.id, line.accountId), eq(chartOfAccounts.tenantId, tenantId)),
        );
      }

      // Update journal total
      const newTotal = totalAmount + commissionAmount;
      await db.update(journalEntries).set({
        totalDebit: newTotal.toFixed(2),
        totalCredit: newTotal.toFixed(2),
      }).where(eq(journalEntries.id, journalId));
    }
  }

  // Notification
  try {
    await db.insert(notifications).values({
      tenantId,
      userId: user.id,
      title: "Ticket Approved",
      message: `Ticket ${ticket.ticketNumber} has been approved and processed.`,
      type: "success",
      category: "ticket",
      referenceType: "ticket",
      referenceId: ticket.id,
    });

    // Notify creator
    if (ticket.issuedBy && ticket.issuedBy !== user.id) {
      await db.insert(notifications).values({
        tenantId,
        userId: ticket.issuedBy,
        title: "Ticket Approved",
        message: `Your ticket ${ticket.ticketNumber} has been approved and processed.`,
        type: "success",
        category: "ticket",
        referenceType: "ticket",
        referenceId: ticket.id,
      });
    }
  } catch {
    // Non-critical
  }

  return { success: true };
}

// =====================================================
// REFUND HELPER
// =====================================================

async function refundTicket(
  db: import("./queries/connection").DbOrTx,
  ticket: typeof tickets.$inferSelect,
  user: { id: number; tenantId: number | null },
  refundAmount: number,
  penaltyAmount: number,
  reason: string,
) {
  const tenantId = user.tenantId as number;
  const totalReversal = refundAmount + penaltyAmount;

  // Extract walletId from metadata
  const metadata = getTicketMetadata(ticket);
  const walletId = metadata?.walletId ?? null;
  if (!walletId) {
    throw new TRPCError({ code: "BAD_REQUEST", message: "Ticket wallet not recorded" });
  }

  const userWallet = await db.query.wallets.findFirst({
    where: and(eq(wallets.id, walletId), eq(wallets.tenantId, tenantId)),
  });
  if (!userWallet) {
    throw new TRPCError({ code: "BAD_REQUEST", message: "Wallet not found" });
  }

  // Credit wallet with refund amount (atomic)
  await db.update(wallets)
    .set({ balance: sql`${wallets.balance} + ${refundAmount.toFixed(2)}` })
    .where(eq(wallets.id, userWallet.id));

  const updatedWallet = await db.query.wallets.findFirst({
    where: eq(wallets.id, userWallet.id),
  });

  await db.insert(walletTransactions).values({
    walletId: userWallet.id,
    tenantId,
    type: "refund",
    amount: refundAmount.toFixed(2),
    balanceAfter: updatedWallet!.balance,
    description: `Ticket refund: ${ticket.ticketNumber}${reason ? ` - ${reason}` : ""}`,
    referenceType: "ticket",
    referenceId: ticket.id,
    createdBy: user.id,
  });

  // Reversal journal entry
  const revenueAccount = await db.query.chartOfAccounts.findFirst({
    where: and(eq(chartOfAccounts.code, "4000"), eq(chartOfAccounts.tenantId, tenantId)),
  });
  const creditAccount = ticket.customerId
    ? await db.query.chartOfAccounts.findFirst({ where: and(eq(chartOfAccounts.code, "1200"), eq(chartOfAccounts.tenantId, tenantId)) })
    : await db.query.chartOfAccounts.findFirst({ where: and(eq(chartOfAccounts.code, "1000"), eq(chartOfAccounts.tenantId, tenantId)) });

  if (!revenueAccount || !creditAccount) {
    throw new TRPCError({ code: "INTERNAL_SERVER_ERROR", message: "Required COA accounts missing for refund posting" });
  }

  // Get or create penalty revenue account if needed
  let penaltyAccount = null;
  if (penaltyAmount > 0) {
    penaltyAccount = await db.query.chartOfAccounts.findFirst({
      where: and(eq(chartOfAccounts.code, "4200"), eq(chartOfAccounts.tenantId, tenantId)),
    });
    if (!penaltyAccount) {
      const result = await db.insert(chartOfAccounts).values({
        tenantId,
        code: "4200",
        name: "Penalty Revenue",
        type: "revenue",
        currentBalance: "0.00",
        status: "active",
        currency: "USD",
      });
      penaltyAccount = { id: Number(result[0].insertId), code: "4200", name: "Penalty Revenue", type: "revenue" as const, currentBalance: "0.00" };
    }
  }

  const journalResult = await db.insert(journalEntries).values({
    tenantId,
    entryNumber: `JE-${Date.now()}`,
    date: new Date(),
    description: `Ticket Refund ${ticket.ticketNumber}${reason ? ` - ${reason}` : ""}`,
    referenceType: "ticket",
    referenceId: ticket.id,
    status: "posted",
    totalDebit: totalReversal.toFixed(2),
    totalCredit: totalReversal.toFixed(2),
  });
  const journalId = Number(journalResult[0].insertId ?? 0);

  if (journalId > 0) {
    const lines = [
      { journalEntryId: journalId, accountId: revenueAccount.id, description: "Revenue reversal - ticket refund", debit: totalReversal.toFixed(2), credit: "0.00" },
      { journalEntryId: journalId, accountId: creditAccount.id, description: "Cash/AR refund to customer", debit: "0.00", credit: refundAmount.toFixed(2) },
    ];
    if (penaltyAmount > 0 && penaltyAccount) {
      lines.push({ journalEntryId: journalId, accountId: penaltyAccount.id, description: "Cancellation penalty", debit: "0.00", credit: penaltyAmount.toFixed(2) });
    }

    await db.insert(journalEntryLines).values(lines);

    for (const line of lines) {
      const account = await db.query.chartOfAccounts.findFirst({
        where: and(eq(chartOfAccounts.id, line.accountId), eq(chartOfAccounts.tenantId, tenantId)),
      });
      const currentBal = Number(account?.currentBalance ?? 0);
      const newBal = currentBal + Number(line.debit) - Number(line.credit);
      await db.insert(ledgerEntries).values({
        tenantId,
        journalEntryId: journalId,
        accountId: line.accountId,
        date: new Date(),
        description: line.description,
        debit: line.debit,
        credit: line.credit,
        balance: newBal.toFixed(2),
      });
      await db.update(chartOfAccounts).set({ currentBalance: newBal.toFixed(2) }).where(
        and(eq(chartOfAccounts.id, line.accountId), eq(chartOfAccounts.tenantId, tenantId)),
      );
    }
  }

  // Update ticket
  await db.update(tickets).set({ status: "refunded", paymentStatus: "refunded" }).where(eq(tickets.id, ticket.id));

  // Customer transaction
  if (ticket.customerId) {
    await db.insert(customerTransactions).values({
      tenantId,
      customerId: ticket.customerId,
      ticketId: ticket.id,
      type: "refund",
      amount: refundAmount.toFixed(2),
      balance: refundAmount.toFixed(2),
      description: `Ticket refund: ${ticket.ticketNumber}${reason ? ` - ${reason}` : ""}`,
      createdBy: user.id,
    });

    // Update customer stats
    await db.update(customers).set({
      totalBookings: sql`GREATEST(0, ${customers.totalBookings} - 1)`,
      totalRevenue: sql`GREATEST(0, ${customers.totalRevenue} - ${totalReversal.toFixed(2)})`,
    }).where(eq(customers.id, ticket.customerId));

    // Cancel invoice if exists
    try {
      await db.update(invoices).set({ status: "cancelled" }).where(
        and(eq(invoices.ticketId, ticket.id), eq(invoices.tenantId, tenantId)),
      );
    } catch { /* non-critical */ }
  }

  // Notification
  try {
    await db.insert(notifications).values({
      tenantId,
      userId: user.id,
      title: "Ticket Refunded",
      message: `Ticket ${ticket.ticketNumber} has been refunded.$${refundAmount.toLocaleString()} returned${penaltyAmount > 0 ? ` (penalty: $${penaltyAmount.toLocaleString()})` : ""}.`,
      type: "warning",
      category: "ticket",
      referenceType: "ticket",
      referenceId: ticket.id,
    });
  } catch { /* non-critical */ }

  return { success: true };
}

export const ticketRouter = createRouter({
  // =====================================================
  // LIST TICKETS
  // =====================================================

  list: authedQuery
    .input(
      z
        .object({
          status: z.string().optional(),
          search: z.string().optional(),
          page: z.number().default(1),
          limit: z.number().default(20),
        })
        .optional(),
    )
    .query(async ({ input, ctx }) => {
      const db = getDb();

      const tenantId = ensureTicketTenant(ctx, "list");
      console.log("[Ticket query] list input:", input);

      const page =
        input?.page ?? 1;

      const limit =
        input?.limit ?? 20;

      const offset =
        (page - 1) * limit;

      const conditions = [
        eq(tickets.tenantId, tenantId),
        isNull(tickets.deletedAt),
      ];

      if (input?.status) {
        conditions.push(
          eq(
            tickets.status,
            input.status as
              | "confirmed"
              | "pending"
              | "cancelled"
              | "refunded"
              | "completed",
          ),
        );
      }

      if (input?.search) {
        conditions.push(
          or(
            like(tickets.ticketNumber, `%${input.search}%`),
            like(tickets.pnrCode, `%${input.search}%`),
            like(tickets.routeFrom, `%${input.search}%`),
            like(tickets.routeTo, `%${input.search}%`),
          )!,
        );
      }

      const where =
        conditions.length > 1
          ? and(...conditions)
          : conditions[0];

      const items = await db.select().from(tickets).where(where).limit(limit).offset(offset).orderBy(desc(tickets.createdAt));
      const ticketIds = items.map(t => t.id);
      const airlineIds = [...new Set(items.map(t => t.airlineId).filter(Boolean))] as number[];

      const airlineList = airlineIds.length > 0
        ? await db.select().from(airlines).where(and(eq(airlines.tenantId, tenantId), inArray(airlines.id, airlineIds)))
        : [];
      const airlineMap = new Map(airlineList.map(a => [a.id, a]));

      const passengerList = ticketIds.length > 0
        ? await db.select().from(ticketPassengers).where(inArray(ticketPassengers.ticketId, ticketIds))
        : [];
      const passengersByTicket = new Map<number, typeof passengerList>();
      for (const p of passengerList) {
        if (!passengersByTicket.has(p.ticketId)) passengersByTicket.set(p.ticketId, []);
        passengersByTicket.get(p.ticketId)!.push(p);
      }

      const itemsWithRelations = items.map(t => ({
        ...t,
        airline: t.airlineId ? airlineMap.get(t.airlineId) || null : null,
        passengers: passengersByTicket.get(t.id) || [],
      }));

      const countResult = await db
        .select({
          count: sql<number>`count(*)`,
        })
        .from(tickets)
        .where(where);

      return {
        items: itemsWithRelations,
        total: Number(countResult[0]?.count ?? 0),
        page,
        limit,
      };
    }),

  // =====================================================
  // GET SINGLE TICKET
  // =====================================================

  get: authedQuery
    .input(
      z.object({
        id: z.number(),
      }),
    )
    .query(async ({ input, ctx }) => {
      const db = getDb();
      const tenantId = ensureTicketTenant(ctx, "get");
      console.log("[Ticket query] get input:", input);

      const ticketResult = await db.select().from(tickets).where(
        and(eq(tickets.id, input.id), eq(tickets.tenantId, tenantId))
      ).limit(1);
      const ticket = ticketResult[0] || null;
      console.log("[Ticket query] ticket result:", ticket);

      if (!ticket) return null;

      const airlineResult = ticket.airlineId
        ? await db.select().from(airlines).where(
            and(eq(airlines.id, ticket.airlineId), eq(airlines.tenantId, tenantId))
          ).limit(1)
        : [];
      console.log("[Ticket query] airline result:", airlineResult[0] || null);

      const passengerResult = await db.select().from(ticketPassengers).where(
        eq(ticketPassengers.ticketId, ticket.id)
      );
      console.log("[Ticket query] passengers count:", passengerResult.length);

      return {
        ...ticket,
        airline: airlineResult[0] || null,
        passengers: passengerResult,
      };
    }),

  // =====================================================
  // CREATE TICKET
  // =====================================================

  create: agentQuery
    .input(
      z.object({
        ticketNumber: z.string().min(1),

        pnrCode: z.string().optional(),

        airlineId: z.number(),

        customerId: z.number().optional(),

        walletId: z.number(),

        travelDate: z
          .string()
          .refine(
            (value) =>
              !isNaN(
                new Date(value).getTime(),
              ),
            {
              message:
                "Valid travel date is required",
            },
          ),

        returnDate: z
          .string()
          .optional()
          .refine(
            (value) =>
              !value ||
              !isNaN(
                new Date(value).getTime(),
              ),
            {
              message:
                "Return date must be valid",
            },
          ),

        routeFrom: z
          .string()
          .min(2)
          .max(10),

        routeTo: z
          .string()
          .min(2)
          .max(10),

        tripType: z
          .enum([
            "one_way",
            "round_trip",
            "multi_city",
          ])
          .default("one_way"),

        class: z
          .enum([
            "economy",
            "premium_economy",
            "business",
            "first",
          ])
          .default("economy"),

        baseFare: z.string(),

        taxAmount: z.string(),

        totalAmount: z.string(),

        commissionAmount: z.string(),

        paidAmount: z.string().optional(),

        supplierCost: z.string().optional(),

        expense: z.string().optional(),

        netPayable: z.string(),

        notes: z.string().optional(),

        passengers: z
          .array(
            z.object({
              firstName: z.string(),

              lastName: z.string(),

              passengerType: z
                .enum([
                  "adult",
                  "child",
                  "infant",
                ])
                .default("adult"),

              passportNumber:
                z.string().optional(),

              nationality:
                z.string().optional(),

              seatNumber:
                z.string().optional(),
            }),
          )
          .optional(),
      }),
    )

    .mutation(async ({ input, ctx }) => {
      const db = getDb();

      const { passengers, ...ticketData } = input;
      const tenantId = ctx.user!.tenantId as number;
      console.log("[Ticket create] input:", input);

      // Calculate auto fields
      const ticketPrice = Number(ticketData.totalAmount || "0");
      const paidAmount = Number(ticketData.paidAmount || "0");
      console.log("[ticket total]", ticketPrice);
      let paymentStatus: "pending" | "partial" | "paid" = "pending";
      if (paidAmount >= ticketPrice && ticketPrice > 0) paymentStatus = "paid";
      else if (paidAmount > 0) paymentStatus = "partial";

      // =====================================================
      // WALLET VALIDATION (early check, no deduction yet)
      // =====================================================
      const userWallet = await db.query.wallets.findFirst({
        where: and(
          eq(wallets.id, input.walletId),
          eq(wallets.tenantId, tenantId),
          eq(wallets.status, "active"),
        ),
      });
      if (!userWallet) {
        throw new TRPCError({ code: "BAD_REQUEST", message: "Wallet not found or inactive" });
      }

      // =====================================================
      // ACCOUNTING ACCOUNTS VALIDATION (early check)
      // =====================================================
      const cashAccount = await db.query.chartOfAccounts.findFirst({
        where: and(eq(chartOfAccounts.code, "1000"), eq(chartOfAccounts.tenantId, tenantId)),
      });
      const revenueAccount = await db.query.chartOfAccounts.findFirst({
        where: and(eq(chartOfAccounts.code, "4000"), eq(chartOfAccounts.tenantId, tenantId)),
      });
      if (!cashAccount || !revenueAccount) {
        throw new TRPCError({ code: "BAD_REQUEST", message: "Accounting accounts missing" });
      }

      // =====================================================
      // AIRLINE VALIDATION
      // =====================================================
      const airline = await db.query.airlines.findFirst({
        where: and(eq(airlines.id, input.airlineId), eq(airlines.tenantId, tenantId)),
      });
      if (!airline) {
        throw new TRPCError({ code: "BAD_REQUEST", message: "Airline not found" });
      }

      // =====================================================
      // CREATE TICKET (pending, no financial posting)
      // =====================================================
      const result = await db.insert(tickets).values({
        ...ticketData,
        tenantId,
        travelDate: new Date(input.travelDate),
        returnDate: input.returnDate ? new Date(input.returnDate) : undefined,
        status: "pending",
        paymentStatus,
        issuedBy: ctx.user!.id,
        metadata: { walletId: input.walletId },
      });

      const ticketId = Number(result[0].insertId);

      // =====================================================
      // PASSENGERS
      // =====================================================
      if (passengers && passengers.length > 0) {
        await db.insert(ticketPassengers).values(
          passengers.map((p) => ({ ...p, ticketId })),
        );
      }

      // =====================================================
      // NOTIFICATION
      // =====================================================
      try {
        await db.insert(notifications).values({
          tenantId,
          userId: ctx.user!.id,
          title: "New Ticket Pending Approval",
          message: `Ticket ${input.ticketNumber} has been created and is awaiting approval.`,
          type: "info",
          category: "ticket",
          referenceType: "ticket",
          referenceId: ticketId,
        });

        // Notify admins / accountants
        const admins = await db.select({ id: users.id }).from(users).where(
          and(eq(users.tenantId, tenantId), inArray(users.role, ["admin", "accountant", "super_admin"]))
        );
        if (admins.length > 0) {
          await db.insert(notifications).values(
            admins.map((u) => ({
              tenantId,
              userId: u.id,
              title: "New Ticket Pending Approval",
              message: `Ticket ${input.ticketNumber} has been created and is awaiting approval.`,
              type: "info" as const,
              category: "ticket" as const,
              referenceType: "ticket" as const,
              referenceId: ticketId,
            }))
          );
        }
      } catch {
        // Non-critical: notification failure should not block ticket creation
      }

      await auditLog({
        ctx,
        action: "create",
        entityType: "ticket",
        entityId: ticketId,
        newValues: { ticketNumber: input.ticketNumber, status: "pending", amount: input.totalAmount },
      });

      return { id: ticketId };
    }),

  // =====================================================
  // APPROVE TICKET
  // =====================================================

  approve: tenantAdminQuery
    .input(z.object({ id: z.number() }))
    .mutation(async ({ input, ctx }) => {
      const db = getDb();
      const tenantId = ctx.user!.tenantId as number;

      const existing = await db.query.tickets.findFirst({
        where: and(eq(tickets.id, input.id), eq(tickets.tenantId, tenantId)),
      });
      if (!existing) {
        throw new TRPCError({ code: "NOT_FOUND", message: "Ticket not found" });
      }
      if (existing.status !== "pending") {
        throw new TRPCError({ code: "BAD_REQUEST", message: "Ticket is not pending approval" });
      }

      const result = await db.transaction(async (tx) => {
        const fresh = await tx.query.tickets.findFirst({
          where: and(eq(tickets.id, input.id), eq(tickets.tenantId, tenantId)),
        });
        if (!fresh || fresh.status !== "pending") {
          throw new TRPCError({ code: "CONFLICT", message: "Ticket is not pending approval" });
        }
        return approveTicket(tx, fresh, ctx.user!);
      });
      await auditLog({
        ctx,
        action: "approve",
        entityType: "ticket",
        entityId: input.id,
        oldValues: { status: existing.status },
        newValues: { status: "confirmed" },
      });
      return result;
    }),

  // =====================================================
  // REJECT TICKET
  // =====================================================

  reject: tenantAdminQuery
    .input(z.object({ id: z.number(), reason: z.string().optional() }))
    .mutation(async ({ input, ctx }) => {
      const db = getDb();
      const tenantId = ctx.user!.tenantId as number;

      const existing = await db.query.tickets.findFirst({
        where: and(eq(tickets.id, input.id), eq(tickets.tenantId, tenantId)),
      });
      if (!existing) {
        throw new TRPCError({ code: "NOT_FOUND", message: "Ticket not found" });
      }
      if (existing.status !== "pending") {
        throw new TRPCError({ code: "BAD_REQUEST", message: "Ticket is not pending approval" });
      }

      await db.update(tickets).set({ status: "cancelled", paymentStatus: "cancelled" }).where(eq(tickets.id, input.id));

      try {
        await db.insert(notifications).values({
          tenantId,
          userId: ctx.user!.id,
          title: "Ticket Rejected",
          message: `Ticket ${existing.ticketNumber} has been rejected. ${input.reason || ""}`,
          type: "warning",
          category: "ticket",
          referenceType: "ticket",
          referenceId: existing.id,
        });

        // Notify creator
        if (existing.issuedBy && existing.issuedBy !== ctx.user!.id) {
          await db.insert(notifications).values({
            tenantId,
            userId: existing.issuedBy,
            title: "Ticket Rejected",
            message: `Your ticket ${existing.ticketNumber} has been rejected. ${input.reason || ""}`,
            type: "warning",
            category: "ticket",
            referenceType: "ticket",
            referenceId: existing.id,
          });
        }
      } catch {
        // Non-critical
      }

      await auditLog({
        ctx,
        action: "reject",
        entityType: "ticket",
        entityId: input.id,
        oldValues: { status: existing.status },
        newValues: { status: "cancelled", reason: input.reason },
      });

      return { success: true };
    }),

  // =====================================================
  // REFUND TICKET
  // =====================================================

  refund: tenantAdminQuery
    .input(z.object({
      id: z.number(),
      refundAmount: z.string().min(1),
      penaltyAmount: z.string().optional(),
      reason: z.string().optional(),
    }))
    .mutation(async ({ input, ctx }) => {
      const db = getDb();
      const tenantId = ctx.user!.tenantId as number;
      const refundAmount = Number(input.refundAmount);
      const penaltyAmount = Number(input.penaltyAmount || "0");

      if (isNaN(refundAmount) || refundAmount <= 0) {
        throw new TRPCError({ code: "BAD_REQUEST", message: "Refund amount must be positive" });
      }
      if (isNaN(penaltyAmount) || penaltyAmount < 0) {
        throw new TRPCError({ code: "BAD_REQUEST", message: "Penalty amount cannot be negative" });
      }

      const existing = await db.query.tickets.findFirst({
        where: and(eq(tickets.id, input.id), eq(tickets.tenantId, tenantId)),
      });
      if (!existing) {
        throw new TRPCError({ code: "NOT_FOUND", message: "Ticket not found" });
      }
      if (!["confirmed", "completed"].includes(existing.status)) {
        throw new TRPCError({ code: "BAD_REQUEST", message: "Only confirmed or completed tickets can be refunded" });
      }

      const totalAmount = Number(existing.totalAmount);
      if (refundAmount + penaltyAmount > totalAmount) {
        throw new TRPCError({ code: "BAD_REQUEST", message: "Refund + penalty cannot exceed ticket total" });
      }

      // Concurrency protection: prevent double-refund
      if (existing.status === "refunded") {
        throw new TRPCError({ code: "CONFLICT", message: "Ticket already refunded" });
      }

      const result = await db.transaction(async (tx) => {
        const fresh = await tx.query.tickets.findFirst({
          where: and(eq(tickets.id, input.id), eq(tickets.tenantId, tenantId)),
        });
        if (!fresh || !["confirmed", "completed"].includes(fresh.status)) {
          throw new TRPCError({ code: "CONFLICT", message: "Ticket cannot be refunded" });
        }
        if (fresh.status === "refunded") {
          throw new TRPCError({ code: "CONFLICT", message: "Ticket already refunded" });
        }
        return refundTicket(tx, fresh, ctx.user!, refundAmount, penaltyAmount, input.reason || "");
      });

      await auditLog({
        ctx,
        action: "refund",
        entityType: "ticket",
        entityId: input.id,
        oldValues: { status: existing.status, totalAmount: existing.totalAmount },
        newValues: { status: "refunded", refundAmount: input.refundAmount, penaltyAmount: input.penaltyAmount, reason: input.reason },
      });

      return result;
    }),

  // =====================================================
  // UPDATE STATUS (simple transitions, approval goes through approve/reject)
  // =====================================================

  updateStatus: tenantAdminQuery
    .input(
      z.object({
        id: z.number(),
        status: z.enum(["confirmed", "pending", "cancelled", "refunded", "completed"]),
        paymentStatus: z.enum(["pending", "partial", "paid", "refunded", "cancelled"]).optional(),
      }),
    )
    .mutation(async ({ input, ctx }) => {
      const db = getDb();
      const tenantId = ctx.user!.tenantId as number;

      const existing = await db.query.tickets.findFirst({
        where: and(eq(tickets.id, input.id), eq(tickets.tenantId, tenantId)),
      });
      if (!existing) {
        throw new TRPCError({ code: "NOT_FOUND", message: "Ticket not found" });
      }

      // Redirect pendingΓåÆconfirmed to approve workflow
      if (existing.status === "pending" && input.status === "confirmed") {
        return db.transaction(async (tx) => {
          const fresh = await tx.query.tickets.findFirst({
            where: and(eq(tickets.id, input.id), eq(tickets.tenantId, tenantId)),
          });
          if (!fresh || fresh.status !== "pending") {
            throw new TRPCError({ code: "CONFLICT", message: "Ticket is not pending approval" });
          }
          return approveTicket(tx, fresh, ctx.user!);
        });
      }

      const update: Record<string, string> = { status: input.status };
      if (input.paymentStatus) update.paymentStatus = input.paymentStatus;

      await db.update(tickets).set(update).where(eq(tickets.id, input.id));

      return { success: true };
    }),

  // =====================================================
  // AIRLINES
  // =====================================================

  airlines: authedQuery.query(
    async ({ ctx }) => {
      const db = getDb();

      return db.query.airlines.findMany(
        {
          where: and(
            eq(
              airlines.status,
              "active",
            ),

            eq(
              airlines.tenantId,
              ctx.user!
                .tenantId as number,
            ),
          ),

          orderBy: [
            asc(airlines.name),
          ],
        },
      );
    },
  ),

  // =====================================================
  // STATS
  // =====================================================

  stats: authedQuery.query(
    async ({ ctx }) => {
      const db = getDb();

      const tenantId =
        ctx.user!.tenantId as number;

      const statusCounts =
        await db
          .select({
            status:
              tickets.status,

            count:
              sql<number>`count(*)`,
          })
          .from(tickets)
          .where(
            eq(
              tickets.tenantId,
              tenantId,
            ),
          )
          .groupBy(
            tickets.status,
          );

      const revenue =
        await db
          .select({
            total:
              sql<number>`COALESCE(SUM(total_amount), 0)`,
          })
          .from(tickets)
          .where(
            eq(
              tickets.tenantId,
              tenantId,
            ),
          );

      return {
        statusCounts,

        totalRevenue: Number(
          revenue[0]?.total ?? 0,
        ),
      };
    },
  ),

  // =====================================================
  // DELETE
  // =====================================================

  delete: tenantAdminQuery
    .input(
      z.object({
        id: z.number(),
      }),
    )

    .mutation(async ({ input, ctx }) => {
      const db = getDb();
      const tenantId = ctx.user!.tenantId as number;

      // Soft delete: mark ticket as deleted instead of hard delete
      await db.update(tickets).set({
        deletedAt: new Date(),
        deletedBy: ctx.user!.id,
      }).where(
        and(
          eq(tickets.id, input.id),
          eq(tickets.tenantId, tenantId),
        ),
      );

      return {
        success: true,
      };
    }),
});

/**
 * File Upload & Serving Handler
 *
 * Hono routes for multipart file uploads and secure file serving.
 * Integrated with the existing auth session cookie system.
 */

import type { Hono, Context } from "hono";
import { getDb } from "./queries/connection";
import { authenticateRequest } from "./kimi/auth";
import { documents } from "@db/schema";
import { eq, and } from "drizzle-orm";
import {
  storeFile,
  readStoredFile,
  validateFile,
  fileExists,
  deleteStoredFile,
} from "./lib/file-storage";

export function registerUploadRoutes(app: Hono<any>) {
  // ΓöÇΓöÇΓöÇ MULTIPART FILE UPLOAD ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
  app.post("/api/upload", async (c) => {
    try {
      // Authenticate
      const user = await authenticateRequest(c.req.raw.headers);
      if (!user?.tenantId) {
        return c.json({ error: "Unauthorized" }, 401);
      }

      const tenantId = user.tenantId;

      // Parse multipart body
      const body = await c.req.parseBody({ all: false });
      const file = body.file;

      if (!file || !(file instanceof File)) {
        return c.json({ error: "No file provided" }, 400);
      }

      // Validate
      const validation = validateFile({ type: file.type, size: file.size });
      if (!validation.valid) {
        return c.json({ error: validation.error }, 400);
      }

      // Extract metadata fields
      const entityType = String(body.entityType || "other");
      const entityId = Number(body.entityId || 0);
      const documentType = String(body.documentType || "attachment");
      const description = String(body.description || "");

      // Store file
      const buffer = Buffer.from(await file.arrayBuffer());
      const stored = await storeFile(buffer, {
        tenantId,
        entityType,
        originalName: file.name,
        mimeType: file.type,
      });

      // Record in documents table
      const db = getDb();
      const docResult = await db.insert(documents).values({
        tenantId,
        entityType: entityType as any,
        entityId,
        documentType: documentType as any,
        fileName: file.name,
        fileUrl: stored.relativePath,
        fileSize: stored.size,
        mimeType: file.type,
        status: "generated",
        generatedBy: user.id,
        generatedAt: new Date(),
        metadata: description ? { description } : null,
      });

      const documentId = Number(docResult[0].insertId);

      return c.json({
        success: true,
        documentId,
        fileName: file.name,
        url: `/api/files/${documentId}`,
        size: stored.size,
        mimeType: file.type,
      });
    } catch (err: any) {
      console.error("[upload] error:", err);
      return c.json({ error: err.message || "Upload failed" }, 500);
    }
  });

  // ΓöÇΓöÇΓöÇ SECURE FILE SERVING ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
  app.get("/api/files/:documentId", async (c) => {
    try {
      // Authenticate
      const user = await authenticateRequest(c.req.raw.headers);
      if (!user?.tenantId) {
        return c.json({ error: "Unauthorized" }, 401);
      }

      const documentId = Number(c.req.param("documentId"));
      if (isNaN(documentId)) {
        return c.json({ error: "Invalid document ID" }, 400);
      }

      // Lookup document metadata
      const db = getDb();
      const doc = await db
        .select({
          fileUrl: documents.fileUrl,
          mimeType: documents.mimeType,
          fileName: documents.fileName,
          tenantId: documents.tenantId,
        })
        .from(documents)
        .where(eq(documents.id, documentId))
        .limit(1);

      if (!doc[0]) {
        return c.json({ error: "Not found" }, 404);
      }

      // Tenant isolation
      if (doc[0].tenantId !== user.tenantId) {
        return c.json({ error: "Forbidden" }, 403);
      }

      const filePath = doc[0].fileUrl;
      if (!filePath) {
        return c.json({ error: "File path missing" }, 404);
      }

      const exists = await fileExists(filePath);
      if (!exists) {
        return c.json({ error: "File not found on disk" }, 404);
      }

      const buffer = await readStoredFile(filePath);
      return c.body(new Uint8Array(buffer), 200, {
        "Content-Type": doc[0].mimeType || "application/octet-stream",
        "Content-Disposition": `inline; filename="${doc[0].fileName || "file"}"`,
        "Cache-Control": "private, max-age=3600",
      });
    } catch (err: any) {
      console.error("[files] error:", err);
      return c.json({ error: err.message || "Failed to serve file" }, 500);
    }
  });

  // ΓöÇΓöÇΓöÇ DELETE UPLOADED FILE ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
  app.delete("/api/files/:documentId", async (c) => {
    try {
      const user = await authenticateRequest(c.req.raw.headers);
      if (!user?.tenantId) {
        return c.json({ error: "Unauthorized" }, 401);
      }

      const documentId = Number(c.req.param("documentId"));
      if (isNaN(documentId)) {
        return c.json({ error: "Invalid document ID" }, 400);
      }

      const db = getDb();
      const doc = await db
        .select({ id: documents.id, fileUrl: documents.fileUrl, tenantId: documents.tenantId })
        .from(documents)
        .where(eq(documents.id, documentId))
        .limit(1);

      if (!doc[0]) {
        return c.json({ error: "Not found" }, 404);
      }

      if (doc[0].tenantId !== user.tenantId) {
        return c.json({ error: "Forbidden" }, 403);
      }

      if (doc[0].fileUrl) {
        await deleteStoredFile(doc[0].fileUrl);
      }
      await db.delete(documents).where(eq(documents.id, doc[0].id));

      return c.json({ success: true });
    } catch (err: any) {
      console.error("[files-delete] error:", err);
      return c.json({ error: err.message || "Delete failed" }, 500);
    }
  });
}

import { useEffect } from "react";
import { Routes, Route, useLocation, useNavigate, Navigate } from "react-router";
import AppLayout from "./components/layout/AppLayout";
import HomePage from "./pages/Home";
import Dashboard from "./pages/Dashboard";
import Wallets from "./pages/Wallets";
import Tickets from "./pages/Tickets";
import CRM from "./pages/CRM";
import CustomerDetail from "./pages/CustomerDetail";
import Invoices from "./pages/Invoices";
import Receivables from "./pages/Receivables";
import Deposits from "./pages/Deposits";
import PaymentActivation from "./pages/PaymentActivation";
import PaymentLocations from "./pages/PaymentLocations";
import Suppliers from "./pages/Suppliers";
import SupplierDetail from "./pages/SupplierDetail";
import Payables from "./pages/Payables";
import ExchangeRates from "./pages/ExchangeRates";
import BankReconciliation from "./pages/BankReconciliation";
import Reports from "./pages/Reports";
import Documents from "./pages/Documents";
import Expenses from "./pages/Expenses";
import Accounting from "./pages/Accounting";
import AIAssistant from "./pages/AIAssistant";
import Settings from "./pages/Settings";
import Login from "./pages/Login";
import Register from "./pages/Register";
import RegisterSuccess from "./pages/RegisterSuccess";
import Admin from "./pages/Admin";
import NotFound from "./pages/NotFound";
import { useAuth } from "@/hooks/useAuth";

function RequireAuth({ children }: { children: React.ReactNode }) {
  const navigate = useNavigate();
  const location = useLocation();
  const { isLoggedIn, loading } = useAuth();

  useEffect(() => {
    if (!loading && !isLoggedIn) {
      navigate("/login", { replace: true, state: { from: location.pathname } });
    }
  }, [navigate, location.pathname, loading, isLoggedIn]);

  if (loading || !isLoggedIn) return null;
  return <>{children}</>;
}

function RequireSuperAdmin({ children }: { children: React.ReactNode }) {
  const navigate = useNavigate();
  const location = useLocation();
  const { user, isLoggedIn, loading } = useAuth();

  useEffect(() => {
    if (!loading && !isLoggedIn) {
      navigate("/login", { replace: true, state: { from: location.pathname } });
      return;
    }
    if (!loading && user?.role !== "super_admin") {
      navigate("/dashboard", { replace: true });
    }
  }, [navigate, location.pathname, loading, isLoggedIn, user]);

  if (loading || !isLoggedIn || user?.role !== "super_admin") return null;
  return <>{children}</>;
}

function RedirectIfAuth({ children }: { children: React.ReactNode }) {
  const navigate = useNavigate();
  const { isLoggedIn, loading, user } = useAuth();

  useEffect(() => {
    if (!loading && isLoggedIn) {
      if (user && user.role !== "super_admin" && (user as any).subscription?.status !== "active") {
        navigate("/payment-activation", { replace: true });
        return;
      }
      navigate("/dashboard", { replace: true });
    }
  }, [navigate, loading, isLoggedIn]);

  if (loading || isLoggedIn) return null;
  return <>{children}</>;
}

export default function App() {
  const { user } = useAuth();
  return (
    <Routes>
      <Route path="/" element={<HomePage />} />
      <Route path="/login" element={<RedirectIfAuth><Login /></RedirectIfAuth>} />
      <Route path="/register" element={<RedirectIfAuth><Register /></RedirectIfAuth>} />
      <Route path="/register/success" element={<RegisterSuccess />} />
      <Route
        path="/dashboard"
        element={
          <RequireAuth>
            {user && user.role !== "super_admin" && (user as any).subscription?.status !== "active" ? (
              <Navigate to="/payment-activation" replace />
            ) : (
              <AppLayout><Dashboard /></AppLayout>
            )}
          </RequireAuth>
        }
      />
      <Route
        path="/wallets"
        element={
          <RequireAuth>
            <AppLayout><Wallets /></AppLayout>
          </RequireAuth>
        }
      />
      <Route
        path="/tickets"
        element={
          <RequireAuth>
            <AppLayout><Tickets /></AppLayout>
          </RequireAuth>
        }
      />
      <Route
        path="/crm"
        element={
          <RequireAuth>
            <AppLayout><CRM /></AppLayout>
          </RequireAuth>
        }
      />
      <Route
        path="/crm/customers/:id"
        element={
          <RequireAuth>
            <AppLayout><CustomerDetail /></AppLayout>
          </RequireAuth>
        }
      />
      <Route
        path="/invoices"
        element={
          <RequireAuth>
            <AppLayout><Invoices /></AppLayout>
          </RequireAuth>
        }
      />
      <Route
        path="/receivables"
        element={
          <RequireAuth>
            <AppLayout><Receivables /></AppLayout>
          </RequireAuth>
        }
      />
      <Route
        path="/deposits"
        element={
          <RequireAuth>
            <AppLayout><Deposits /></AppLayout>
          </RequireAuth>
        }
      />
      <Route
        path="/payment-locations"
        element={
          <RequireAuth>
            <AppLayout><PaymentLocations /></AppLayout>
          </RequireAuth>
        }
      />
      <Route
        path="/suppliers"
        element={
          <RequireAuth>
            <AppLayout><Suppliers /></AppLayout>
          </RequireAuth>
        }
      />
      <Route
        path="/suppliers/:id"
        element={
          <RequireAuth>
            <AppLayout><SupplierDetail /></AppLayout>
          </RequireAuth>
        }
      />
      <Route
        path="/payables"
        element={
          <RequireAuth>
            <AppLayout><Payables /></AppLayout>
          </RequireAuth>
        }
      />
      <Route
        path="/exchange-rates"
        element={
          <RequireAuth>
            <AppLayout><ExchangeRates /></AppLayout>
          </RequireAuth>
        }
      />
      <Route
        path="/bank-reconciliation"
        element={
          <RequireAuth>
            <AppLayout><BankReconciliation /></AppLayout>
          </RequireAuth>
        }
      />
      <Route
        path="/reports"
        element={
          <RequireAuth>
            <AppLayout><Reports /></AppLayout>
          </RequireAuth>
        }
      />
      <Route
        path="/documents"
        element={
          <RequireAuth>
            <AppLayout><Documents /></AppLayout>
          </RequireAuth>
        }
      />
      <Route
        path="/expenses"
        element={
          <RequireAuth>
            <AppLayout><Expenses /></AppLayout>
          </RequireAuth>
        }
      />
      <Route
        path="/accounting"
        element={
          <RequireAuth>
            <AppLayout><Accounting /></AppLayout>
          </RequireAuth>
        }
      />
      <Route
        path="/ai"
        element={
          <RequireAuth>
            <AppLayout><AIAssistant /></AppLayout>
          </RequireAuth>
        }
      />
      <Route
 path="/payment-activation"
 element={
   <RequireAuth>
      <AppLayout>
         <PaymentActivation/>
      </AppLayout>
   </RequireAuth>
 }
/>
      <Route
        path="/settings"
        element={
          <RequireAuth>
            <AppLayout><Settings /></AppLayout>
          </RequireAuth>
        }
      />
      <Route
        path="/admin"
        element={
          <RequireSuperAdmin>
            <AppLayout><Admin /></AppLayout>
          </RequireSuperAdmin>
        }
      />
      <Route path="*" element={<NotFound />} />
    </Routes>
  );
}

