  y = 65;
  doc.setFillColor(241, 245, 249);
  doc.rect(14, y, 182, 60, "F");
  doc.setFontSize(11);
  doc.setTextColor(99, 102, 241);
  doc.text("PAYMENT DETAILS", 18, y + 8);
  doc.setTextColor(51, 65, 85);
  doc.setFontSize(10);

