};

const canApproveRoles = new Set(["super_admin", "admin", "accountant"]);

export default function DepositsPage() {
  const [search, setSearch] = useState("");
  const [statusFilter, setStatusFilter] = useState("");
  const [createOpen, setCreateOpen] = useState(false);
  const [newDeposit, setNewDeposit] = useState({
    walletId: "",
    customerId: "",
    amount: "",
    paymentMethod: "cash" as "cash" | "bank_transfer" | "cheque",
    referenceNumber: "",
    locationId: "",
    notes: "",
  });

  const { user } = useAuth();
  const canApprove = canApproveRoles.has(user?.role || "");

  const utils = trpc.useUtils();
  const { data, isLoading, error, refetch } = trpc.deposit.list.useQuery(
    { status: statusFilter || undefined, limit: 50 }
  );
  const { data: wallets } = trpc.wallet.list.useQuery();
  const { data: locations } = trpc.paymentLocation.list.useQuery({ status: "active" });
  const { data: customersData } = trpc.crm.customers.useQuery({ limit: 1000 });
  const customers = customersData?.items ?? [];
  const { data: stats } = trpc.deposit.stats.useQuery();
  const createDeposit = trpc.deposit.create.useMutation({
    onSuccess: () => {
      refetch();
      setCreateOpen(false);
      setNewDeposit({ walletId: "", customerId: "", amount: "", paymentMethod: "cash", referenceNumber: "", locationId: "", notes: "" });
    },
    onError: (err) => alert(err.message),
  });
  const updateStatus = trpc.deposit.updateStatus.useMutation({
    onSuccess: () => refetch(),
    onError: (err) => alert(err.message),
  });

  const statusCounts: Record<string, { count: number; total: number }> = {};
  (stats?.statusCounts || []).forEach((s: any) => statusCounts[s.status] = { count: s.count, total: s.total });

  const filtered = search
    ? data?.items?.filter((d: any) =>
        d.depositCode.toLowerCase().includes(search.toLowerCase()) ||
        (d.customer?.firstName || "").toLowerCase().includes(search.toLowerCase()) ||
        (d.customer?.lastName || "").toLowerCase().includes(search.toLowerCase())
      )
    : data?.items;

  return (
    <div className="space-y-6">
      <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-3">
        <div>
          <h1 className="text-xl sm:text-2xl font-bold">Deposit Management</h1>
          <p className="text-slate-500 mt-1 text-sm">Track and approve customer deposits</p>
        </div>
        <Dialog open={createOpen} onOpenChange={setCreateOpen}>
          <DialogTrigger asChild>
            <Button className="bg-indigo-600 hover:bg-indigo-700 w-full sm:w-auto"><Plus className="h-4 w-4 mr-2" /> Create Deposit</Button>
          </DialogTrigger>
          <DialogContent aria-describedby={undefined} className="max-w-lg max-h-[80vh] overflow-y-auto">
            <DialogHeader><DialogTitle>Create Deposit Request</DialogTitle></DialogHeader>
            <div className="space-y-3 pt-4">
              <div>
                <label className="text-sm text-slate-500">Wallet</label>
                <select className="w-full border rounded-md px-3 py-2 text-sm bg-white" value={newDeposit.walletId} onChange={e => setNewDeposit(s => ({ ...s, walletId: e.target.value }))}>
                  <option value="">Select wallet</option>
                  {(wallets || []).map((w: any) => <option key={w.id} value={w.id}>{w.name} (${Number(w.balance).toLocaleString()})</option>)}
                </select>
              </div>
              <div>
                <label className="text-sm text-slate-500">Customer</label>
                <select className="w-full border rounded-md px-3 py-2 text-sm bg-white" value={newDeposit.customerId} onChange={e => setNewDeposit(s => ({ ...s, customerId: e.target.value }))}>
                  <option value="">Select customer (optional)</option>
                  {(customers || []).map((c: any) => (
                    <option key={c.id} value={c.id}>
                      {c.firstName} {c.lastName} {c.company ? `(${c.company})` : ""}
                    </option>
                  ))}
                </select>
              </div>
              <div>
                <label className="text-sm text-slate-500">Payment Method</label>
                <select className="w-full border rounded-md px-3 py-2 text-sm bg-white" value={newDeposit.paymentMethod} onChange={e => setNewDeposit(s => ({ ...s, paymentMethod: e.target.value as any }))}>
                  <option value="cash">Cash</option>
                  <option value="bank_transfer">Bank Transfer</option>
                  <option value="cheque">Cheque</option>
                </select>
              </div>
              <div>
                <label className="text-sm text-slate-500">Amount</label>
                <Input type="number" step="0.01" value={newDeposit.amount} onChange={e => setNewDeposit(s => ({ ...s, amount: e.target.value }))} placeholder="0.00" />
              </div>
              <div>
                <label className="text-sm text-slate-500">Reference Number</label>
                <Input value={newDeposit.referenceNumber} onChange={e => setNewDeposit(s => ({ ...s, referenceNumber: e.target.value }))} placeholder="Receipt / cheque number" />
              </div>
              <div>
                <label className="text-sm text-slate-500">Payment Location</label>
                <select className="w-full border rounded-md px-3 py-2 text-sm bg-white" value={newDeposit.locationId} onChange={e => setNewDeposit(s => ({ ...s, locationId: e.target.value }))}>
                  <option value="">Select location</option>
                  {(locations?.items || []).map((l: any) => <option key={l.id} value={l.id}>{l.name} ΓÇö {l.city}</option>)}
                </select>
              </div>
              <div>
                <label className="text-sm text-slate-500">Notes</label>
                <Input value={newDeposit.notes} onChange={e => setNewDeposit(s => ({ ...s, notes: e.target.value }))} placeholder="Optional notes" />
              </div>
              <Button className="w-full bg-indigo-600" disabled={!newDeposit.walletId || !newDeposit.amount || createDeposit.isPending} onClick={() => createDeposit.mutate({
                walletId: Number(newDeposit.walletId),
                customerId: newDeposit.customerId ? Number(newDeposit.customerId) : undefined,
                amount: newDeposit.amount,
                paymentMethod: newDeposit.paymentMethod,
                referenceNumber: newDeposit.referenceNumber || undefined,
                locationId: newDeposit.locationId ? Number(newDeposit.locationId) : undefined,
                notes: newDeposit.notes || undefined,
              })}>
                {createDeposit.isPending ? "Creating..." : "Create Deposit"}
              </Button>
            </div>
          </DialogContent>
        </Dialog>
      </div>

      {/* Stats */}
      <div className="grid grid-cols-2 lg:grid-cols-5 gap-2 sm:gap-4">
        {["pending", "under_review", "approved", "rejected", "expired"].map(status => {
          const s = statusCounts[status];
          const cfg = statusConfig[status];
          const Icon = cfg?.icon || DollarSign;
          return (
            <Card key={status} className="border-0 shadow-sm cursor-pointer hover:shadow-md transition-shadow" onClick={() => setStatusFilter(statusFilter === status ? "" : status)}>
              <CardContent className="p-3 sm:p-4">
                <div className="flex items-center gap-2">
                  <div className={`h-7 w-7 sm:h-8 sm:w-8 rounded-lg flex items-center justify-center ${cfg?.color?.split(" ")[0]}`}>
                    <Icon className="h-3.5 w-3.5 sm:h-4 sm:w-4" />
                  </div>
                  <div>
                    <p className="text-[10px] sm:text-xs text-slate-500">{cfg?.label}</p>
                    <p className="text-lg sm:text-xl font-bold">${(s?.total || 0).toLocaleString()}</p>
                  </div>
                </div>
                <p className="text-[10px] sm:text-xs text-slate-500 mt-1">{s?.count || 0} deposits</p>
              </CardContent>
            </Card>
          );
        })}
      </div>

      {/* Search */}
      <div className="relative max-w-md">
        <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-slate-400" />
        <Input placeholder="Search by code or customer..." className="pl-9" value={search} onChange={e => setSearch(e.target.value)} />
      </div>

      {/* Table */}
      {isLoading ? (
        <div className="space-y-2">
          {[...Array(5)].map((_, i) => <Skeleton key={i} className="h-12" />)}
        </div>
      ) : error ? (
        <div className="text-center py-12 border rounded-lg">
          <p className="text-red-500 mb-2">Failed to load deposits</p>
          <Button variant="outline" onClick={() => refetch()}>Retry</Button>
        </div>
      ) : (
        <div className="border rounded-lg overflow-hidden">
          <Table>
            <TableHeader>
              <TableRow>
                <TableHead>Deposit Code</TableHead>
                <TableHead>Amount</TableHead>
                <TableHead>Method</TableHead>
                <TableHead>Wallet</TableHead>
                <TableHead>Status</TableHead>
                <TableHead className="text-right">Actions</TableHead>
              </TableRow>
            </TableHeader>
            <TableBody>
              {filtered?.length === 0 && (
                <TableRow>
                  <TableCell colSpan={6} className="text-center py-8 text-slate-500">No deposits found.</TableCell>
                </TableRow>
              )}
              {filtered?.map((d: any) => {
                const cfg = statusConfig[d.status] || statusConfig.pending;
                const Icon = cfg.icon;
                return (
                  <TableRow key={d.id}>
                    <TableCell>
                      <div className="font-mono text-sm font-medium">{d.depositCode}</div>
                      <div className="text-xs text-slate-500">{d.customer ? `${d.customer.firstName} ${d.customer.lastName}` : "Walk-in"}</div>
                    </TableCell>
                    <TableCell className="font-medium">${Number(d.amount).toLocaleString()}</TableCell>
                    <TableCell className="capitalize text-sm">{d.paymentMethod.replace("_", " ")}</TableCell>
                    <TableCell className="text-sm">{d.wallet?.name || "-"}</TableCell>
                    <TableCell>
                      <Badge className={cfg.color}>
                        <Icon className="h-3 w-3 mr-1" /> {cfg.label}
                      </Badge>
                    </TableCell>
                    <TableCell className="text-right">
                      {d.status === "pending" && canApprove && (
                        <div className="flex justify-end gap-1">
                          <Button size="sm" variant="ghost" className="text-emerald-600 h-7 text-xs px-2" onClick={() => updateStatus.mutate({ id: d.id, status: "approved" })} disabled={updateStatus.isPending}>
                            <CheckCircle className="h-3 w-3 mr-1" /> Approve
                          </Button>
                          <Button size="sm" variant="ghost" className="text-red-600 h-7 text-xs px-2" onClick={() => updateStatus.mutate({ id: d.id, status: "rejected" })} disabled={updateStatus.isPending}>
                            <XCircle className="h-3 w-3 mr-1" /> Reject
                          </Button>
                        </div>
                      )}
                      {d.status === "pending" && !canApprove && (
                        <span className="text-[10px] text-amber-600 bg-amber-50 px-2 py-1 rounded">Pending</span>
                      )}
                      {d.status === "approved" && (
                        <Button size="sm" variant="ghost" className="text-indigo-600 h-7 text-xs px-2" onClick={async () => {
                          const data = await utils.document.depositReceiptData.fetch({ id: d.id });
                          if (data) {
                            const doc = generateDepositReceiptPDF(data);
                            doc.save(`receipt-${data.deposit.depositCode}.pdf`);
                          }
                        }}>
                          <Download className="h-3 w-3 mr-1" /> Receipt
                        </Button>
                      )}
                    </TableCell>
                  </TableRow>
                );
              })}
            </TableBody>
          </Table>
        </div>
      )}
    </div>
  );
}

import { useState } from "react";
import { trpc } from "@/providers/trpc";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogTrigger } from "@/components/ui/dialog";
import { Progress } from "@/components/ui/progress";
import { Receipt, Search, Plus, CheckCircle, XCircle, Clock, DollarSign, BookOpen } from "lucide-react";
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer } from "recharts";

const statusConfig: Record<string, { color: string; icon: any }> = {
  approved: { color: "bg-emerald-100 text-emerald-800", icon: CheckCircle },
  pending: { color: "bg-amber-100 text-amber-800", icon: Clock },
  rejected: { color: "bg-red-100 text-red-800", icon: XCircle },
  reimbursed: { color: "bg-blue-100 text-blue-800", icon: DollarSign },
};

export default function ExpensesPage() {
  const [search, setSearch] = useState("");
  const [statusFilter, setStatusFilter] = useState("");
  const [createOpen, setCreateOpen] = useState(false);

  const utils = trpc.useUtils();
  const { data: expensesData, refetch } = trpc.expense.list.useQuery({ search, status: statusFilter });
  const { data: categories } = trpc.expense.categories.useQuery();
  const { data: stats } = trpc.expense.stats.useQuery();
  const createExpense = trpc.expense.create.useMutation({
    onSuccess: async () => {
      await utils.expense.list.invalidate();
      await utils.expense.stats.invalidate();
      await utils.dashboard.stats.invalidate();
      await utils.dashboard.expenseByCategory.invalidate();
      refetch();
      setCreateOpen(false);
      setNewExpense({ categoryId: 0, title: "", description: "", amount: "", expenseDate: "", paymentMethod: "card" as const, vendor: "", receiptNumber: "", notes: "" });
    },
    onError: (err) => alert(err.message),
  });
  const updateStatus = trpc.expense.updateStatus.useMutation({
    onSuccess: async () => {
      await utils.expense.list.invalidate();
      await utils.expense.stats.invalidate();
      await utils.dashboard.stats.invalidate();
      await utils.dashboard.expenseByCategory.invalidate();
      refetch();
    },
    onError: (err) => alert(err.message),
  });

  const [newExpense, setNewExpense] = useState<{
    categoryId: number; title: string; description: string; amount: string; expenseDate: string;
    paymentMethod: "cash" | "card" | "bank_transfer" | "cheque" | "wallet" | "other"; vendor: string; receiptNumber: string; notes: string;
  }>({
    categoryId: 0, title: "", description: "", amount: "", expenseDate: "",
    paymentMethod: "card", vendor: "", receiptNumber: "", notes: "",
  });

  const statusCounts: Record<string, { count: number; total: number }> = {};
  (stats?.statusCounts || []).forEach(s => statusCounts[s.status] = { count: s.count, total: s.total });
  const totalAll = Object.values(statusCounts).reduce((sum, s) => sum + s.total, 0);

  return (
    <div className="space-y-6">
      <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-3">
        <div>
          <h1 className="text-xl sm:text-2xl font-bold text-slate-900 dark:text-white">Expense Management</h1>
          <p className="text-slate-500 mt-1 text-sm">Track, approve, and manage business expenses</p>
        </div>
        <Dialog open={createOpen} onOpenChange={setCreateOpen}>
          <DialogTrigger asChild>
            <Button className="bg-indigo-600 hover:bg-indigo-700 w-full sm:w-auto"><Plus className="h-4 w-4 mr-2" /> Submit Expense</Button>
          </DialogTrigger>
          <DialogContent aria-describedby={undefined} className="max-w-[95vw] sm:max-w-lg">
            <DialogHeader><DialogTitle>Submit New Expense</DialogTitle></DialogHeader>
            <div className="space-y-3 pt-4">
              <div>
                <Label>Category</Label>
                <Select onValueChange={v => setNewExpense({...newExpense, categoryId: Number(v)})}>
                  <SelectTrigger><SelectValue placeholder="Select category" /></SelectTrigger>
                  <SelectContent>
                    {(categories || []).length === 0 ? (
                      <SelectItem value="__empty__" disabled>No records found</SelectItem>
                    ) : (
                      (categories || []).map(c => <SelectItem key={c.id} value={c.id.toString()}>{c.name}</SelectItem>)
                    )}
                  </SelectContent>
                </Select>
              </div>
              <div><Label>Title</Label><Input value={newExpense.title} onChange={e => setNewExpense({...newExpense, title: e.target.value})} placeholder="Expense title" /></div>
              <div><Label>Amount</Label><Input type="number" value={newExpense.amount} onChange={e => setNewExpense({...newExpense, amount: e.target.value})} placeholder="0.00" /></div>
              <div><Label>Date</Label><Input type="date" onChange={e => setNewExpense({...newExpense, expenseDate: e.target.value})} /></div>
              <div>
                <Label>Payment Method</Label>
                <Select value={newExpense.paymentMethod} onValueChange={v => setNewExpense({...newExpense, paymentMethod: v as "cash" | "card" | "bank_transfer" | "cheque" | "wallet" | "other"})}>
                  <SelectTrigger><SelectValue /></SelectTrigger>
                  <SelectContent>
                    <SelectItem value="cash">Cash</SelectItem>
                    <SelectItem value="card">Card</SelectItem>
                    <SelectItem value="bank_transfer">Bank Transfer</SelectItem>
                    <SelectItem value="cheque">Cheque</SelectItem>
                    <SelectItem value="wallet">Wallet</SelectItem>
                  </SelectContent>
                </Select>
              </div>
              <div><Label>Vendor</Label><Input value={newExpense.vendor} onChange={e => setNewExpense({...newExpense, vendor: e.target.value})} placeholder="Vendor name" /></div>
              <Button className="w-full bg-indigo-600" onClick={() => createExpense.mutate(newExpense)} disabled={!newExpense.title || !newExpense.amount || !newExpense.categoryId || !newExpense.expenseDate || createExpense.isPending}>Submit Expense</Button>
            </div>
          </DialogContent>
        </Dialog>
      </div>

      {/* Stats - FIXED: 2 cols on mobile */}
      <div className="grid grid-cols-2 lg:grid-cols-4 gap-2 sm:gap-4">
        {["approved", "pending", "rejected", "reimbursed"].map(status => {
          const s = statusCounts[status];
          const pct = totalAll > 0 ? ((s?.total || 0) / totalAll) * 100 : 0;
          const cfg = statusConfig[status];
          const Icon = cfg?.icon || Receipt;
          return (
            <Card key={status} className="border-0 shadow-sm cursor-pointer hover:shadow-md transition-shadow" onClick={() => setStatusFilter(statusFilter === status ? "" : status)}>
              <CardContent className="p-3 sm:p-4">
                <div className="flex items-center gap-2">
                  <div className={`h-7 w-7 sm:h-8 sm:w-8 rounded-lg flex items-center justify-center ${cfg?.color?.split(" ")[0]}`}>
                    <Icon className="h-3.5 w-3.5 sm:h-4 sm:w-4" />
                  </div>
                  <div>
                    <p className="text-[10px] sm:text-xs text-slate-500 capitalize">{status}</p>
                    <p className="text-lg sm:text-xl font-bold">${(s?.total || 0).toLocaleString()}</p>
                  </div>
                </div>
                <div className="mt-2"><Progress value={pct} className="h-1.5" /></div>
                <p className="text-[10px] sm:text-xs text-slate-500 mt-1">{s?.count || 0} expenses</p>
              </CardContent>
            </Card>
          );
        })}
      </div>

      {/* Chart */}
      <Card className="border-0 shadow-sm">
        <CardHeader className="pb-2"><CardTitle className="text-sm font-medium text-slate-600">Monthly Expense Trend</CardTitle></CardHeader>
        <CardContent>
          <ResponsiveContainer width="100%" height={200}>
            <BarChart data={stats?.monthly || []}>
              <CartesianGrid strokeDasharray="3 3" stroke="#e2e8f0" />
              <XAxis dataKey="month" tick={{ fontSize: 11 }} stroke="#94a3b8" />
              <YAxis tick={{ fontSize: 11 }} stroke="#94a3b8" tickFormatter={v => `$${v}`} />
              <Tooltip formatter={(v: any) => [`$${Number(v).toLocaleString()}`, ""]} />
              <Bar dataKey="total" fill="#6366f1" radius={[4, 4, 0, 0]} />
            </BarChart>
          </ResponsiveContainer>
        </CardContent>
      </Card>

      {/* Search */}
      <div className="relative">
        <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-slate-400" />
        <Input className="pl-9" placeholder="Search expenses..." value={search} onChange={e => setSearch(e.target.value)} />
      </div>

      {/* Table */}
      <Card className="border-0 shadow-sm">
        <CardContent className="p-0">
          <div className="overflow-x-auto">
            <table className="w-full text-sm min-w-[640px]">
              <thead className="bg-slate-50 dark:bg-slate-800 border-b"><tr>
                <th className="text-left p-2 sm:p-3 font-medium text-slate-500 text-xs">Expense</th>
                <th className="text-left p-2 sm:p-3 font-medium text-slate-500 text-xs">Category</th>
                <th className="text-left p-2 sm:p-3 font-medium text-slate-500 text-xs">Vendor</th>
                <th className="text-left p-2 sm:p-3 font-medium text-slate-500 text-xs">Date</th>
                <th className="text-right p-2 sm:p-3 font-medium text-slate-500 text-xs">Amount</th>
                <th className="text-center p-2 sm:p-3 font-medium text-slate-500 text-xs">Status</th>
                <th className="text-center p-2 sm:p-3 font-medium text-slate-500 text-xs">Actions</th>
              </tr></thead>
              <tbody>
                {(expensesData?.items || []).map((expense) => (
                  <tr key={expense.id} className="border-b hover:bg-slate-50 dark:hover:bg-slate-800">
                    <td className="p-2 sm:p-3">
                      <p className="font-medium text-xs sm:text-sm">{expense.title}</p>
                      <p className="text-[10px] text-slate-500">{expense.receiptNumber}</p>
                    </td>
                    <td className="p-2 sm:p-3">
                      <div className="flex items-center gap-2">
                        <div className="h-2 w-2 rounded-full flex-shrink-0" style={{ backgroundColor: expense.category?.color || "#6366f1" }} />
                        <span className="text-xs sm:text-sm">{expense.category?.name}</span>
                      </div>
                    </td>
                    <td className="p-2 sm:p-3 text-xs sm:text-sm">{expense.vendor}</td>
                    <td className="p-2 sm:p-3 text-xs sm:text-sm">{expense.expenseDate ? new Date(expense.expenseDate).toLocaleDateString() : "-"}</td>
                    <td className="p-2 sm:p-3 text-right font-medium text-xs sm:text-sm">${Number(expense.amount).toLocaleString()}</td>
                    <td className="p-2 sm:p-3 text-center">
                      <Badge className={`text-[10px] ${statusConfig[expense.status]?.color || ""}`}>{expense.status}</Badge>
                    </td>
                    <td className="p-2 sm:p-3 text-center">
                      {expense.status === "pending" && (
                        <div className="flex justify-center gap-1 flex-wrap">
                          <Button size="sm" variant="ghost" className="text-emerald-600 h-7 text-xs px-2" onClick={() => updateStatus.mutate({ id: expense.id, status: "approved" })}>
                            <CheckCircle className="h-3 w-3 mr-1" /> Approve
                          </Button>
                          <Button size="sm" variant="ghost" className="text-red-600 h-7 text-xs px-2" onClick={() => updateStatus.mutate({ id: expense.id, status: "rejected" })}>
                            <XCircle className="h-3 w-3 mr-1" /> Reject
                          </Button>
                        </div>
                      )}
                      {expense.status === "approved" && (
                        <div className="flex justify-center gap-1 flex-wrap items-center">
                          <span className="inline-flex items-center text-[10px] text-emerald-600 bg-emerald-50 px-2 py-1 rounded" title="Journal entry auto-posted on approval">
                            <BookOpen className="h-3 w-3 mr-1" /> Posted
                          </span>
                          <Button size="sm" variant="ghost" className="text-blue-600 h-7 text-xs px-2" onClick={() => updateStatus.mutate({ id: expense.id, status: "reimbursed" })}>
                            <DollarSign className="h-3 w-3 mr-1" /> Reimburse
                          </Button>
                        </div>
                      )}
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </CardContent>
      </Card>
    </div>
  );
}

import { useState } from "react";
import { Link, useNavigate } from "react-router";
import { useTranslation } from "react-i18next";
import { trpc } from "@/providers/trpc";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from "@/components/ui/card";
import { Alert, AlertDescription } from "@/components/ui/alert";
import { Building2, LogIn, AlertCircle, Eye, EyeOff, Shield, User, Lock } from "lucide-react";

export default function LoginPage() {
  const { t } = useTranslation("login");
  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");
  const [showPassword, setShowPassword] = useState(false);
  const [error, setError] = useState("");
  const [loading, setLoading] = useState(false);
  const navigate = useNavigate();
  const loginMutation = trpc.auth.login.useMutation();
  const utils = trpc.useUtils();

  const handleLogin = async (e: React.FormEvent) => {
    e.preventDefault();
    setError("");
    setLoading(true);

    try {
      const result = await loginMutation.mutateAsync({ email, password });
      console.log("[login success]", result.user?.email);
      await utils.auth.me.invalidate();
      navigate("/dashboard", { replace: true });
    } catch (trpcErr: any) {
      const serverMessage = trpcErr?.message;
      // Fallback to local dev demo login only in development
      const { isLocalDemoAuthEnabled, loginLocal } = await import("@/lib/localAuth");
      if (isLocalDemoAuthEnabled) {
        const user = loginLocal(email, password);
        if (user) {
          navigate("/dashboard", { replace: true });
          return;
        }
      }
      setError(serverMessage || t("invalidCredentials", "Invalid email or password. Please try again."));
    } finally {
      setLoading(false);
    }
  };

  const demoAccounts = [
    { role: t("adminDemo"), email: "admin@psb-erp.com", password: "admin123", color: "bg-red-50 text-red-700 border-red-200" },
    { role: t("managerDemo"), email: "manager@psb-erp.com", password: "manager123", color: "bg-blue-50 text-blue-700 border-blue-200" },
    { role: t("agentDemo"), email: "agent@psb-erp.com", password: "agent123", color: "bg-emerald-50 text-emerald-700 border-emerald-200" },
  ];

  return (
    <div className="min-h-screen bg-gradient-to-br from-slate-50 to-slate-100 dark:from-slate-950 dark:to-slate-900 flex items-center justify-center p-4">
      <div className="w-full max-w-md">
        {/* Logo */}
        <div className="text-center mb-8">
          <div className="inline-flex items-center justify-center h-14 w-14 rounded-2xl bg-indigo-600 shadow-lg mb-4">
            <Building2 className="h-8 w-8 text-white" />
          </div>
          <h1 className="text-2xl font-bold text-slate-900 dark:text-white">PSB-ERP</h1>
          <p className="text-sm text-slate-500 mt-1">{t("subtitle")}</p>
        </div>

        <Card className="border-0 shadow-xl">
          <CardHeader className="space-y-1 pb-4">
            <CardTitle className="text-xl text-center">{t("title")}</CardTitle>
            <CardDescription className="text-center text-sm">
              {t("emailLabel")}
            </CardDescription>
          </CardHeader>
          <CardContent>
            {error && (
              <Alert variant="destructive" className="mb-4">
                <AlertCircle className="h-4 w-4" />
                <AlertDescription>{error}</AlertDescription>
              </Alert>
            )}

            <form onSubmit={handleLogin} className="space-y-4">
              <div className="space-y-2">
                <Label htmlFor="email">{t("emailLabel")}</Label>
                <div className="relative">
                  <User className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-slate-400" />
                  <Input
                    id="email"
                    type="email"
                    placeholder={t("emailPlaceholder")}
                    value={email}
                    onChange={(e) => setEmail(e.target.value)}
                    className="pl-10"
                    required
                  />
                </div>
              </div>

              <div className="space-y-2">
                <Label htmlFor="password">{t("passwordLabel")}</Label>
                <div className="relative">
                  <Lock className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-slate-400" />
                  <Input
                    id="password"
                    type={showPassword ? "text" : "password"}
                    placeholder={t("passwordPlaceholder")}
                    value={password}
                    onChange={(e) => setPassword(e.target.value)}
                    className="pl-10 pr-10"
                    required
                  />
                  <button
                    type="button"
                    onClick={() => setShowPassword(!showPassword)}
                    className="absolute right-3 top-1/2 -translate-y-1/2 text-slate-400 hover:text-slate-600"
                    title={showPassword ? t("hidePassword") : t("showPassword")}
                  >
                    {showPassword ? <EyeOff className="h-4 w-4" /> : <Eye className="h-4 w-4" />}
                  </button>
                </div>
              </div>

              <Button type="submit" className="w-full bg-indigo-600 hover:bg-indigo-700 h-11" disabled={loading}>
                <LogIn className="h-4 w-4 mr-2" />
                {loading ? t("signingIn") : t("signInButton")}
              </Button>
            </form>

            {/* Registration link */}
            <div className="mt-4 text-center text-sm">
              <span className="text-slate-500">{t("noAccount")} </span>
              <Link to="/register" className="text-indigo-600 hover:text-indigo-700 font-medium">
                {t("registerNow")}
              </Link>
            </div>

            {/* Demo Accounts */}
            <div className="mt-6 pt-4 border-t">
              <p className="text-xs text-center text-slate-500 mb-3 flex items-center justify-center gap-1">
                <Shield className="h-3 w-3" /> {t("demoAccounts")}
              </p>
              <div className="space-y-2">
                {demoAccounts.map((acc) => (
                  <button
                    key={acc.email}
                    type="button"
                    onClick={() => { setEmail(acc.email); setPassword(acc.password); setError(""); }}
                    className={`w-full flex items-center justify-between px-3 py-2 rounded-lg border text-left transition-colors hover:opacity-80 ${acc.color}`}
                  >
                    <div>
                      <p className="text-xs font-semibold">{acc.role}</p>
                      <p className="text-[10px] opacity-80">{acc.email}</p>
                    </div>
                    <p className="text-[10px] opacity-70">{acc.password}</p>
                  </button>
                ))}
              </div>
            </div>

            <div className="mt-4 text-center">
              <Link to="/" className="text-xs text-slate-400 hover:text-indigo-600 transition-colors">
                Back to Home Page
              </Link>
            </div>
          </CardContent>
        </Card>
      </div>
    </div>
  );
}

import { useState } from "react";
import { trpc } from "@/providers/trpc";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogTrigger } from "@/components/ui/dialog";
import { Skeleton } from "@/components/ui/skeleton";
import { Tabs, TabsContent, TabsList, TabsTrigger } from "@/components/ui/tabs";
import {
  Table, TableBody, TableCell, TableHead, TableHeader, TableRow,
} from "@/components/ui/table";
import {
  Receipt, Search, Plus, AlertCircle, DollarSign, CreditCard,
  TrendingUp, Download,
} from "lucide-react";
import { generatePaymentVoucherPDF } from "@/lib/pdf-generator";

const billStatusColors: Record<string, string> = {
  draft: "bg-slate-100 text-slate-800",
  open: "bg-blue-100 text-blue-800",
  partial: "bg-amber-100 text-amber-800",
  paid: "bg-emerald-100 text-emerald-800",
  overdue: "bg-red-100 text-red-800",
  cancelled: "bg-gray-100 text-gray-800",
};

const paymentMethodLabels: Record<string, string> = {
  cash: "Cash",
  bank_transfer: "Bank Transfer",
  cheque: "Cheque",
  credit_card: "Credit Card",
  wallet: "Wallet",
};

export default function PayablesPage() {
  const [search, setSearch] = useState("");
  const [statusFilter, setStatusFilter] = useState("__all__");
  const [createBillOpen, setCreateBillOpen] = useState(false);
  const [paymentOpen, setPaymentOpen] = useState(false);
  const [selectedBill, setSelectedBill] = useState<{ id: number; billNumber: string; balanceDue: string; supplierId: number } | null>(null);

  const utils = trpc.useUtils();
  const { data: stats } = trpc.payable.stats.useQuery();
  const { data: billsData, isLoading, error: billsError } = trpc.payable.bills.useQuery({
    search: search || undefined,
    status: statusFilter !== "__all__" ? statusFilter : undefined,
  });
  const { data: aging, error: agingError } = trpc.payable.agingReport.useQuery({});
  const { data: paymentsData, error: paymentsError } = trpc.payable.payments.useQuery({});
  console.log("[Payables] billsData:", billsData, "aging:", aging, "payments:", paymentsData, "errors:", { billsError, agingError, paymentsError });

  const createBill = trpc.payable.createBill.useMutation({
    onSuccess: async () => {
      await utils.payable.bills.invalidate();
      await utils.payable.stats.invalidate();
      await utils.payable.agingReport.invalidate();
      await utils.supplier.stats.invalidate();
      setCreateBillOpen(false);
      resetBillForm();
    },
    onError: (err) => alert(err.message),
  });

  const createPayment = trpc.payable.createPayment.useMutation({
    onSuccess: async () => {
      await utils.payable.bills.invalidate();
      await utils.payable.stats.invalidate();
      await utils.payable.agingReport.invalidate();
      await utils.payable.payments.invalidate();
      await utils.supplier.stats.invalidate();
      setPaymentOpen(false);
      setSelectedBill(null);
      resetPaymentForm();
    },
    onError: (err) => alert(err.message),
  });

  const [billForm, setBillForm] = useState({
    supplierId: "",
    referenceNumber: "",
    issueDate: new Date().toISOString().split("T")[0],
    dueDate: "",
    description: "",
    category: "",
    items: [{ description: "", quantity: "1", unitPrice: "" }],
    taxAmount: "0",
    discountAmount: "0",
  });

  const [paymentForm, setPaymentForm] = useState({
    amount: "",
    paymentMethod: "bank_transfer" as const,
    paymentDate: new Date().toISOString().split("T")[0],
    referenceNumber: "",
    notes: "",
  });

  const resetBillForm = () => setBillForm({
    supplierId: "", referenceNumber: "", issueDate: new Date().toISOString().split("T")[0],
    dueDate: "", description: "", category: "",
    items: [{ description: "", quantity: "1", unitPrice: "" }],
    taxAmount: "0", discountAmount: "0",
  });

  const resetPaymentForm = () => setPaymentForm({
    amount: "", paymentMethod: "bank_transfer", paymentDate: new Date().toISOString().split("T")[0],
    referenceNumber: "", notes: "",
  });

  const { data: suppliersData } = trpc.supplier.list.useQuery({ limit: 100 });

  if (isLoading) return <div className="py-8 text-center text-slate-500">Loading payables...</div>;
  if (billsError) return <div className="py-8 text-center text-red-600">Error loading bills: {billsError.message}</div>;
  if (!billsData) return <div className="py-8 text-center text-slate-500">No payable data available</div>;

  const handleCreateBill = () => {
    if (!billForm.supplierId || !billForm.dueDate || billForm.items.some(i => !i.description || !i.unitPrice)) return;
    const subtotal = billForm.items.reduce((sum, item) => sum + (Number(item.quantity) * Number(item.unitPrice)), 0);
    if (subtotal <= 0) return;
    createBill.mutate({
      supplierId: Number(billForm.supplierId),
      referenceNumber: billForm.referenceNumber || undefined,
      issueDate: billForm.issueDate,
      dueDate: billForm.dueDate,
      description: billForm.description || undefined,
      category: billForm.category || undefined,
      items: billForm.items.map(i => ({
        description: i.description,
        quantity: Number(i.quantity),
        unitPrice: Number(i.unitPrice),
      })),
      taxAmount: Number(billForm.taxAmount) || 0,
      discountAmount: Number(billForm.discountAmount) || 0,
    });
  };

  const handleCreatePayment = () => {
    if (!selectedBill || !paymentForm.amount) return;
    createPayment.mutate({
      supplierId: selectedBill.supplierId,
      billId: selectedBill.id,
      amount: Number(paymentForm.amount),
      paymentMethod: paymentForm.paymentMethod,
      paymentDate: paymentForm.paymentDate,
      referenceNumber: paymentForm.referenceNumber || undefined,
      notes: paymentForm.notes || undefined,
    });
  };

  const openPayment = (bill: { id: number; billNumber: string; balanceDue: string; supplierId: number }) => {
    setSelectedBill(bill);
    setPaymentForm(prev => ({ ...prev, amount: bill.balanceDue }));
    setPaymentOpen(true);
  };

  return (
    <div className="space-y-6">
      <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-3">
        <div>
          <h1 className="text-xl sm:text-2xl font-bold text-slate-900 dark:text-white">Accounts Payable</h1>
          <p className="text-slate-500 mt-1 text-sm">Manage supplier bills and payments</p>
        </div>
        <Dialog open={createBillOpen} onOpenChange={setCreateBillOpen}>
          <DialogTrigger asChild>
            <Button size="sm" className="self-start sm:self-auto">
              <Plus className="h-4 w-4 mr-1" /> New Bill
            </Button>
          </DialogTrigger>
          <DialogContent aria-describedby={undefined} className="max-w-lg max-h-[90vh] overflow-y-auto">
            <DialogHeader><DialogTitle>Create New Bill</DialogTitle></DialogHeader>
            <div className="space-y-3 pt-2">
              <div>
                <Label>Supplier *</Label>
                <Select value={billForm.supplierId} onValueChange={v => setBillForm({ ...billForm, supplierId: v })}>
                  <SelectTrigger><SelectValue placeholder="Select supplier" /></SelectTrigger>
                  <SelectContent>
                    {(suppliersData?.items || []).length === 0 ? (
                      <SelectItem value="__empty__" disabled>No records found</SelectItem>
                    ) : (
                      (suppliersData?.items || []).map(s => (
                        <SelectItem key={s.id} value={String(s.id)}>{s.companyName}</SelectItem>
                      ))
                    )}
                  </SelectContent>
                </Select>
              </div>
              <div className="grid grid-cols-2 gap-3">
                <div>
                  <Label>Issue Date</Label>
                  <Input type="date" value={billForm.issueDate} onChange={e => setBillForm({ ...billForm, issueDate: e.target.value })} />
                </div>
                <div>
                  <Label>Due Date *</Label>
                  <Input type="date" value={billForm.dueDate} onChange={e => setBillForm({ ...billForm, dueDate: e.target.value })} />
                </div>
              </div>
              <div>
                <Label>Reference #</Label>
                <Input value={billForm.referenceNumber} onChange={e => setBillForm({ ...billForm, referenceNumber: e.target.value })} placeholder="Supplier invoice reference" />
              </div>
              <div>
                <Label>Category</Label>
                <Input value={billForm.category} onChange={e => setBillForm({ ...billForm, category: e.target.value })} placeholder="e.g. flight, hotel" />
              </div>
              <div>
                <Label>Description</Label>
                <Input value={billForm.description} onChange={e => setBillForm({ ...billForm, description: e.target.value })} />
              </div>
              <div className="space-y-2">
                <Label>Line Items</Label>
                {billForm.items.map((item, idx) => (
                  <div key={idx} className="grid grid-cols-12 gap-2 items-end">
                    <div className="col-span-5">
                      <Input value={item.description} onChange={e => {
                        const items = [...billForm.items];
                        items[idx].description = e.target.value;
                        setBillForm({ ...billForm, items });
                      }} placeholder="Description" />
                    </div>
                    <div className="col-span-2">
                      <Input type="number" value={item.quantity} onChange={e => {
                        const items = [...billForm.items];
                        items[idx].quantity = e.target.value;
                        setBillForm({ ...billForm, items });
                      }} placeholder="Qty" />
                    </div>
                    <div className="col-span-3">
                      <Input type="number" value={item.unitPrice} onChange={e => {
                        const items = [...billForm.items];
                        items[idx].unitPrice = e.target.value;
                        setBillForm({ ...billForm, items });
                      }} placeholder="Price" />
                    </div>
                    <div className="col-span-2">
                      {idx === billForm.items.length - 1 ? (
                        <Button type="button" variant="outline" size="sm" className="w-full" onClick={() => setBillForm({ ...billForm, items: [...billForm.items, { description: "", quantity: "1", unitPrice: "" }] })}>+</Button>
                      ) : (
                        <Button type="button" variant="ghost" size="sm" className="w-full text-red-500" onClick={() => {
                          const items = billForm.items.filter((_, i) => i !== idx);
                          setBillForm({ ...billForm, items });
                        }}>├ù</Button>
                      )}
                    </div>
                  </div>
                ))}
              </div>
              <div className="grid grid-cols-2 gap-3">
                <div>
                  <Label>Tax</Label>
                  <Input type="number" value={billForm.taxAmount} onChange={e => setBillForm({ ...billForm, taxAmount: e.target.value })} />
                </div>
                <div>
                  <Label>Discount</Label>
                  <Input type="number" value={billForm.discountAmount} onChange={e => setBillForm({ ...billForm, discountAmount: e.target.value })} />
                </div>
              </div>
              <div className="pt-2 border-t">
                <p className="text-sm font-medium text-right">
                  Total: ${billForm.items.reduce((sum, item) => sum + (Number(item.quantity) * Number(item.unitPrice)), 0) + Number(billForm.taxAmount) - Number(billForm.discountAmount)}
                </p>
              </div>
              <Button onClick={handleCreateBill} disabled={createBill.isPending} className="w-full">
                {createBill.isPending ? "Creating..." : "Create Bill"}
              </Button>
            </div>
          </DialogContent>
        </Dialog>
      </div>

      {/* Stats */}
      <div className="grid grid-cols-2 sm:grid-cols-4 gap-3 sm:gap-4">
        <Card className="border-0 shadow-sm">
          <CardContent className="p-3 sm:p-4">
            <div className="flex items-center gap-2">
              <div className="p-1.5 rounded-lg bg-blue-50"><Receipt className="h-4 w-4 text-blue-600" /></div>
              <span className="text-xs text-slate-500">Total Bills</span>
            </div>
            <p className="text-xl font-bold mt-1">{stats?.totalBills ?? 0}</p>
          </CardContent>
        </Card>
        <Card className="border-0 shadow-sm">
          <CardContent className="p-3 sm:p-4">
            <div className="flex items-center gap-2">
              <div className="p-1.5 rounded-lg bg-amber-50"><DollarSign className="h-4 w-4 text-amber-600" /></div>
              <span className="text-xs text-slate-500">Total Due</span>
            </div>
            <p className="text-xl font-bold mt-1">${(stats?.totalDue ?? 0).toLocaleString()}</p>
          </CardContent>
        </Card>
        <Card className="border-0 shadow-sm">
          <CardContent className="p-3 sm:p-4">
            <div className="flex items-center gap-2">
              <div className="p-1.5 rounded-lg bg-red-50"><AlertCircle className="h-4 w-4 text-red-600" /></div>
              <span className="text-xs text-slate-500">Overdue</span>
            </div>
            <p className="text-xl font-bold mt-1">${(stats?.overdueAmount ?? 0).toLocaleString()}</p>
          </CardContent>
        </Card>
        <Card className="border-0 shadow-sm">
          <CardContent className="p-3 sm:p-4">
            <div className="flex items-center gap-2">
              <div className="p-1.5 rounded-lg bg-emerald-50"><TrendingUp className="h-4 w-4 text-emerald-600" /></div>
              <span className="text-xs text-slate-500">Total Paid</span>
            </div>
            <p className="text-xl font-bold mt-1">${(stats?.totalPayments ?? 0).toLocaleString()}</p>
          </CardContent>
        </Card>
      </div>

      {/* Tabs */}
      <Tabs defaultValue="bills">
        <TabsList className="w-full sm:w-auto overflow-x-auto">
          <TabsTrigger value="bills">Bills</TabsTrigger>
          <TabsTrigger value="aging">Aging Report</TabsTrigger>
          <TabsTrigger value="payments">Payments</TabsTrigger>
        </TabsList>

        <TabsContent value="bills" className="mt-4">
          <div className="flex flex-col sm:flex-row gap-2 mb-4">
            <div className="relative flex-1">
              <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-slate-400" />
              <Input className="pl-9" placeholder="Search bills..." value={search} onChange={e => setSearch(e.target.value)} />
            </div>
            <Select value={statusFilter} onValueChange={setStatusFilter}>
              <SelectTrigger className="w-full sm:w-36">
                <SelectValue placeholder="Status" />
              </SelectTrigger>
              <SelectContent>
                <SelectItem value="__all__">All</SelectItem>
                <SelectItem value="open">Open</SelectItem>
                <SelectItem value="partial">Partial</SelectItem>
                <SelectItem value="paid">Paid</SelectItem>
                <SelectItem value="overdue">Overdue</SelectItem>
              </SelectContent>
            </Select>
          </div>

          {isLoading ? (
            <div className="space-y-2">
              {[...Array(4)].map((_, i) => <Skeleton key={i} className="h-12" />)}
            </div>
          ) : (
            <div className="overflow-x-auto">
              <Table>
                <TableHeader>
                  <TableRow>
                    <TableHead>Bill #</TableHead>
                    <TableHead>Supplier</TableHead>
                    <TableHead>Date</TableHead>
                    <TableHead>Due</TableHead>
                    <TableHead>Total</TableHead>
                    <TableHead>Paid</TableHead>
                    <TableHead>Balance</TableHead>
                    <TableHead>Status</TableHead>
                    <TableHead className="text-right">Action</TableHead>
                  </TableRow>
                </TableHeader>
                <TableBody>
                  {(billsData?.items || []).map(bill => (
                    <TableRow key={bill.id}>
                      <TableCell className="font-medium text-xs">{bill.billNumber}</TableCell>
                      <TableCell className="text-xs">{(bill as any).supplier?.companyName || "ΓÇö"}</TableCell>
                      <TableCell className="text-xs">{String(bill.issueDate)}</TableCell>
                      <TableCell className="text-xs">{String(bill.dueDate)}</TableCell>
                      <TableCell className="text-xs">${Number(bill.totalAmount).toLocaleString()}</TableCell>
                      <TableCell className="text-xs">${Number(bill.amountPaid).toLocaleString()}</TableCell>
                      <TableCell className="text-xs font-semibold">${Number(bill.balanceDue).toLocaleString()}</TableCell>
                      <TableCell><Badge className={`text-[10px] ${billStatusColors[bill.status] || ""}`}>{bill.status}</Badge></TableCell>
                      <TableCell className="text-right">
                        {bill.status !== "paid" && bill.status !== "cancelled" && (
                          <Button size="sm" variant="ghost" onClick={() => openPayment(bill as any)}>
                            Pay
                          </Button>
                        )}
                      </TableCell>
                    </TableRow>
                  ))}
                </TableBody>
              </Table>
            </div>
          )}

          {billsData?.items?.length === 0 && !isLoading && (
            <div className="text-center py-12 text-slate-500">
              <Receipt className="h-12 w-12 mx-auto mb-3 text-slate-300" />
              <p className="text-lg font-medium">No bills found</p>
            </div>
          )}
          {!billsData && !isLoading && (
            <div className="text-center py-12 text-slate-500">
              <p className="text-sm">Failed to load bills. Check console.</p>
            </div>
          )}
        </TabsContent>

        <TabsContent value="aging" className="mt-4">
          <Card>
            <CardHeader className="pb-2">
              <CardTitle className="text-sm font-medium">Aging Summary {aging?.asOfDate ? `ΓÇö as of ${aging.asOfDate}` : ""}</CardTitle>
            </CardHeader>
            <CardContent>
              <div className="grid grid-cols-2 sm:grid-cols-5 gap-3 mb-6">
                <div className="p-3 rounded-lg bg-emerald-50 text-center">
                  <p className="text-xs text-slate-500">Current</p>
                  <p className="text-lg font-bold text-emerald-700">${(aging?.summary.current ?? 0).toLocaleString()}</p>
                </div>
                <div className="p-3 rounded-lg bg-blue-50 text-center">
                  <p className="text-xs text-slate-500">1-30 Days</p>
                  <p className="text-lg font-bold text-blue-700">${(aging?.summary.days1To30 ?? 0).toLocaleString()}</p>
                </div>
                <div className="p-3 rounded-lg bg-amber-50 text-center">
                  <p className="text-xs text-slate-500">31-60 Days</p>
                  <p className="text-lg font-bold text-amber-700">${(aging?.summary.days31To60 ?? 0).toLocaleString()}</p>
                </div>
                <div className="p-3 rounded-lg bg-orange-50 text-center">
                  <p className="text-xs text-slate-500">61-90 Days</p>
                  <p className="text-lg font-bold text-orange-700">${(aging?.summary.days61To90 ?? 0).toLocaleString()}</p>
                </div>
                <div className="p-3 rounded-lg bg-red-50 text-center">
                  <p className="text-xs text-slate-500">Over 90</p>
                  <p className="text-lg font-bold text-red-700">${(aging?.summary.over90 ?? 0).toLocaleString()}</p>
                </div>
              </div>
              <div className="flex justify-between items-center pt-3 border-t">
                <span className="text-sm font-medium">Total Outstanding</span>
                <span className="text-lg font-bold">${(aging?.summary.total ?? 0).toLocaleString()}</span>
              </div>

              {aging && aging.details && aging.details.length > 0 && (
                <div className="mt-6 overflow-x-auto">
                  <Table>
                    <TableHeader>
                      <TableRow>
                        <TableHead>Bill #</TableHead>
                        <TableHead>Supplier</TableHead>
                        <TableHead>Due Date</TableHead>
                        <TableHead>Days Overdue</TableHead>
                        <TableHead>Balance</TableHead>
                      </TableRow>
                    </TableHeader>
                    <TableBody>
                      {aging.details.map(bill => (
                        <TableRow key={bill.id}>
                          <TableCell className="font-medium text-xs">{bill.billNumber}</TableCell>
                          <TableCell className="text-xs">{bill.supplier?.companyName || "ΓÇö"}</TableCell>
                          <TableCell className="text-xs">{String(bill.dueDate)}</TableCell>
                          <TableCell className="text-xs font-semibold text-red-600">{bill.daysOverdue}</TableCell>
                          <TableCell className="text-xs font-semibold">${Number(bill.balanceDue).toLocaleString()}</TableCell>
                        </TableRow>
                      ))}
                    </TableBody>
                  </Table>
                </div>
              )}
            </CardContent>
          </Card>
        </TabsContent>

        <TabsContent value="payments" className="mt-4">
          <div className="overflow-x-auto">
            <Table>
              <TableHeader>
                <TableRow>
                  <TableHead>Payment #</TableHead>
                  <TableHead>Supplier</TableHead>
                  <TableHead>Date</TableHead>
                  <TableHead>Amount</TableHead>
                  <TableHead>Method</TableHead>
                  <TableHead>Reference</TableHead>
                  <TableHead className="text-right">Action</TableHead>
                </TableRow>
              </TableHeader>
              <TableBody>
                {(paymentsData?.items || []).map(payment => (
                  <TableRow key={payment.id}>
                    <TableCell className="font-medium text-xs">{payment.paymentNumber}</TableCell>
                    <TableCell className="text-xs">{(payment as any).supplier?.companyName || "ΓÇö"}</TableCell>
                    <TableCell className="text-xs">{String(payment.paymentDate)}</TableCell>
                    <TableCell className="text-xs font-semibold">${Number(payment.amount).toLocaleString()}</TableCell>
                    <TableCell className="text-xs">{paymentMethodLabels[payment.paymentMethod] || payment.paymentMethod}</TableCell>
                    <TableCell className="text-xs">{payment.referenceNumber || "ΓÇö"}</TableCell>
                    <TableCell className="text-right">
                      <Button size="sm" variant="ghost" className="text-indigo-600 h-7 text-xs px-2" onClick={async () => {
                        const data = await utils.document.paymentVoucherData.fetch({ id: payment.id });
                        if (data) {
                          const doc = generatePaymentVoucherPDF(data);
                          doc.save(`voucher-${data.payment.paymentNumber}.pdf`);
                        }
                      }}>
                        <Download className="h-3 w-3 mr-1" /> PDF
                      </Button>
                    </TableCell>
                  </TableRow>
                ))}
              </TableBody>
            </Table>
          </div>
          {paymentsData?.items?.length === 0 && (
            <div className="text-center py-12 text-slate-500">
              <CreditCard className="h-12 w-12 mx-auto mb-3 text-slate-300" />
              <p className="text-lg font-medium">No payments yet</p>
            </div>
          )}
        </TabsContent>
      </Tabs>

      {/* Payment Dialog */}
      <Dialog open={paymentOpen} onOpenChange={setPaymentOpen}>
        <DialogContent aria-describedby={undefined} className="max-w-md">
          <DialogHeader><DialogTitle>Record Payment {selectedBill ? `ΓÇö ${selectedBill.billNumber}` : ""}</DialogTitle></DialogHeader>
          <div className="space-y-3 pt-2">
            <div>
              <Label>Amount *</Label>
              <Input type="number" value={paymentForm.amount} onChange={e => setPaymentForm({ ...paymentForm, amount: e.target.value })} />
            </div>
            <div>
              <Label>Payment Method</Label>
              <Select value={paymentForm.paymentMethod} onValueChange={v => setPaymentForm({ ...paymentForm, paymentMethod: v as any })}>
                <SelectTrigger><SelectValue /></SelectTrigger>
                <SelectContent>
                  <SelectItem value="cash">Cash</SelectItem>
                  <SelectItem value="bank_transfer">Bank Transfer</SelectItem>
                  <SelectItem value="cheque">Cheque</SelectItem>
                  <SelectItem value="credit_card">Credit Card</SelectItem>
                  <SelectItem value="wallet">Wallet</SelectItem>
                </SelectContent>
              </Select>
            </div>
            <div>
              <Label>Payment Date</Label>
              <Input type="date" value={paymentForm.paymentDate} onChange={e => setPaymentForm({ ...paymentForm, paymentDate: e.target.value })} />
            </div>
            <div>
              <Label>Reference #</Label>
              <Input value={paymentForm.referenceNumber} onChange={e => setPaymentForm({ ...paymentForm, referenceNumber: e.target.value })} placeholder="Transaction reference" />
            </div>
            <div>
              <Label>Notes</Label>
              <Input value={paymentForm.notes} onChange={e => setPaymentForm({ ...paymentForm, notes: e.target.value })} />
            </div>
            <Button onClick={handleCreatePayment} disabled={createPayment.isPending} className="w-full">
              {createPayment.isPending ? "Processing..." : "Record Payment"}
            </Button>
          </div>
        </DialogContent>
      </Dialog>
    </div>
  );
}

import { useState } from "react";
