              <div><label className="text-sm text-slate-500">Address</label><Input value={newLoc.address} onChange={e => setNewLoc(s => ({ ...s, address: e.target.value }))} placeholder="Full address" /></div>
              <div className="grid grid-cols-2 gap-3">
