import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
  DialogTrigger,
} from "@/components/ui/dialog";
import {
  Table,
  TableBody,
  TableCell,
  TableHead,
  TableHeader,
  TableRow,
} from "@/components/ui/table";
import { Badge } from "@/components/ui/badge";
import { Skeleton } from "@/components/ui/skeleton";
import { Search, DollarSign, FileText, TrendingUp } from "lucide-react";

const typeColors: Record<string, string> = {
  receivable: "bg-orange-100 text-orange-700",
  payment: "bg-green-100 text-green-700",
  deposit: "bg-blue-100 text-blue-700",
  credit: "bg-purple-100 text-purple-700",
  refund: "bg-red-100 text-red-700",
  adjustment: "bg-gray-100 text-gray-700",
};

export default function ReceivablesPage() {
  const [search, setSearch] = useState("");
  const [selectedCustomerId, setSelectedCustomerId] = useState<number | null>(null);
  const [paymentForm, setPaymentForm] = useState({ amount: "", description: "" });

  const { data, isLoading, error, refetch } = trpc.receivable.list.useQuery(
    { page: 1, limit: 50 }
  );
  const { data: balanceData } = trpc.receivable.customerBalance.useQuery(
    { customerId: selectedCustomerId! },
    { enabled: !!selectedCustomerId }
  );
  const { data: statementData } = trpc.receivable.statement.useQuery(
    { customerId: selectedCustomerId! },
    { enabled: !!selectedCustomerId }
  );
  const { data: agingData } = trpc.receivable.aging.useQuery();

  const createPayment = trpc.receivable.createPayment.useMutation({
    onSuccess: () => {
      refetch();
      setPaymentForm({ amount: "", description: "" });
    },
  });

  const agingBuckets = agingData
    ? [
        { label: "Current", amount: agingData.current },
        { label: "1-30 Days", amount: agingData.d30 },
        { label: "31-60 Days", amount: agingData.d60 },
        { label: "60+ Days", amount: agingData.d90 },
      ]
    : [];

  const totalReceivable = agingBuckets.reduce((sum, g) => sum + Number(g.amount), 0);

  const filteredItems = search
    ? data?.items?.filter((tx: any) => {
        const customerName = `${tx.customer?.firstName || ""} ${tx.customer?.lastName || ""}`.toLowerCase();
        return (
          customerName.includes(search.toLowerCase()) ||
          (tx.description || "").toLowerCase().includes(search.toLowerCase())
        );
      })
    : data?.items;

  return (
    <div className="space-y-6">
      <div className="flex items-center justify-between">
        <h1 className="text-2xl font-bold">Customer Receivables</h1>
      </div>

      {/* Summary Cards */}
      <div className="grid grid-cols-1 sm:grid-cols-3 gap-4">
        <div className="bg-white border rounded-lg p-4 shadow-sm">
          <div className="flex items-center gap-2 text-gray-500 text-sm mb-1">
            <TrendingUp className="h-4 w-4" />
            Total Receivables
          </div>
          <p className="text-2xl font-bold">${totalReceivable.toLocaleString()}</p>
        </div>
        <div className="bg-white border rounded-lg p-4 shadow-sm">
          <div className="flex items-center gap-2 text-gray-500 text-sm mb-1">
            <DollarSign className="h-4 w-4" />
            Total Customers
          </div>
          <p className="text-2xl font-bold">{new Set(data?.items?.map((t: any) => t.customerId)).size}</p>
        </div>
        <div className="bg-white border rounded-lg p-4 shadow-sm">
          <div className="flex items-center gap-2 text-gray-500 text-sm mb-1">
            <FileText className="h-4 w-4" />
            Transactions
          </div>
          <p className="text-2xl font-bold">{data?.items?.length ?? 0}</p>
        </div>
      </div>

      {/* Aging Report */}
      {agingBuckets.length > 0 && (
        <div className="border rounded-lg p-4">
          <h3 className="text-sm font-semibold mb-3">Aging Summary</h3>
          <div className="grid grid-cols-2 sm:grid-cols-4 gap-3">
            {agingBuckets.map((bucket) => (
              <div key={bucket.label} className="bg-gray-50 rounded p-3">
                <p className="text-xs text-gray-500">{bucket.label}</p>
                <p className="text-lg font-semibold">${Number(bucket.amount).toLocaleString()}</p>
              </div>
            ))}
          </div>
        </div>
      )}

      <div className="flex flex-col sm:flex-row gap-3">
        <div className="relative flex-1">
          <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-gray-400" />
          <Input
            placeholder="Search by customer or reference..."
            className="pl-9"
            value={search}
            onChange={(e) => setSearch(e.target.value)}
          />
        </div>
      </div>

      {isLoading ? (
        <div className="space-y-2">
          {[...Array(5)].map((_, i) => (
            <Skeleton key={i} className="h-12 w-full" />
          ))}
        </div>
      ) : error ? (
        <div className="text-center py-12 border rounded-lg">
          <p className="text-red-500 mb-2">Failed to load receivables</p>
          <Button variant="outline" onClick={() => refetch()}>Retry</Button>
        </div>
      ) : (
        <div className="border rounded-lg overflow-hidden">
          <Table>
            <TableHeader>
              <TableRow>
                <TableHead>Customer</TableHead>
                <TableHead>Type</TableHead>
                <TableHead>Amount</TableHead>
                <TableHead>Balance</TableHead>
                <TableHead>Date</TableHead>
                <TableHead>Description</TableHead>
                <TableHead className="text-right">Actions</TableHead>
              </TableRow>
            </TableHeader>
            <TableBody>
              {filteredItems?.length === 0 && (
                <TableRow>
                  <TableCell colSpan={7} className="text-center py-8 text-gray-500">
                    No receivable transactions found.
                  </TableCell>
                </TableRow>
              )}
              {filteredItems?.map((tx: any) => (
                <TableRow key={tx.id}>
                  <TableCell>
                    <span className="font-medium">{tx.customer?.firstName} {tx.customer?.lastName}</span>
                    <p className="text-xs text-gray-500">{tx.customer?.email}</p>
                  </TableCell>
                  <TableCell>
                    <Badge className={typeColors[tx.type] || "bg-gray-100"}>
                      {tx.type}
                    </Badge>
                  </TableCell>
                  <TableCell className={tx.type === "payment" || tx.type === "credit" || tx.type === "refund" ? "text-green-600" : "text-orange-600"}>
                    {tx.type === "payment" || tx.type === "credit" || tx.type === "refund" ? "-" : "+"}
                    ${Number(tx.amount).toLocaleString()}
                  </TableCell>
                  <TableCell className="font-medium">${Number(tx.balance).toLocaleString()}</TableCell>
                  <TableCell>{new Date(tx.createdAt).toLocaleDateString()}</TableCell>
                  <TableCell className="max-w-[200px] truncate">{tx.description}</TableCell>
                  <TableCell className="text-right">
                    <Dialog>
                      <DialogTrigger asChild>
                        <Button size="sm" variant="ghost" onClick={() => setSelectedCustomerId(tx.customerId)}>
                          <FileText className="h-4 w-4" />
                        </Button>
                      </DialogTrigger>
                      <DialogContent className="max-w-2xl max-h-[80vh] overflow-y-auto">
                        <DialogHeader>
                          <DialogTitle>
                            Statement ΓÇö {tx.customer?.firstName} {tx.customer?.lastName}
                          </DialogTitle>
                        </DialogHeader>
                        {balanceData !== undefined && (
                          <div className="bg-gray-50 p-3 rounded mb-3">
                            <p className="text-sm text-gray-500">Current Balance</p>
                            <p className={`text-xl font-bold ${balanceData.balance > 0 ? "text-red-600" : "text-green-600"}`}>
                              ${Number(balanceData.balance).toLocaleString()}
                            </p>
                          </div>
                        )}

                        <Dialog>
                          <DialogTrigger asChild>
                            <Button size="sm" className="mb-2">
                              <DollarSign className="h-4 w-4 mr-1" /> Record Payment
                            </Button>
                          </DialogTrigger>
                          <DialogContent>
                            <DialogHeader>
                              <DialogTitle>Record Payment</DialogTitle>
                            </DialogHeader>
                            <div className="space-y-3">
                              <div>
                                <label className="text-sm text-gray-500">Customer</label>
                                <p className="font-medium">{tx.customer?.firstName} {tx.customer?.lastName}</p>
                              </div>
                              <div>
                                <label className="text-sm text-gray-500">Amount</label>
                                <Input
                                  type="number"
                                  step="0.01"
                                  value={paymentForm.amount}
                                  onChange={(e) => setPaymentForm((s) => ({ ...s, amount: e.target.value }))}
                                  placeholder="0.00"
                                />
                              </div>
                              <div>
                                <label className="text-sm text-gray-500">Description</label>
                                <Input
                                  value={paymentForm.description}
                                  onChange={(e) => setPaymentForm((s) => ({ ...s, description: e.target.value }))}
                                  placeholder="Payment description..."
                                />
                              </div>
                              <Button
                                className="w-full"
                                disabled={createPayment.isPending || !paymentForm.amount}
                                onClick={() =>
                                  createPayment.mutate({
                                    customerId: tx.customerId,
                                    amount: paymentForm.amount,
                                    description: paymentForm.description,
                                  })
                                }
                              >
                                {createPayment.isPending ? "Processing..." : "Record Payment"}
                              </Button>
                            </div>
                          </DialogContent>
                        </Dialog>

                        <Table>
                          <TableHeader>
                            <TableRow>
                              <TableHead>Date</TableHead>
                              <TableHead>Type</TableHead>
                              <TableHead>Amount</TableHead>
                              <TableHead>Balance</TableHead>
                              <TableHead>Description</TableHead>
                            </TableRow>
                          </TableHeader>
                          <TableBody>
                            {statementData?.transactions?.map((stmt: any) => (
                              <TableRow key={stmt.id}>
                                <TableCell>{new Date(stmt.createdAt).toLocaleDateString()}</TableCell>
                                <TableCell>
                                  <Badge className={typeColors[stmt.type] || "bg-gray-100"}>
                                    {stmt.type}
                                  </Badge>
                                </TableCell>
                                <TableCell>${Number(stmt.amount).toLocaleString()}</TableCell>
                                <TableCell>${Number(stmt.balance).toLocaleString()}</TableCell>
                                <TableCell className="max-w-[150px] truncate">{stmt.description}</TableCell>
                              </TableRow>
                            ))}
                          </TableBody>
                        </Table>
                      </DialogContent>
                    </Dialog>
                  </TableCell>
                </TableRow>
              ))}
            </TableBody>
          </Table>
        </div>
      )}
    </div>
  );
}

import { useState } from "react";
import { Link, useNavigate } from "react-router";
import { useTranslation } from "react-i18next";
import { trpc } from "@/providers/trpc";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from "@/components/ui/card";
import { Alert, AlertDescription } from "@/components/ui/alert";
import {
  Building2,
  AlertCircle,
  Eye,
  EyeOff,
  ArrowRight,
  ArrowLeft,
  Check,
  Plane,
  Star,
  Crown,
} from "lucide-react";

const plans = [
  { id: "starter" as const, label: "Starter", icon: Plane, price: 50, features: ["Up to 3 users", "Basic reports", "Email support"] },
  { id: "professional" as const, label: "Professional", icon: Star, price: 100, features: ["Up to 10 users", "Advanced reports", "Priority support", "Multi-branch"] },
  { id: "enterprise" as const, label: "Enterprise", icon: Crown, price: 200, features: ["Unlimited users", "Custom reports", "24/7 support", "API access"] },
];

const durations = [
  { months: 1, label: "1month", discount: 0 },
  { months: 3, label: "3months", discount: 5 },
  { months: 6, label: "6months", discount: 10 },
  { months: 12, label: "12months", discount: 15 },
];

export default function RegisterPage() {
  const { t } = useTranslation("register");
  const { t: tc } = useTranslation("common");
  const navigate = useNavigate();

  const [step, setStep] = useState(1);
  const [showPassword, setShowPassword] = useState(false);
  const [error, setError] = useState("");

  const [form, setForm] = useState({
    agencyName: "",
    ownerName: "",
    email: "",
    phone: "",
    address: "",
    city: "",
    password: "",
    plan: "starter" as "starter" | "professional" | "enterprise",
    durationMonths: 1,
  });

  const registerMutation = trpc.registration.register.useMutation({
    onSuccess: (data) => {
      navigate("/register/success", {
        state: {
          token: data.token,
          agencyName: data.agencyName,
          plan: data.plan,
          durationMonths: data.durationMonths,
        },
      });
    },
    onError: (err) => {
      const msg = err.message;
      if (msg.includes("Email already")) setError(t("duplicateEmail"));
      else if (msg.includes("Agency name already")) setError(t("duplicateAgency"));
      else setError(msg || tc("error"));
    },
  });

  const handleChange = (field: string, value: string | number) => {
    setForm((prev) => ({ ...prev, [field]: value }));
    setError("");
  };

  const validateStep1 = () => {
    if (!form.agencyName.trim() || form.agencyName.length < 2) return false;
    if (!form.ownerName.trim() || form.ownerName.length < 2) return false;
    if (!form.email.trim() || !form.email.includes("@")) return false;
    if (!form.phone.trim() || form.phone.length < 5) return false;
    if (!form.address.trim() || form.address.length < 5) return false;
    if (!form.city.trim() || form.city.length < 2) return false;
    if (!form.password || form.password.length < 8) {
      setError(t("weakPassword"));
      return false;
    }
    return true;
  };

  const handleNext = () => {
    setError("");
    if (step === 1 && validateStep1()) {
      setStep(2);
    } else if (step === 2) {
      setStep(3);
    }
  };

  const handleBack = () => {
    setError("");
    setStep((s) => s - 1);
  };

  const handleSubmit = () => {
    setError("");
    registerMutation.mutate(form);
  };

  const selectedPlan = plans.find((p) => p.id === form.plan)!;
  const selectedDuration = durations.find((d) => d.months === form.durationMonths)!;
  const totalPrice = selectedPlan.price * form.durationMonths * (1 - selectedDuration.discount / 100);

  const stepLabels = [t("step1"), t("step2"), t("step3")];

  return (
    <div className="min-h-screen bg-gradient-to-br from-slate-50 to-slate-100 dark:from-slate-950 dark:to-slate-900 flex items-center justify-center p-4">
      <div className="w-full max-w-2xl">
        {/* Logo */}
        <div className="text-center mb-6">
          <div className="inline-flex items-center justify-center h-14 w-14 rounded-2xl bg-indigo-600 shadow-lg mb-4">
            <Building2 className="h-8 w-8 text-white" />
          </div>
          <h1 className="text-2xl font-bold text-slate-900 dark:text-white">PSB-ERP</h1>
          <p className="text-sm text-slate-500 mt-1">{t("subtitle")}</p>
        </div>

        {/* Stepper */}
        <div className="flex items-center justify-center mb-6">
          {stepLabels.map((label, i) => (
            <div key={i} className="flex items-center">
              <div className="flex flex-col items-center">
                <div
                  className={`h-8 w-8 rounded-full flex items-center justify-center text-sm font-bold transition-colors ${
                    step > i + 1
                      ? "bg-emerald-500 text-white"
                      : step === i + 1
                      ? "bg-indigo-600 text-white"
                      : "bg-slate-200 text-slate-500"
                  }`}
                >
                  {step > i + 1 ? <Check className="h-4 w-4" /> : i + 1}
                </div>
                <span className="text-[10px] mt-1 text-slate-500">{label}</span>
              </div>
              {i < stepLabels.length - 1 && (
                <div className={`w-12 sm:w-20 h-0.5 mx-2 ${step > i + 1 ? "bg-emerald-500" : "bg-slate-200"}`} />
              )}
            </div>
          ))}
        </div>

        <Card className="border-0 shadow-xl">
          <CardHeader className="space-y-1 pb-4">
            <CardTitle className="text-xl text-center">{t("title")}</CardTitle>
            <CardDescription className="text-center text-sm">
              {step === 1 ? t("step1") : step === 2 ? t("step2") : t("step3")}
            </CardDescription>
          </CardHeader>
          <CardContent>
            {error && (
              <Alert variant="destructive" className="mb-4">
                <AlertCircle className="h-4 w-4" />
