                    <TableCell className="text-xs">{String(r.date)}</TableCell>
                    <TableCell className="text-xs font-medium">{(r as any).account?.name || "ΓÇö"}</TableCell>
                    <TableCell className="text-xs">{r.description || "ΓÇö"}</TableCell>
                    <TableCell className="text-xs">{Number(r.debit) > 0 ? `$${Number(r.debit).toLocaleString()}` : "ΓÇö"}</TableCell>
                    <TableCell className="text-xs">{Number(r.credit) > 0 ? `$${Number(r.credit).toLocaleString()}` : "ΓÇö"}</TableCell>
                    <TableCell className="text-xs font-semibold">${Number(r.balance).toLocaleString()}</TableCell>
                  </TableRow>
                ))}
              </TableBody>
            </Table>
          </div>
        </TabsContent>
      </Tabs>
    </div>
  );
}

